-- Poems batch 81
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2e4e76c6-bade-4850-a537-7ece1f0abdb0','夏日即事  其三','張九成','宋','宋诗','song-poetry','','[]','日長院落迥無人，忽悟猶餘此老身。',32,'全唐诗/poet.song.103000.json','["日長院落迥無人，忽悟猶餘此老身。", "只擬一時都忘了，放教桃李四時春。"]'),
('c649cb42-7d75-42ff-8c47-f1d22dfe51b1','夏日即事  其四','張九成','宋','宋诗','song-poetry','','[]','雲開日出四窗明，恰到猶餘夢自生。',32,'全唐诗/poet.song.103000.json','["雲開日出四窗明，恰到猶餘夢自生。", "一枕覺來人寂寂，時聞兒子讀書聲。"]'),
('a1163861-307a-403f-83e6-b18ef8f94e3c','惜花','張九成','宋','宋诗','song-poetry','','[]','數日生寒緊杜門，今朝步屧到前村。',32,'全唐诗/poet.song.103000.json','["數日生寒緊杜門，今朝步屧到前村。", "可憐桃李都飛盡，細雨斜風更斷魂。"]'),
('a8a1cfc1-c7f1-418f-9aa3-d77545ce65d4','二月八日偶成  其一','張九成','宋','宋诗','song-poetry','','[]','今年春色可勝嗟，二月山中未見花。',32,'全唐诗/poet.song.103000.json','["今年春色可勝嗟，二月山中未見花。", "長憶去年今夜月，海棠花影到窗紗。"]'),
('e0dda097-de08-488b-9399-06ded9d41f24','二月八日偶成  其二','張九成','宋','宋诗','song-poetry','','[]','春寒滲滲越常年，桃李枝間尚悄然。',32,'全唐诗/poet.song.103000.json','["春寒滲滲越常年，桃李枝間尚悄然。", "數日長陰君莫歎，人人道是養花天。"]'),
('b6c24080-061a-48ec-ba7e-641d4aa37945','二月八日偶成  其三','張九成','宋','宋诗','song-poetry','','[]','庭院無端作許寒，好花無處壓欄竿。',32,'全唐诗/poet.song.103000.json','["庭院無端作許寒，好花無處壓欄竿。", "東君今歲知何意，勒住羣花不得看。"]'),
('b53ff253-6257-4a39-aeee-8f2034f8219f','六月十二日偶成  其一','張九成','宋','宋诗','song-poetry','','[]','閒居百事不關心，只有多情尚苦吟。',32,'全唐诗/poet.song.103000.json','["閒居百事不關心，只有多情尚苦吟。", "午睡覺來何所樂，鄰雞一唱柳垂陰。"]'),
('ff508eec-e2b3-4841-8539-582a98f01927','六月十二日偶成  其二','張九成','宋','宋诗','song-poetry','','[]','目昏數日不觀書，閉眼無言意自如。',32,'全唐诗/poet.song.103000.json','["目昏數日不觀書，閉眼無言意自如。", "忽笑子綦云喪我，仰天何事尚長吁。"]'),
('05778b74-793f-4a4f-b903-2607d00f9a50','題郡齋壁','張九成','宋','宋诗','song-poetry','','[]','吏散兵休文案靜，數竿脩竹隔疏簾。',32,'全唐诗/poet.song.103000.json','["吏散兵休文案靜，數竿脩竹隔疏簾。", "嗟予老矣欲歸去，肯對江山歎滯淹。"]'),
('f91f67f4-f9b4-47ea-95d2-e8ca06097396','庾嶺舊傳有梅往往詩人借此爲江南春信予到此數年因登嶺上不見一枝遂成一絕','張九成','宋','宋诗','song-poetry','','[]','詩人常說嶺頭梅，往往春風自此來。',32,'全唐诗/poet.song.103000.json','["詩人常說嶺頭梅，往往春風自此來。", "我到嶺頭都不見，空將春夢又空回。"]'),
('73fb98c1-c704-459e-a3fa-8484c9ecdcba','南安寶戒院作','張九成','宋','宋诗','song-poetry','','[]','苦無人事擾閑居，贏得終年學著書。',32,'全唐诗/poet.song.103000.json','["苦無人事擾閑居，贏得終年學著書。", "今日欣然出門去，秋風吹意滿芙蕖。"]'),
('cfdf938f-4cf1-40df-866c-cd0c3a68a000','盆中石菖蒲','張九成','宋','宋诗','song-poetry','','[]','清姿水石間，相得不可無。',120,'全唐诗/poet.song.103000.json','["清姿水石間，相得不可無。", "如人飽道義，其色長敷腴。", "不受塵土覆，自與人世殊。", "我何愛軒冕，冒昧名利塗。", "聖人惡潔身，名士多自汙。", "理亦顧其可，未應如此拘。", "往往不知者，假此爲穿窬。", "吾方存胸中，未敢執一隅。", "姑從吾所好，誰能復改圖。", "不若歸去來，無愧石上蒲。"]'),
('ad583e63-8b3e-4f55-b716-7e98d2daa2d5','庭下草','張九成','宋','宋诗','song-poetry','','[]','秋風吹碧草，久客情如何。',72,'全唐诗/poet.song.103000.json','["秋風吹碧草，久客情如何。", "鄉關斷過雁，青山高嵳峩。", "然而夢寐間，往往長經過。", "夢覺亦我耳，所得初無多。", "天地存胸中，要當常拂摩。", "肯爲外物流，爲賦白雪歌。"]'),
('06f2548e-6b12-4d83-9cc0-a3f5a80c799d','論語絕句  其一','張九成','宋','宋诗','song-poetry','','[]','既是文章可得聞，不應此外尚云云。',32,'全唐诗/poet.song.103000.json','["既是文章可得聞，不應此外尚云云。", "如何夫子言天道，肯把文章兩處分。"]'),
('3bf591d9-9b48-4be7-afca-b4a365bc5f6f','論語絕句  其二','張九成','宋','宋诗','song-poetry','','[]','算來只是弄精神，識破於時始悟真。',32,'全唐诗/poet.song.103000.json','["算來只是弄精神，識破於時始悟真。", "表裏分明都見了，區區何必更書紳。"]'),
('57e9cf93-de60-4cd2-b2ab-2a1ad9d4b524','論語絕句  其三','張九成','宋','宋诗','song-poetry','','[]','雖然此影不離形，莫向形中便認真。',32,'全唐诗/poet.song.103000.json','["雖然此影不離形，莫向形中便認真。", "形影兩亡都不見，當於此處認斯人。"]'),
('2815fb88-139d-4772-b400-240b5fd51eb6','論語絕句  其四','張九成','宋','宋诗','song-poetry','','[]','見得分明乃謂如，分明如此尚爲疏。',32,'全唐诗/poet.song.103000.json','["見得分明乃謂如，分明如此尚爲疏。", "莫於見處留形迹，方信心齋萬象虛。"]'),
('9e666a3b-f627-4cb4-bb72-4ae97a6811f1','論語絕句  其五','張九成','宋','宋诗','song-poetry','','[]','機緘固爾寓絃歌，不是知音不肯過。',32,'全唐诗/poet.song.103000.json','["機緘固爾寓絃歌，不是知音不肯過。", "夫子聞之方莞爾，未知言偃意如何。"]'),
('6a0ce731-1b6f-410f-abc3-d04e833bff45','論語絕句  其六','張九成','宋','宋诗','song-poetry','','[]','門人唯諾亦尋常，彼此如何較短長。',32,'全唐诗/poet.song.103000.json','["門人唯諾亦尋常，彼此如何較短長。", "自是旁人不曾識，指爲鳴鳳在朝陽。"]'),
('809f8cf7-2958-498d-b050-b85c5eb95587','論語絕句  其七','張九成','宋','宋诗','song-poetry','','[]','此理尋常豈不如，奈何人不反思之。',32,'全唐诗/poet.song.103000.json','["此理尋常豈不如，奈何人不反思之。", "故應指掌從君示，想亦於斯勿更疑。"]'),
('a3bcdd54-975f-4a2f-b948-2e029b1458f1','論語絕句  其八','張九成','宋','宋诗','song-poetry','','[]','於時舍瑟方鏗爾，豈意吾師亦喟然。',32,'全唐诗/poet.song.103000.json','["於時舍瑟方鏗爾，豈意吾師亦喟然。", "此際風流人不識，只應瀟灑得心傳。"]'),
('6fc61185-ff5c-4612-b7fc-1297c4ba30c6','論語絕句  其九','張九成','宋','宋诗','song-poetry','','[]','白首窮經恨不知，書生辛苦竟何爲。',32,'全唐诗/poet.song.103000.json','["白首窮經恨不知，書生辛苦竟何爲。", "一朝聞道無餘事，若較尋常死亦遲。"]'),
('d970f838-e513-4511-a849-67663b0fa15e','論語絕句  其一○','張九成','宋','宋诗','song-poetry','','[]','須知道體亦常虛，君子安能一器拘。',32,'全唐诗/poet.song.103000.json','["須知道體亦常虛，君子安能一器拘。", "賜也但知瑚璉貴，豈聞天地亦蘧廬。"]'),
('1b485144-7078-4d0d-aa39-9384eca721c7','論語絕句  其一一','張九成','宋','宋诗','song-poetry','','[]','所長孰不願施之，豈肯言吾未信斯。',32,'全唐诗/poet.song.103000.json','["所長孰不願施之，豈肯言吾未信斯。", "大是此心真不昧，斷知天地不容欺。"]'),
('4b8f5aa8-087d-4892-a02d-af64c02ada3c','論語絕句  其一二','張九成','宋','宋诗','song-poetry','','[]','行道嗟吾已矣夫，仲由從我去乘桴。',32,'全唐诗/poet.song.103000.json','["行道嗟吾已矣夫，仲由從我去乘桴。", "果然子路聞之喜，好勇如由亦自無。"]'),
('58bdedfd-6032-47ac-a015-c74a3db99528','論語絕句  其一三','張九成','宋','宋诗','song-poetry','','[]','豈是於回果弗如，只緣聞處尚多疏。',32,'全唐诗/poet.song.103000.json','["豈是於回果弗如，只緣聞處尚多疏。", "若還真箇能聞一，安得其他更有餘。"]'),
('8fe06a84-5489-4176-9a5e-1624a7cbc2f8','論語絕句  其一四','張九成','宋','宋诗','song-poetry','','[]','朽固難雕糞莫杇，於予材美亦何誅。',32,'全唐诗/poet.song.103000.json','["朽固難雕糞莫杇，於予材美亦何誅。", "欲令顧此深爲戒，言語之科首宰予。"]'),
('d879bcd1-edd7-4865-a2de-17d1e8f656ce','論語絕句  其一五','張九成','宋','宋诗','song-poetry','','[]','貧即無聊富即驕，回心獨爾樂簞瓢。',32,'全唐诗/poet.song.103000.json','["貧即無聊富即驕，回心獨爾樂簞瓢。", "箇中得趣無人會，惆悵遺風久寂寥。"]'),
('e624bac1-8a03-43a8-9d47-eb7e81a9b1ee','論語絕句  其一六','張九成','宋','宋诗','song-poetry','','[]','子路何嘗肯不情，從人姑爾事虛名。',32,'全唐诗/poet.song.103000.json','["子路何嘗肯不情，從人姑爾事虛名。", "所行唯恐復聞耳，既已聞之且力行。"]'),
('e8fa89be-12f7-488e-8df6-72be673fdecd','論語絕句  其一七','張九成','宋','宋诗','song-poetry','','[]','須知有慾不爲剛，血氣乘之反類狂。',32,'全唐诗/poet.song.103000.json','["須知有慾不爲剛，血氣乘之反類狂。", "所以孟軻言直養，要令無助亦無忘。"]'),
('de25ac96-25b2-49f3-bf1b-2565f831b5fe','論語絕句  其一八','張九成','宋','宋诗','song-poetry','','[]','文子平生不妄爲，仲尼想亦喜聞之。',32,'全唐诗/poet.song.103000.json','["文子平生不妄爲，仲尼想亦喜聞之。", "或能再矣斯猶可，何况加之以三思。"]'),
('14eeec5e-3e57-469a-b1c1-8928b5e05876','論語絕句  其一九','張九成','宋','宋诗','song-poetry','','[]','武子人皆指作愚，不知愚意竟何如。',32,'全唐诗/poet.song.103000.json','["武子人皆指作愚，不知愚意竟何如。", "雖愚到底無人識，始覺從來智者疏。"]'),
('877da92b-e24e-4a8f-9844-a5f1e9ad2770','論語絕句  其二○','張九成','宋','宋诗','song-poetry','','[]','願乘車馬衣輕裘，便與顔回論不投。',32,'全唐诗/poet.song.103000.json','["願乘車馬衣輕裘，便與顔回論不投。", "更得預聞夫子志，天高地下果難儔。"]'),
('7da0a896-2d44-4e17-8f03-5fe46bcddd12','論語絕句  其二一','張九成','宋','宋诗','song-poetry','','[]','三千七十固多哉，好學如何獨有回。',32,'全唐诗/poet.song.103000.json','["三千七十固多哉，好學如何獨有回。", "若論不遷并不貳，更無人向此中來。"]'),
('618bf92c-6b86-45ad-b22b-95551230f551','論語絕句  其二二','張九成','宋','宋诗','song-poetry','','[]','孔子於仁論不違，回心三月亦如之。',32,'全唐诗/poet.song.103000.json','["孔子於仁論不違，回心三月亦如之。", "不違乃是回心事，心事如何子得知。"]'),
('12e17ac9-8aa0-4763-9939-364a0b0898fd','論語絕句  其二三','張九成','宋','宋诗','song-poetry','','[]','算來此亦是尋常，不比其他味較長。',32,'全唐诗/poet.song.103000.json','["算來此亦是尋常，不比其他味較長。", "孔子絃歌顔子樂，大家相見沒商量。"]'),
('7e343fcc-67e4-4880-ba43-a50832600980','論語絕句  其二四','張九成','宋','宋诗','song-poetry','','[]','仁智從來不可分，動中機向靜中存。',32,'全唐诗/poet.song.103000.json','["仁智從來不可分，動中機向靜中存。", "自然形體難增損，不要猶添斧鑿痕。"]'),
('cbc21531-a17a-4c4e-8b26-a7b6bb57ee8c','論語絕句  其二五','張九成','宋','宋诗','song-poetry','','[]','未識機鋒莫浪猜，行藏吾只許顔回。',32,'全唐诗/poet.song.103000.json','["未識機鋒莫浪猜，行藏吾只許顔回。", "苟能用我吾何慊，不惜因渠也一來。"]'),
('10963886-d411-43e4-970b-53beb81ca8fb','論語絕句  其二六','張九成','宋','宋诗','song-poetry','','[]','子思曾發用中機，此道須臾不可離。',32,'全唐诗/poet.song.103000.json','["子思曾發用中機，此道須臾不可離。", "率性自然難損益，要之何慮亦何思。"]'),
('6c249002-fa0b-42e0-8972-808b888f5d4d','論語絕句  其二七','張九成','宋','宋诗','song-poetry','','[]','仁體從來大似天，事之方見失於偏。',32,'全唐诗/poet.song.103000.json','["仁體從來大似天，事之方見失於偏。", "是何堯舜有爲病，一或容心便不然。"]'),
('b1c1bd12-bed4-41d4-b5e7-736f46f1ae90','論語絕句  其二八','張九成','宋','宋诗','song-poetry','','[]','不因聞見得心傳，此理於吾甚曉然。',32,'全唐诗/poet.song.103000.json','["不因聞見得心傳，此理於吾甚曉然。", "若使一流聞見裏，故知厭倦有時焉。"]'),
('685c2bcf-444d-46a1-9a42-f007dc09bc5b','論語絕句  其二九','張九成','宋','宋诗','song-poetry','','[]','向也於公隔一重，尋思常在夢魂中。',32,'全唐诗/poet.song.103000.json','["向也於公隔一重，尋思常在夢魂中。", "如今已是心相識，爾自西行我自東。"]'),
('b4bcdb7b-4361-4ee1-8ffb-f2401d9423ec','論語絕句  其三○','張九成','宋','宋诗','song-poetry','','[]','試看迷途一瞽蒙，若還無相豈能通。',32,'全唐诗/poet.song.103000.json','["試看迷途一瞽蒙，若還無相豈能通。", "力行未到安身處，不免依他入箇中。"]'),
('2532575d-07f9-4d1b-8310-a2907a80aa9c','論語絕句  其三一','張九成','宋','宋诗','song-poetry','','[]','富貴要之不可求，求之無不反招尤。',32,'全唐诗/poet.song.103000.json','["富貴要之不可求，求之無不反招尤。", "何如且只從吾好，他若來時不自由。"]'),
('b3e3b8d9-f0df-4027-95c7-ad1c5a19c946','論語絕句  其三二','張九成','宋','宋诗','song-poetry','','[]','箾韶深寓舜之心，夫子聞之感亦深。',32,'全唐诗/poet.song.103000.json','["箾韶深寓舜之心，夫子聞之感亦深。", "三月遂忘於肉味，誰知千古遇知音。"]'),
('40ce889a-7678-4405-b9b7-3bd9e128635f','論語絕句  其三三','張九成','宋','宋诗','song-poetry','','[]','讀易工夫恨不深，晚年方見聖人心。',32,'全唐诗/poet.song.103000.json','["讀易工夫恨不深，晚年方見聖人心。", "如何五十云無過，蓋欲從初學到今。"]'),
('0b2ceca3-6331-45e2-9e0e-d653002b58c1','論語絕句  其三四','張九成','宋','宋诗','song-poetry','','[]','日月光明滿六虛，奈緣蒙瞽以爲無。',32,'全唐诗/poet.song.103000.json','["日月光明滿六虛，奈緣蒙瞽以爲無。", "試教借問傍人看，可是吾曾隱爾乎。"]'),
('c199a62d-2a50-4fca-a9fc-e481985cf000','論語絕句  其三五','張九成','宋','宋诗','song-poetry','','[]','射宿有心陰中物，釣綱終是不無心。',32,'全唐诗/poet.song.103000.json','["射宿有心陰中物，釣綱終是不無心。", "固知夫子應無此，書此方知意亦深。"]'),
