('bc8e934d-f30d-4914-9b84-769e41520dcb','頌古二十首  其一七','釋了一','宋','宋诗','song-poetry','','[]','竹箆舉起成生殺，豈肯容人亂札錐。',32,'全唐诗/poet.song.103000.json','["竹箆舉起成生殺，豈肯容人亂札錐。", "劈脊一揮如薦得，銀山鐵壁也光輝。"]'),
('f8d0f7a8-88b6-4e9f-8b33-d8fd0615b58f','頌古二十首  其一八','釋了一','宋','宋诗','song-poetry','','[]','鐘樓上念讚，床脚下種菜。',40,'全唐诗/poet.song.103000.json','["鐘樓上念讚，床脚下種菜。", "猛虎當路蹲，時人俱不會。", "黄蘗花開自有時，明州有箇憨布袋。"]'),
('04f787a3-785c-49d5-9f7c-823dd0e413b6','頌古二十首  其一九','釋了一','宋','宋诗','song-poetry','','[]','楊岐金圈與栗蓬，吞跳依前事不同。',32,'全唐诗/poet.song.103000.json','["楊岐金圈與栗蓬，吞跳依前事不同。", "大海都來一口吸，更無南北與西東。"]'),
('5c166a1f-fd98-4529-80ab-cf33c244e70a','頌古二十首  其二○','釋了一','宋','宋诗','song-poetry','','[]','熱糍盪口成痕跡，糍冷令人便動脾。',32,'全唐诗/poet.song.103000.json','["熱糍盪口成痕跡，糍冷令人便動脾。", "何似且拈安一處，家常茶飯且隨時。"]'),
('13b0cfa0-46d5-4a8a-b54f-5f3598744a90','偈二十首  其一','釋鼎需','宋','宋诗','song-poetry','','[]','隈嚴遁谷，敗種焦牙。',20,'全唐诗/poet.song.103000.json','["隈嚴遁谷，敗種焦牙。", "應物隨形，拖泥带水。"]'),
('72094599-f1e1-4713-8876-8a0d9223c290','偈二十首  其二','釋鼎需','宋','宋诗','song-poetry','','[]','奔流度刃，未是作家。',20,'全唐诗/poet.song.103000.json','["奔流度刃，未是作家。", "疾燄過風，猶爲鈍漢。"]'),
('c2a625cd-8557-4696-9de0-639a8f8622a0','偈二十首  其三','釋鼎需','宋','宋诗','song-poetry','','[]','子能承父業，賺殺幾多人。',40,'全唐诗/poet.song.103000.json','["子能承父業，賺殺幾多人。", "家破人亡後，無門寄此身。", "愁人莫向愁人說，說向愁人愁殺人。"]'),
('866791f4-5f35-4066-a2da-2092fb4089bb','偈二十首  其四','釋鼎需','宋','宋诗','song-poetry','','[]','欲得現前，莫存順逆。',20,'全唐诗/poet.song.103000.json','["欲得現前，莫存順逆。", "屙屎送尿，多少省力。"]'),
('3f998d85-1d16-40ce-a4fa-bc885dc1e2dc','偈二十首  其五','釋鼎需','宋','宋诗','song-poetry','','[]','堂堂兮巍巍，威威兮蕤蕤。',44,'全唐诗/poet.song.103000.json','["堂堂兮巍巍，威威兮蕤蕤。", "手携兔角杖，脚踏石烏龜。", "來莫可抑，去莫可追。", "而今到此，合掌趺跪。"]'),
('2d36e363-f624-4063-b322-66cb1d003fde','偈二十首  其六','釋鼎需','宋','宋诗','song-poetry','','[]','我觀鷂子摶天飛，烏龜水底逐魚兒。',52,'全唐诗/poet.song.103000.json','["我觀鷂子摶天飛，烏龜水底逐魚兒。", "三箇婆婆六箇嬭，金剛背上爛如泥。", "諸仁者，知不知。", "伯牙雖會彈，善聽須子期。"]'),
('85ac5752-cdfb-46fc-a0b4-81cb5cbd723b','偈二十首  其七','釋鼎需','宋','宋诗','song-poetry','','[]','昨夜三更轉向西，昏昏宇宙幾人迷。',32,'全唐诗/poet.song.103000.json','["昨夜三更轉向西，昏昏宇宙幾人迷。", "澄潭影轉風初息，孤狖微聞嶺外啼。"]'),
('ba16cf09-3ba6-42a4-9c8f-0a2573688cde','偈二十首  其八','釋鼎需','宋','宋诗','song-poetry','','[]','在凡全凡，在聖全聖。',80,'全唐诗/poet.song.103000.json','["在凡全凡，在聖全聖。", "各各據本位，通達事理竟。", "譬如鐘中無鼓響，鼓中無鐘聲。", "鐘鼓不相參，句句無前後。", "若能於此徹根源，一任金毛喚作狗。", "忙忙途路未歸人，切忌面南看北斗。"]'),
('0173ce52-3bc4-4a80-b4cc-bdee727f31ea','偈二十首  其九','釋鼎需','宋','宋诗','song-poetry','','[]','獨枕孤峯忘歲月，梧桐葉落始知秋。',94,'全唐诗/poet.song.103000.json','["獨枕孤峯忘歲月，梧桐葉落始知秋。", "若知撲落非他物，始解縱橫得自由。", "萬仞懸崖絲繫腰，百尺竿頭獨打翹。", "大洋海裏驟驊騮，須彌頂上駕扁舟。", "好箇通天作略，自然脫體風流。", "今朝有酒今朝醉，明日愁來明日愁。"]'),
('be0f6b16-b91f-4c9d-8bad-d18ae894a8b4','偈二十首  其一○','釋鼎需','宋','宋诗','song-poetry','','[]','行亦禪，坐亦禪，語默動靜體安然。',32,'全唐诗/poet.song.103000.json','["行亦禪，坐亦禪，語默動靜體安然。", "江上晚來堪畫處，一葉扁舟破遠煙。"]'),
('5e97bb75-f2f5-49b2-89c2-0f8433f10ee9','偈二十首  其一一','釋鼎需','宋','宋诗','song-poetry','','[]','陜府鐵牛吞大像，生得河東鸑鷟兒。',52,'全唐诗/poet.song.103000.json','["陜府鐵牛吞大像，生得河東鸑鷟兒。", "海門深處宜歸隱，只恐調高人不知。", "知不知，擬欲擡眸一顧之，早是失却兩莖眉。"]'),
('74c68c10-2a4c-4d0a-a17d-d1c341838569','偈二十首  其一二','釋鼎需','宋','宋诗','song-poetry','','[]','世尊拈花，迦葉微笑。',40,'全唐诗/poet.song.103000.json','["世尊拈花，迦葉微笑。", "師鐵得金，一場富貴。", "馬祖升堂，百丈卷席。", "爲衆竭力，禍出私門。"]'),
('34e9ac42-b2f7-4d39-8399-578c5b611375','偈二十首  其一三','釋鼎需','宋','宋诗','song-poetry','','[]','人間正月十五日，西來祖意若爲陳。',32,'全唐诗/poet.song.103000.json','["人間正月十五日，西來祖意若爲陳。", "樓臺上下火照火，車馬往來人看人。"]'),
('e97af5b9-6eac-4f19-b7e2-2d9ca1f503da','偈二十首  其一四','釋鼎需','宋','宋诗','song-poetry','','[]','一不得孤負自己，二不得停囚長智。',36,'全唐诗/poet.song.103000.json','["一不得孤負自己，二不得停囚長智。", "三不得生心比擬，擬不擬，眨起眉毛千萬里。"]'),
('131f6884-ac94-4507-baee-a370b0d2c65d','偈二十首  其一五','釋鼎需','宋','宋诗','song-poetry','','[]','虎頭带角人難措，石火電光須密布。',32,'全唐诗/poet.song.103000.json','["虎頭带角人難措，石火電光須密布。", "假饒烈士薦應難，懵底那能解回互。"]'),
('545ea494-4cc4-4fe1-a8dd-dbd4d0681c70','偈二十首  其一六','釋鼎需','宋','宋诗','song-poetry','','[]','死中活，閒雲散盡長空闊。',61,'全唐诗/poet.song.103000.json','["死中活，閒雲散盡長空闊。", "活中死，螺江水流截不住。", "兩岸蘆花相對開，漁翁撥棹還歸去。", "去去何處，寒梅已綻嶺南枝，漫漫雪覆千峯寺。"]'),
('e6cbd2d3-c5ab-4f0c-b48f-412fc94eeb12','偈二十首  其一七','釋鼎需','宋','宋诗','song-poetry','','[]','三月安居，九旬禁足。',36,'全唐诗/poet.song.103000.json','["三月安居，九旬禁足。", "物外閒人，何拘何束。", "青絹扇子足風凉，一任山青并水綠。"]'),
('210188ae-c8c8-4bec-9dba-9acb55672820','偈二十首  其一八','釋鼎需','宋','宋诗','song-poetry','','[]','行羅漢慈，破結賊故。',30,'全唐诗/poet.song.103000.json','["行羅漢慈，破結賊故。", "行菩薩慈，安衆生故。", "行如來慈，續慧命故。"]'),
('572296b8-2b11-44b8-91b1-a8bd60d54833','偈二十首  其一九','釋鼎需','宋','宋诗','song-poetry','','[]','橫按吹毛，虛張意氣。',20,'全唐诗/poet.song.103000.json','["橫按吹毛，虛張意氣。", "衝開鐵壁，枉費精神。"]'),
('d76007b3-554e-47a0-9578-192de33083ba','偈二十首  其二○','釋鼎需','宋','宋诗','song-poetry','','[]','西天悉達多太子，今日降神出母胎。',32,'全唐诗/poet.song.103000.json','["西天悉達多太子，今日降神出母胎。", "一步一蓮隨寶足，人間天上獨崔嵬。"]'),
('be8f527e-2de3-4384-bbd3-0c202906a9c0','頌古四首  其一','釋鼎需','宋','宋诗','song-poetry','','[]','入息未嘗居陰界，出息何曾涉萬緣。',32,'全唐诗/poet.song.103000.json','["入息未嘗居陰界，出息何曾涉萬緣。", "一聲漁笛離南浦，依舊蘆花深處眠。"]'),
('a2c8ed8f-3f71-45be-a999-278b9b6d3454','頌古四首  其二','釋鼎需','宋','宋诗','song-poetry','','[]','池陽面壁許誰知，萬古孤峯對落暉。',32,'全唐诗/poet.song.103000.json','["池陽面壁許誰知，萬古孤峯對落暉。", "纔見攢眉便回去，早知不是丈夫兒。"]'),
('dcf94733-52b0-494c-8bcd-ed93fbf6ce39','頌古四首  其三','釋鼎需','宋','宋诗','song-poetry','','[]','閉門入圃太周遮，一喚回頭便到家。',32,'全唐诗/poet.song.103000.json','["閉門入圃太周遮，一喚回頭便到家。", "良遂知時人不委，海山空映夕陽斜。"]'),
('c4b08eb6-4ae4-4f34-9d21-e6c05d385151','頌古四首  其四','釋鼎需','宋','宋诗','song-poetry','','[]','言言言兮，飄風灑雪。',36,'全唐诗/poet.song.103000.json','["言言言兮，飄風灑雪。", "默默默兮，雷輷電掣。", "藕絲孔裏騎大鵬，等閒挨落天邊月。"]'),
('7e984dd4-13ac-4a40-b829-83e8197d2944','自贊','釋鼎需','宋','宋诗','song-poetry','','[]','一不愛乖崖傲物，又不愛像樓打樓。',32,'全唐诗/poet.song.103000.json','["一不愛乖崖傲物，又不愛像樓打樓。", "飽諳世事慵開口，暗展雙眉自點頭。"]'),
('7cd63981-5074-44c4-820c-2379992a66eb','偈四首  其一','釋鼎需','宋','宋诗','song-poetry','','[]','便請從東過西，不妨水雲自若。',28,'全唐诗/poet.song.103000.json','["便請從東過西，不妨水雲自若。", "如其稍涉遲回，直是一槌粉碎。"]'),
('c708b928-ea41-4b74-a335-68abcbb48417','偈四首  其二','釋鼎需','宋','宋诗','song-poetry','','[]','懶翁懶中懶，最懶懶說禪。',52,'全唐诗/poet.song.103000.json','["懶翁懶中懶，最懶懶說禪。", "亦不重自己，亦不重先賢。", "又誰管你地，又誰管你天。", "物外翛然無個事，日上三竿猶更眠。"]'),
('bd20dbde-0df3-4d80-881c-27110510d5ee','偈四首  其三','釋鼎需','宋','宋诗','song-poetry','','[]','心如皎月連天照，性似寒潭徹底清。',32,'全唐诗/poet.song.103000.json','["心如皎月連天照，性似寒潭徹底清。", "無價夜光人不識，夢中虛度幾千春。"]'),
('20129200-2f93-4ce0-8862-09e2de8559dc','偈四首  其四','釋鼎需','宋','宋诗','song-poetry','','[]','十四十五，明明已露。',20,'全唐诗/poet.song.103000.json','["十四十五，明明已露。", "更問如何，西天此土。"]'),
('a5e34d31-b840-4c6a-a032-75be5bc93f38','偈','釋鼎需','宋','宋诗','song-poetry','','[]','頂門豎亞摩醯眼，肘後斜懸奪命符。',32,'全唐诗/poet.song.103000.json','["頂門豎亞摩醯眼，肘後斜懸奪命符。", "瞎却眼，卸却符，趙州東壁掛葫蘆。"]'),
('310362bf-a499-474b-9e00-c73fdf27d35e','頌古十七首  其一','釋鼎需','宋','宋诗','song-poetry','','[]','鳥窠佛法無多子，只在襤襂一布毛。',32,'全唐诗/poet.song.103000.json','["鳥窠佛法無多子，只在襤襂一布毛。", "一氣吹來何處去，至今天下有譊訛。"]'),
('0069dac1-4944-4050-88ec-d5c3a132a672','頌古十七首  其二','釋鼎需','宋','宋诗','song-poetry','','[]','打車即是打牛是，鼻孔遼天也被穿。',32,'全唐诗/poet.song.103000.json','["打車即是打牛是，鼻孔遼天也被穿。", "已向人前輸肺腑，可憐今古妄加鞭。"]'),
('25af9889-6b70-498d-8017-d6742b0c2f7a','頌古十七首  其三','釋鼎需','宋','宋诗','song-poetry','','[]','父子相將草裏遊，人前拈弄幾包羞。',32,'全唐诗/poet.song.103000.json','["父子相將草裏遊，人前拈弄幾包羞。", "返雷一震驚天地，直得滄溟絕點流。"]'),
('3df2129c-0ba9-479c-8d05-374911a9fed1','頌古十七首  其四','釋鼎需','宋','宋诗','song-poetry','','[]','大義開田創祖基，分明書契示傳持。',32,'全唐诗/poet.song.103000.json','["大義開田創祖基，分明書契示傳持。", "兒孫不肯遺先業，乞食年年役路歧。"]'),
('251cc424-38e9-41c1-a497-2942fd2aa1f0','頌古十七首  其五','釋鼎需','宋','宋诗','song-poetry','','[]','王令威嚴誰敢擬，纖毫纔動鐵輪隨。',32,'全唐诗/poet.song.103000.json','["王令威嚴誰敢擬，纖毫纔動鐵輪隨。", "時人只見錐頭利，幾人能見利頭錐。"]'),
('00219db8-8230-4ccc-8549-ecb545ee62c2','頌古十七首  其六','釋鼎需','宋','宋诗','song-poetry','','[]','鏌铘在握當堂坐，擬欲衝前便喪軀。',32,'全唐诗/poet.song.103000.json','["鏌铘在握當堂坐，擬欲衝前便喪軀。", "縱使機鋒如電拂，到頭未免病棲蘆。"]'),
('f7a09f25-3e80-4239-b973-4c0b0f8d1686','頌古十七首  其七','釋鼎需','宋','宋诗','song-poetry','','[]','堪笑當年陸大夫，獨誇身外更無餘。',32,'全唐诗/poet.song.103000.json','["堪笑當年陸大夫，獨誇身外更無餘。", "不因指出花如夢，爭得雙眸翳盡除。"]'),
('cc356914-fab7-4db3-bdc8-123b43597339','頌古十七首  其八','釋鼎需','宋','宋诗','song-poetry','','[]','鹽貴米賤，諸事成現。',20,'全唐诗/poet.song.103000.json','["鹽貴米賤，諸事成現。", "擬欲商量，腦後拔箭。"]'),
('78325de3-11d1-4cd6-b8fa-995b3239d9ad','頌古十七首  其九','釋鼎需','宋','宋诗','song-poetry','','[]','金木水火土，始終顛倒數。',43,'全唐诗/poet.song.103000.json','["金木水火土，始終顛倒數。", "五六下四三，初爻傳白虎。", "苦苦，卜得此卦一生貧，遠信不來病人死。"]'),
('df8239b4-c8af-420c-b0a8-9b3d6d743162','頌古十七首  其一○','釋鼎需','宋','宋诗','song-poetry','','[]','騎虎頭，把虎尾，霹靂一聲驚萬里。',44,'全唐诗/poet.song.103000.json','["騎虎頭，把虎尾，霹靂一聲驚萬里。", "坐觀成敗老將軍，腦後一槌誰敢擬。", "擬不擬，箇箇無裩長者子。"]'),
('e6c3684e-b16b-4599-a8ce-b74a36024c0a','頌古十七首  其一一','釋鼎需','宋','宋诗','song-poetry','','[]','昨夜三更轉向西，昏昏宇宙幾人迷。',32,'全唐诗/poet.song.103000.json','["昨夜三更轉向西，昏昏宇宙幾人迷。", "澄潭影轉風初息，猿狖微聞嶺外啼。"]'),
('74ce6e38-a9e6-48bb-9b1b-0f1628ec8919','頌古十七首  其一二','釋鼎需','宋','宋诗','song-poetry','','[]','兩箇孩兒抱花鼓，左邊打了右邊舞。',32,'全唐诗/poet.song.103000.json','["兩箇孩兒抱花鼓，左邊打了右邊舞。", "一曲兩曲無人會，歷歷清風動千古。"]'),
('845eaa41-7b5a-46bf-9c25-be537c1997c8','頌古十七首  其一三','釋鼎需','宋','宋诗','song-poetry','','[]','京師出大黄，不許謾商量。',24,'全唐诗/poet.song.103000.json','["京師出大黄，不許謾商量。", "貴買還賤賣，纔喫便承當。"]'),
('f497fe05-1c17-41c9-845e-939a7c21a75f','頌古十七首  其一四','釋鼎需','宋','宋诗','song-poetry','','[]','一不問兮二不休，直須識取那鈎頭。',32,'全唐诗/poet.song.103000.json','["一不問兮二不休，直須識取那鈎頭。", "再三回首來相見，急水波心輥繡毬。"]'),
('a68b0ff1-5cfa-4c76-b980-fbc00681c098','頌古十七首  其一五','釋鼎需','宋','宋诗','song-poetry','','[]','雲門大作師子吼，剛把衷腸爲誰剖。',50,'全唐诗/poet.song.103000.json','["雲門大作師子吼，剛把衷腸爲誰剖。", "眼似流星尚懵然，狂夫逐臭爭知有。", "君不見，巖頭有語兮，咬人屎橛非好狗。"]'),
('febc106f-65fa-428e-bc68-b57c65ffa3eb','頌古十七首  其一六','釋鼎需','宋','宋诗','song-poetry','','[]','畐塞虛空，不如不去。',36,'全唐诗/poet.song.103000.json','["畐塞虛空，不如不去。", "前後際斷，今亦無住。", "倒騎佛殿出三門，却把三門掛露柱。"]'),
('a24d8474-4a3e-4be8-9bff-f89d58f919b5','頌古十七首  其一七','釋鼎需','宋','宋诗','song-poetry','','[]','全鋒敵勝鐵牛機，電掣雷奔已是遲。',54,'全唐诗/poet.song.103000.json','["全鋒敵勝鐵牛機，電掣雷奔已是遲。", "等閒活捉盧陂老，縱饒猛略若爲施。", "君不見，寰中意氣，閫外威權，擬議衝前總滅門。"]'),
('ea4002fe-cdce-4089-9969-b6eef55e44d9','頌古十七首  其一八','釋鼎需','宋','宋诗','song-poetry','','[]','𪂶𪂶鳥，守空池。',20,'全唐诗/poet.song.103000.json','["𪂶𪂶鳥，守空池。", "魚從脚底過，𪂶𪂶總不知。"]'),
('664879e1-dc78-420c-a441-0779d23736f7','頌古十七首  其一九','釋鼎需','宋','宋诗','song-poetry','','[]','幽谷白雲藏白雀，擬心棲處隔山迷。',32,'全唐诗/poet.song.103000.json','["幽谷白雲藏白雀，擬心棲處隔山迷。", "直饒不住棲心處，猶落怡山第二機。"]'),
('02dd471a-8013-4e4c-9656-4ad03d8bcbfb','頌古十七首  其二○','釋鼎需','宋','宋诗','song-poetry','','[]','三人證龜成鱉，剛把天機漏洩。',28,'全唐诗/poet.song.103000.json','["三人證龜成鱉，剛把天機漏洩。", "木人嶺上唱歌，石女眼中滴血。"]'),
('5b43bdca-a4b8-4b98-94f4-f3e91da3e6da','頌古十七首  其二一','釋鼎需','宋','宋诗','song-poetry','','[]','路窮崖斷進無門，賴有山翁指出原。',32,'全唐诗/poet.song.103000.json','["路窮崖斷進無門，賴有山翁指出原。", "九曲黄河清徹底，誰知別是一乾坤。"]'),
('c913a26b-61a9-4a03-8155-1b9c3a0877df','梅花','黄彥節','宋','宋诗','song-poetry','','[]','擬嚼枝頭蠟，驚香却肖蘭。',24,'全唐诗/poet.song.103000.json','["擬嚼枝頭蠟，驚香却肖蘭。", "前村深雪裏，莫作嶺梅看。"]'),
('8b47a095-a499-4dc4-abee-82e185f02e60','偈二十七首  其一','釋守浄','宋','宋诗','song-poetry','','[]','定光金地遥招手，智者江陵暗點頭。',32,'全唐诗/poet.song.103000.json','["定光金地遥招手，智者江陵暗點頭。", "已是白雲千萬里，那堪於此未知休。"]'),
('c1dbfce2-69f9-4da2-9f2c-00fcac36f82d','偈二十七首  其二','釋守浄','宋','宋诗','song-poetry','','[]','談玄說妙，撒屎撒尿。',30,'全唐诗/poet.song.103000.json','["談玄說妙，撒屎撒尿。", "行棒行喝，將鹽止渴。", "立主立賓，花擘宗乘。"]'),
('a553dbc8-2d42-4a81-b7b2-bbc983796813','偈二十七首  其三','釋守浄','宋','宋诗','song-poetry','','[]','傳來鐵鉢盛貓飯，摩衲袈裟入墨盆。',32,'全唐诗/poet.song.103000.json','["傳來鐵鉢盛貓飯，摩衲袈裟入墨盆。", "祖翁活計都壞了，不知將底付兒孫。"]'),
('53af78e8-b023-4432-9e97-aea235ac8ef9','偈二十七首  其四','釋守浄','宋','宋诗','song-poetry','','[]','堂前露柱久懷胎，長下嬰兒頗俊哉。',32,'全唐诗/poet.song.103000.json','["堂前露柱久懷胎，長下嬰兒頗俊哉。", "未解語言先作賦，一操直取狀元來。"]'),
('0703f4f9-e136-4c84-a21e-eb8137cf8949','偈二十七首  其五','釋守浄','宋','宋诗','song-poetry','','[]','文殊普賢談理事，臨濟德山行棒喝。',32,'全唐诗/poet.song.103000.json','["文殊普賢談理事，臨濟德山行棒喝。", "東禪一覺到天明，偏愛風從凉處發。"]'),
('8d36af0a-4eca-410f-964f-90bb53ad5a22','偈二十七首  其六','釋守浄','宋','宋诗','song-poetry','','[]','一念得心，頓超三界。',36,'全唐诗/poet.song.103000.json','["一念得心，頓超三界。", "得無所得，貪瞋爛壞。", "野草閒花滿地愁，將軍戰馬今何在。"]'),
('deab314f-9a62-48c7-a980-04aca955f6ea','偈二十七首  其七','釋守浄','宋','宋诗','song-poetry','','[]','九夏炎炎火熱，木人汗流不輟。',28,'全唐诗/poet.song.103000.json','["九夏炎炎火熱，木人汗流不輟。", "夜來一雨便凉，莫道山僧不說。"]'),
('f76d2bc3-0ba6-4ee5-a245-69ecabad860d','偈二十七首  其八','釋守浄','宋','宋诗','song-poetry','','[]','正炊折脚鐺安隱，無奈公文抵死催。',32,'全唐诗/poet.song.103000.json','["正炊折脚鐺安隱，無奈公文抵死催。", "硬把死蛇頭不得，隨時之義大矣哉。"]'),
('d81ebe29-0622-42a1-b4bb-8a3156d61487','偈二十七首  其九','釋守浄','宋','宋诗','song-poetry','','[]','大兄杜口毗耶，小兄掩室摩竭。',28,'全唐诗/poet.song.103000.json','["大兄杜口毗耶，小兄掩室摩竭。", "恰好和我三人，大家證龜作鱉。"]'),
('6ff7b4bc-0c3b-456d-97d9-8abcca2e17a9','偈二十七首  其一○','釋守浄','宋','宋诗','song-poetry','','[]','石門深且幽，好住不肯住。',56,'全唐诗/poet.song.103000.json','["石門深且幽，好住不肯住。", "翻身入城隍，却向鬧市去。", "鬧浩浩處冷湫湫，冷湫湫處看楊州。", "四五百條花柳巷，二三千處管絃樓。"]'),
('64998451-47de-4d6e-8e7b-ec13ee7ebc8e','偈二十七首  其一一','釋守浄','宋','宋诗','song-poetry','','[]','慧不厭修，福不厭作。',50,'全唐诗/poet.song.103000.json','["慧不厭修，福不厭作。", "福慧雙收，如虎戴角。", "作既無作，修亦無修。", "青山綠水，短棹孤舟。", "格外之談，迥出常流。"]'),
('033b5c3d-ac93-4e55-89c3-cb59ff2ce0bd','偈二十七首  其一二','釋守浄','宋','宋诗','song-poetry','','[]','不用立雪庭下，不用斷臂師前。',42,'全唐诗/poet.song.103000.json','["不用立雪庭下，不用斷臂師前。", "須信當人分上，已與佛祖齊肩。", "會得朝打八百，不會暮打三千。"]'),
('97f53b03-f9ae-4fe4-b307-b8f95657fef7','偈二十七首  其一三','釋守浄','宋','宋诗','song-poetry','','[]','瞿曇鼓動三寸舌，四十九年無法說。',48,'全唐诗/poet.song.103000.json','["瞿曇鼓動三寸舌，四十九年無法說。", "達磨不立一字脚，列派分枝無處著。", "青山不鎖長飛勢，滄海合知來處高。"]'),
('e48bcf8d-a60a-4b28-9574-b677186f2c1c','偈二十七首  其一四','釋守浄','宋','宋诗','song-poetry','','[]','念念捨離諸惡趣，心心克取佛菩提。',32,'全唐诗/poet.song.103000.json','["念念捨離諸惡趣，心心克取佛菩提。", "取捨二途如脫得，永嘉元不識曹溪。"]'),
('9d99d214-f216-43d5-bdf2-19f48f84dc4b','偈二十七首  其一五','釋守浄','宋','宋诗','song-poetry','','[]','佛祖頂𩕳上，有破天大路。',46,'全唐诗/poet.song.103000.json','["佛祖頂𩕳上，有破天大路。", "未透生死關，如何敢進步。", "不進步，大千沒遮護。", "一句絕言詮，那吒擎鐵柱。"]'),
('6164dea8-6249-49b2-bdf6-f383017212f3','偈二十七首  其一六','釋守浄','宋','宋诗','song-poetry','','[]','流水下山非有意，片雲歸洞本無心。',32,'全唐诗/poet.song.103000.json','["流水下山非有意，片雲歸洞本無心。", "人生若得如雲水，鐵樹開花遍界春。"]'),
('b23b3106-0648-47fb-8751-e97759e4cd89','偈二十七首  其一七','釋守浄','宋','宋诗','song-poetry','','[]','我有折脚鐺，三子共提掇。',48,'全唐诗/poet.song.103000.json','["我有折脚鐺，三子共提掇。", "一著一著高，一步一步闊。", "從此活業興，清風動寥泬。", "夜半放烏雞，頭上一點雪。"]'),
('72a570d9-c3e5-4222-96b4-77c25abd07b7','偈二十七首  其一八','釋守浄','宋','宋诗','song-poetry','','[]','今朝十二，鼓聲動地。',34,'全唐诗/poet.song.103000.json','["今朝十二，鼓聲動地。", "雲水上來，討甚巴鼻。", "直饒天雨四花，爭似歸堂打睡。"]'),
('1e0649ab-acdc-4281-9d37-7846f8736624','偈二十七首  其一九','釋守浄','宋','宋诗','song-poetry','','[]','達磨不來東土，二祖不往西天。',28,'全唐诗/poet.song.103000.json','["達磨不來東土，二祖不往西天。", "老盧不識五祖，誰云夜半衣傳。"]'),
('82734a99-047e-4daf-ba31-89ba7dd11914','偈二十七首  其二○','釋守浄','宋','宋诗','song-poetry','','[]','日日波波走，夜夜不曾停。',24,'全唐诗/poet.song.103000.json','["日日波波走，夜夜不曾停。", "走到歲窮夜，依舊定盤星。"]'),
('cf84ec18-cfe0-4d32-aad9-a13612082a09','偈二十七首  其二一','釋守浄','宋','宋诗','song-poetry','','[]','三十六旬窮此夕，定盤星上轉風車。',32,'全唐诗/poet.song.103000.json','["三十六旬窮此夕，定盤星上轉風車。", "放開結角羅紋處，須信風流出當家。"]'),
('ec2d1217-9d8e-497c-9ea0-54e5d05f420f','偈二十七首  其二二','釋守浄','宋','宋诗','song-poetry','','[]','我有懶菴兄，夤緣真有在。',48,'全唐诗/poet.song.103000.json','["我有懶菴兄，夤緣真有在。", "從東復過西，兩處成交代。", "去矣無遺恨，所欠唯睡債。", "難忘手足情，特來爲渠賽。"]'),
('44af1487-a93e-4afc-a2ca-4ef239b2dd6f','偈二十七首  其二三','釋守浄','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','常州有，福州無，江風作惡浪花粗。',32,'全唐诗/poet.song.103000.json','["常州有，福州無，江風作惡浪花粗。", "不用刻舟徒記劍，片帆已過洞庭湖。"]'),
('b5df7bee-b5ec-416a-aad7-22d6bc3377ba','偈二十七首  其二四','釋守浄','宋','宋诗','song-poetry','','[]','三分光陰二早過，靈臺一點不揩磨。',32,'全唐诗/poet.song.103000.json','["三分光陰二早過，靈臺一點不揩磨。", "貪生逐日區區去，喚不回頭爭奈何。"]'),
('2d8290a2-bf82-4bd8-9ee9-07b9144edc27','偈二十七首  其二五','釋守浄','宋','宋诗','song-poetry','','[]','一葉落，便知秋，顢頇佛性。',56,'全唐诗/poet.song.103000.json','["一葉落，便知秋，顢頇佛性。", "一塵起，大地收，儱侗真如。", "若是衲僧門下客，不用更躊躇。", "曾向華山圖上看，又添潘閬倒騎驢。"]'),
('eab92a9e-ffc4-4078-8b8e-9fb266cf301b','偈二十七首  其二六','釋守浄','宋','宋诗','song-poetry','','[]','夢幻空花，六十七年。',20,'全唐诗/poet.song.103000.json','["夢幻空花，六十七年。", "白鳥煙沒，秋水連天。"]'),
('6231c602-bf34-4ee0-bc98-8a0f5af75789','偈二十七首  其二七','釋守浄','宋','宋诗','song-poetry','','[]','夢幻空花六十七，臨行猶自老婆心。',32,'全唐诗/poet.song.103000.json','["夢幻空花六十七，臨行猶自老婆心。", "鴛鴦繡出與人看，誰知元不犯金針。"]'),
('dcd8bce4-cfe3-4ed4-8993-281e33641230','頌古四首  其一','釋守浄','宋','宋诗','song-poetry','','[]','析盡屍骸沒一些，從茲遍界是那吒。',32,'全唐诗/poet.song.103000.json','["析盡屍骸沒一些，從茲遍界是那吒。", "直饒見得無纖翳，未免重添眼裏花。"]'),
('ff34dd73-c526-4317-875f-37a10bfda839','頌古四首  其二','釋守浄','宋','宋诗','song-poetry','','[]','普請開田力已齊，紛紛带水又拖泥。',32,'全唐诗/poet.song.103000.json','["普請開田力已齊，紛紛带水又拖泥。", "展開兩手人休問，昨夜三更月落西。"]'),
('0d5fc9c1-b42b-46d9-a461-207eec2df963','頌古四首  其三','釋守浄','宋','宋诗','song-poetry','','[]','不知此土何爲驗，拈起新羅人草鞋。',32,'全唐诗/poet.song.103000.json','["不知此土何爲驗，拈起新羅人草鞋。", "漢祖殿前樊噲怒，鴻門一踏爲誰開。"]'),
('838b294a-8053-49f5-8a32-0a4a657e787c','頌古四首  其四','釋守浄','宋','宋诗','song-poetry','','[]','涅槃償債更無殊，劈破長沙肘後符。',32,'全唐诗/poet.song.103000.json','["涅槃償債更無殊，劈破長沙肘後符。", "一句全提無話會，錢塘八月浪花粗。"]'),
('0578d99d-4cb6-4c56-8e4f-66377e4445c3','偈三首  其一','釋守浄','宋','宋诗','song-poetry','','[]','坐斷毗盧頂𩕳，須是沒量大人。',28,'全唐诗/poet.song.103000.json','["坐斷毗盧頂𩕳，須是沒量大人。", "若是沒量大人，不坐毗盧頂𩕳。"]'),
('be705a1f-bf24-437b-b92f-a2df7f5e332c','偈三首  其二','釋守浄','宋','宋诗','song-poetry','','[]','今朝臘月九，窮漢外邊走。',40,'全唐诗/poet.song.103000.json','["今朝臘月九，窮漢外邊走。", "雖然不還家，却是他好手。", "陋巷不騎金色馬，回途却著破襴衫。"]'),
('a9f185ed-badf-40c3-b959-9c3f518d448a','偈三首  其三','釋守浄','宋','宋诗','song-poetry','','[]','若欲正提綱，直須大地荒。',24,'全唐诗/poet.song.103000.json','["若欲正提綱，直須大地荒。", "欲來衝雪刃，未免露鋒鋩。"]'),
('29df9c60-c988-4233-9eb1-e7011da771c1','偈一首','釋守浄','宋','宋诗','song-poetry','','[]','閉却口，時時說。',48,'全唐诗/poet.song.103000.json','["閉却口，時時說。", "截却舌，無間歇。", "無間歇，最奇絕。", "最奇絕，眼中屑。", "了了了時無可了，玄玄玄處亦須呵。"]'),
('898826f3-cf43-406c-955a-90a6661d599f','頌古','釋守浄','宋','宋诗','song-poetry','','[]','比謂拈來伸一問，如何舉衆盡茫然。',32,'全唐诗/poet.song.103000.json','["比謂拈來伸一問，如何舉衆盡茫然。", "不因一撲百雜碎，定作人間醜婦寃。"]'),
('84855c87-6ca8-4c1a-8b5f-392cbfe1ec9f','調空首座','釋守浄','宋','宋诗','song-poetry','','[]','山龜有殻藏頭尾，七十二鉆不奈何。',32,'全唐诗/poet.song.103000.json','["山龜有殻藏頭尾，七十二鉆不奈何。", "恰似秀峰空首座，嘉招不肯出煙蘿。"]'),
('ba86cb13-34ef-42bb-8454-96d078ad938e','頌古七首  其一','釋道謙','宋','宋诗','song-poetry','','[]','賢聖劫來未曾殺，而今斷這一刀休。',32,'全唐诗/poet.song.103000.json','["賢聖劫來未曾殺，而今斷這一刀休。", "果然葛怛胸中落，笑殺靈山老比丘。"]'),
('2cee0a38-f609-44f6-870a-645c37ac8756','頌古七首  其二','釋道謙','宋','宋诗','song-poetry','','[]','四箇沒意智漢，做處總無畔岸。',28,'全唐诗/poet.song.103000.json','["四箇沒意智漢，做處總無畔岸。", "一狀領過階前，與伊據款結案。"]'),
('14ed1554-6f99-44e7-8bae-e9041372477c','頌古七首  其三','釋道謙','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','浩浩長江際碧空，片帆高挂便乘風。',32,'全唐诗/poet.song.103000.json','["浩浩長江際碧空，片帆高挂便乘風。", "快哉不費纖毫力，萬里家鄉咫尺通。"]'),
('4dc25513-84b5-402c-8971-eb7114f02343','頌古七首  其四','釋道謙','宋','宋诗','song-poetry','','[]','誰家飯挂空梁，指與小兒令看。',28,'全唐诗/poet.song.103000.json','["誰家飯挂空梁，指與小兒令看。", "解開即是灰囊，當下命根便斷。"]'),
('040502f8-d66f-4f86-bd32-aa6793ffacc6','頌古七首  其五','釋道謙','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','賣盡田園徹骨貧，不知何處可容身。',32,'全唐诗/poet.song.103000.json','["賣盡田園徹骨貧，不知何處可容身。", "樓頭浪蕩無拘檢，鐵笛橫吹過洞庭。"]'),
('494983be-1058-49f5-8cc0-33b4cd170548','頌古七首  其六','釋道謙','宋','宋诗','song-poetry','','["\u534e\u5c71"]','華嶽三峰翠插天，上頭無路可躋攀。',32,'全唐诗/poet.song.103000.json','["華嶽三峰翠插天，上頭無路可躋攀。", "不知誰有神仙手，折取峰頭十丈蓮。"]'),
('28f6c4f5-6e08-4105-9281-c26e37676370','頌古七首  其七','釋道謙','宋','宋诗','song-poetry','','[]','太平時節歲豐盈，旅不赍糧戶不扃。',32,'全唐诗/poet.song.103000.json','["太平時節歲豐盈，旅不赍糧戶不扃。", "官路無人夜無月，唱歌歸去恰三更。"]'),
('31884ccf-0049-47a0-bb34-5a3aa9ac524c','送道友','釋道謙','宋','宋诗','song-poetry','','[]','二三尺雪山藏路，一兩點花春到梅。',32,'全唐诗/poet.song.103000.json','["二三尺雪山藏路，一兩點花春到梅。", "將此贈君持不去，請君收拾早歸來。"]'),
('554bbc61-5acb-462f-b602-c955258cb486','偈','釋法寶','宋','宋诗','song-poetry','','[]','千般言，萬種喻，祇要教君早回去。',32,'全唐诗/poet.song.103000.json','["千般言，萬種喻，祇要教君早回去。", "夜來一片黑雲生，莫教錯却山前路。"]'),
('5c0d73f4-8789-4995-ade2-c8f14d576ac5','偈一首','釋祖元','宋','宋诗','song-poetry','','[]','小菴小舍小叢林，土地何須八九人。',32,'全唐诗/poet.song.103000.json','["小菴小舍小叢林，土地何須八九人。", "若解輪番來打供，免教碎作一堆塵。"]'),
('85ed802f-5566-4d31-8b27-0c23bff58e5e','香嚴貧','釋祖元','宋','宋诗','song-poetry','','[]','無地無錐未是貧，知無尚有守無身。',32,'全唐诗/poet.song.103000.json','["無地無錐未是貧，知無尚有守無身。", "儂家近日貧來甚，不見當初貧底人。"]'),
('6da59922-18cf-4c7f-9433-6200ecb57683','竹篦','釋祖元','宋','宋诗','song-poetry','','[]','不觸又不背，徒勞生擬議。',24,'全唐诗/poet.song.103000.json','["不觸又不背，徒勞生擬議。", "開口更商量，白雲千萬里。"]'),
('9061829e-ce18-431c-b4d5-7dcfb2be7764','偈三首  其一','釋祖元','宋','宋诗','song-poetry','','[]','剔起燈來是火，歷劫無明照破。',28,'全唐诗/poet.song.103000.json','["剔起燈來是火，歷劫無明照破。", "歸堂撞見聖僧，幾乎當面蹉過。"]'),
('10af3b1a-1ea2-4631-8235-4ae33cb2010b','偈三首  其二','釋祖元','宋','宋诗','song-poetry','','[]','有佛處不得住，踏著秤鎚硬似鐵。',69,'全唐诗/poet.song.103000.json','["有佛處不得住，踏著秤鎚硬似鐵。", "無佛處急走過，脚下草深三尺。", "三千里外，逢人不得錯舉。", "北斗掛須彌，棒頭挑日月。", "摘楊花，摘楊花，眼裏瞳人著繡鞋。"]'),
('9d4264df-4f26-467b-9408-85c7efd12e07','偈三首  其三','釋祖元','宋','宋诗','song-poetry','','[]','雁山枯木實頭禪，不在尖新語句邊。',32,'全唐诗/poet.song.103000.json','["雁山枯木實頭禪，不在尖新語句邊。", "背手忽然摸得著，長鯨吞月浪滔天。"]'),
('b8c15011-0421-42b9-b5c1-c2fb8eafbb2e','偈頌七首  其一','釋思岳','宋','宋诗','song-poetry','','[]','鼓山不跨石門句，嚼碎令人牙齒寒。',32,'全唐诗/poet.song.103000.json','["鼓山不跨石門句，嚼碎令人牙齒寒。", "親扣國師問端的，石門無鎖亦無關。"]'),
('9eb5d957-6141-4e8b-9628-092acc54d3b4','偈頌七首  其二','釋思岳','宋','宋诗','song-poetry','','[]','芭蕉聞雷開，耳在什麽處。',38,'全唐诗/poet.song.103000.json','["芭蕉聞雷開，耳在什麽處。", "葵花隨日轉，眼在什麽處。", "若還眼耳分明，透出千門萬戶。"]'),
('b9cfc671-a63e-4974-ae84-af5fd56af834','偈頌七首  其三','釋思岳','宋','宋诗','song-poetry','','[]','一葉飄丹，乾坤獨露。',58,'全唐诗/poet.song.103000.json','["一葉飄丹，乾坤獨露。", "萬緣泯迹，法界全彰。", "溈山水牯牛，大雄白額虎。", "河陽新婦子，臨際小廝兒。", "雖然借路經過，拶著扶籬摸壁。"]'),
('a872ff7a-21ff-40a8-9c44-dc693ac6a6cd','偈頌七首  其四','釋思岳','宋','宋诗','song-poetry','','[]','今年是閏年，剩著三十日。',48,'全唐诗/poet.song.103000.json','["今年是閏年，剩著三十日。", "返究所剩底，添些浮逼逼。", "世間沒量人，一切但省力。", "浄衆此密語，說了却不密。"]'),
('287fc716-6341-4741-9d2a-a46977fda186','偈頌七首  其五','釋思岳','宋','宋诗','song-poetry','','[]','誰道霜風只一般，今年寒勝去年寒。',32,'全唐诗/poet.song.103000.json','["誰道霜風只一般，今年寒勝去年寒。", "夜來得箇真消息，無限鲇魚上竹竿。"]'),
('eba59338-7f5a-44f4-94c1-0b02ec7e9244','偈頌七首  其六','釋思岳','宋','宋诗','song-poetry','','[]','爐已開，炭未有，衲僧暖地且相守。',32,'全唐诗/poet.song.103000.json','["爐已開，炭未有，衲僧暖地且相守。", "忽然乞得火種來，切忌燒脚又燒手。"]'),
('8788d1f0-bd13-4dc0-8021-ba783b5076bf','偈頌七首  其七','釋思岳','宋','宋诗','song-poetry','','[]','世尊不說一箇字，大藏小藏從此出。',32,'全唐诗/poet.song.103000.json','["世尊不說一箇字，大藏小藏從此出。", "達磨九年面壁來，得皮得髓分優劣。"]'),
('94555df6-b3f2-4dae-bcbc-33e73429052c','偈二首  其一','釋思岳','宋','宋诗','song-poetry','','[]','臘月初，歲云徂。',86,'全唐诗/poet.song.103000.json','["臘月初，歲云徂。", "黄河凍已合，深處有嘉魚。", "活鱍鱍，跳不脫，又不能相煦以濕相濡以沫。", "慚愧菩薩摩訶薩，春風幾時來。", "解此黄河凍，令魚化作龍，直透桃花浪。", "會即便會，癡人面前且莫說夢。"]'),
('01e5895b-23d7-4ee7-be24-457dc511bf18','偈二首  其二','釋思岳','宋','宋诗','song-poetry','','[]','二祖償宿債，萬法絕對待。',100,'全唐诗/poet.song.103000.json','["二祖償宿債，萬法絕對待。", "一心無罣礙，浮山有九带。", "十方虛空圓陀陀，無量法門百雜碎。", "若言其有，非內非外。", "若言其無，無在不在。", "知與理冥，境與神會。", "如牛拽磨，似水打碓。", "三千里外逢人東倒西㒦，十字街頭遇賤則貴。"]'),
('fd5c0d8d-183a-4993-bb02-b69211eb61d3','頌古九首  其一','釋思岳','宋','宋诗','song-poetry','','[]','無根樹子一株，山翁不費誅鋤。',28,'全唐诗/poet.song.103000.json','["無根樹子一株，山翁不費誅鋤。", "鎚碎千年桃核，不須緣木求魚。"]'),
('1342e2d5-644b-4023-83cc-81c1daf78b9d','頌古九首  其二','釋思岳','宋','宋诗','song-poetry','','[]','無陰陽地一片，明明賣貴買賤。',28,'全唐诗/poet.song.103000.json','["無陰陽地一片，明明賣貴買賤。", "死屍無處活埋，露出三頭兩面。"]'),
('8e7a7cd7-c626-4d92-94a8-6e28b15dc5e8','頌古九首  其三','釋思岳','宋','宋诗','song-poetry','','[]','不應山谷一所，透出千門萬戶。',28,'全唐诗/poet.song.103000.json','["不應山谷一所，透出千門萬戶。", "清曉一聲杜鵑，勸人不如歸去。"]'),
('50792e56-6b5f-43a4-964a-48ad18cd3d54','頌古九首  其四','釋思岳','宋','宋诗','song-poetry','','[]','時清休唱太平歌，大冶紅罏著一毛。',32,'全唐诗/poet.song.103000.json','["時清休唱太平歌，大冶紅罏著一毛。", "試向其中撮灰燼，亘天紅焰已周遭。"]'),
('2b3058c1-dff8-4e16-8756-edbd96d799ec','頌古九首  其五','釋思岳','宋','宋诗','song-poetry','','[]','明明攪動一缸屎，却把麝香燒旖旎。',32,'全唐诗/poet.song.103000.json','["明明攪動一缸屎，却把麝香燒旖旎。", "許多香氣不曾聞，渾身坐在屎缸裏。"]'),
('001f94e6-bbe5-4907-83a0-601dec7aaccb','頌古九首  其六','釋思岳','宋','宋诗','song-poetry','','[]','一句舉揚宗旨事，法堂上草亦須荒。',64,'全唐诗/poet.song.103000.json','["一句舉揚宗旨事，法堂上草亦須荒。", "回頭却說人間話，大地山河常放光。", "光未明，無有佛，三條椽下好商量。", "岑大蟲，岑大蟲，澧州水，朗州峯。"]'),
('8dfae335-38d7-4051-84a7-f537dbb4baae','頌古九首  其七','釋思岳','宋','宋诗','song-poetry','','[]','本是山中人，愛說山中話。',24,'全唐诗/poet.song.103000.json','["本是山中人，愛說山中話。", "五月賣松風，人間恐無價。"]'),
('01448bef-5eca-468f-a720-d34a9d90cef0','頌古九首  其八','釋思岳','宋','宋诗','song-poetry','','[]','天魔謗佛，桀犬吠堯。',20,'全唐诗/poet.song.103000.json','["天魔謗佛，桀犬吠堯。", "巍巍大人，聖德可昭。"]'),
('21ba3c28-377d-425d-ad60-cbd2db1f1e2f','頌古九首  其九','釋思岳','宋','宋诗','song-poetry','','[]','問佛答云乾屎橛，明明此理難分雪。',32,'全唐诗/poet.song.103000.json','["問佛答云乾屎橛，明明此理難分雪。", "金剛寶劍倒殺人，鈍鋼止用新羅鐵。"]'),
('8ceb87db-c33a-46ca-90bf-2cdd9b992191','偈','釋善直','宋','宋诗','song-poetry','','[]','諸佛不曾出世，人人鼻孔遼天。',28,'全唐诗/poet.song.103000.json','["諸佛不曾出世，人人鼻孔遼天。", "祖師不曾西來，箇箇壁立千仞。"]'),
('a40de3c9-0dc2-4012-a57b-2439282997fe','偈頌十一首  其一','釋了演','宋','宋诗','song-poetry','','[]','誰菴不會說禪，一向外邊之繞。',58,'全唐诗/poet.song.103000.json','["誰菴不會說禪，一向外邊之繞。", "鳴鼓集衆陞堂，豈容亂開臭口。", "而今無計可爲，謾把屎腸抖擻。", "瞎驢趁隊過新羅，驚起南辰藏北斗。"]'),
('e0970baa-754d-4599-a63e-f16c4b5d7824','偈頌十一首  其二','釋了演','宋','宋诗','song-poetry','','[]','撲落非他物，縱橫不是塵。',24,'全唐诗/poet.song.103000.json','["撲落非他物，縱橫不是塵。", "山河并大地，全露法王身。"]'),
('a5cd1ed9-db0f-460f-8c3d-305bf479a340','偈頌十一首  其三','釋了演','宋','宋诗','song-poetry','','[]','昨日鬧浩浩，今朝靜悄悄。',28,'全唐诗/poet.song.103000.json','["昨日鬧浩浩，今朝靜悄悄。", "靜悄悄處鬧浩浩，鬧浩浩處靜悄悄。"]'),
('2c717927-bad6-4416-b31a-74331a8cb9a1','偈頌十一首  其四','釋了演','宋','宋诗','song-poetry','','[]','高高峯頂雲，散作人間雨。',36,'全唐诗/poet.song.103000.json','["高高峯頂雲，散作人間雨。", "一句絕誵訛，相逢莫錯舉。", "不錯舉，貓兒偏解捉老鼠。"]'),
('9d275af8-9e07-4a06-b674-3382ebf1ff2f','偈頌十一首  其五','釋了演','宋','宋诗','song-poetry','','[]','今朝四月初一，即辰孟夏漸熱。',68,'全唐诗/poet.song.103000.json','["今朝四月初一，即辰孟夏漸熱。", "伏惟大衆增休，各各眼橫鼻直。", "若謂世諦流通，燋盤重添艾灸。", "若作佛法商量，瞎漢扶籬摸壁。", "還相委悉麽，只爲分明極。"]'),
('9c94d627-9fc8-4cfb-a321-aa52ce9318a1','偈頌十一首  其六','釋了演','宋','宋诗','song-poetry','','[]','前來半斤，後來八兩。',20,'全唐诗/poet.song.103000.json','["前來半斤，後來八兩。", "斤兩分明，一對漆桶。"]'),
('d66937b8-91fc-43e1-af02-b4746aa77a5d','偈頌十一首  其七','釋了演','宋','宋诗','song-poetry','','[]','時當亞歲，節屆書雲。',26,'全唐诗/poet.song.103000.json','["時當亞歲，節屆書雲。", "不萌枝上喚春歸，無影樹頭增秀色。"]'),
('e9bca356-be1e-4b20-99a6-6215c0dccc85','偈頌十一首  其八','釋了演','宋','宋诗','song-poetry','','[]','臘月一，雪凍草枯，水寒冰結。',40,'全唐诗/poet.song.103000.json','["臘月一，雪凍草枯，水寒冰結。", "黄河絕流，虛空迸裂。", "若將此語定綱宗，敢保老兄猶未徹。"]'),
('acbeaf39-ef87-4ff8-a9c2-b13653e46274','偈頌十一首  其九','釋了演','宋','宋诗','song-poetry','','[]','四海共遵靈鷲制，九旬禁足自蕭然。',74,'全唐诗/poet.song.103000.json','["四海共遵靈鷲制，九旬禁足自蕭然。", "饑餐渴飲隨緣過，禪道是非掃一邊。", "知我者謂我深錐痛劄，不知我者謂我弔影揚鞭。", "畢竟如何，月中丹桂和根拔，水底泥牛驀角牽。"]'),
('c5bfb84a-0a09-46ca-9ef6-9cf48ca4aea8','偈頌十一首  其一○','釋了演','宋','宋诗','song-poetry','','[]','即心即拂，千山萬水。',50,'全唐诗/poet.song.103000.json','["即心即拂，千山萬水。", "非心非佛，草窠裏輥。", "向上一路千聖，不傳熱椀鳴聲。", "三邊若得渾無事，四海何愁不太平。"]'),
('b1747e6c-1fa2-4cd8-9069-18bd018cbd1b','偈頌十一首  其一一','釋了演','宋','宋诗','song-poetry','','[]','踢倒飛來回首去，倒騎佛殿出皇都。',32,'全唐诗/poet.song.103000.json','["踢倒飛來回首去，倒騎佛殿出皇都。", "須知此外封疆闕，八面騰騰任卷舒。"]'),
('54d44d46-76bb-4e94-8bc9-44340bd6af9c','頌古三首  其一','釋了演','宋','宋诗','song-poetry','','[]','倒握毒蛇橫古路，背騎猛虎舞三臺。',32,'全唐诗/poet.song.103000.json','["倒握毒蛇橫古路，背騎猛虎舞三臺。", "收來放去無多子，鐵眼銅睛被活埋。"]'),
('28a728c2-c81a-4725-b690-68f22780b349','頌古三首  其二','釋了演','宋','宋诗','song-poetry','','[]','趙州狗子無佛性，當空掘出秦時鏡。',32,'全唐诗/poet.song.103000.json','["趙州狗子無佛性，當空掘出秦時鏡。", "光明渾不見星兒，上下四維俱徹映。"]'),
('a9ed1319-2031-4af9-bae3-dc5e3f3c690f','頌古三首  其三','釋了演','宋','宋诗','song-poetry','','[]','袖中寶劍摩星斗，肘後靈符照八方。',32,'全唐诗/poet.song.103000.json','["袖中寶劍摩星斗，肘後靈符照八方。", "撥轉目前關捩子，從教天下竟忙忙。"]'),
('aa11ad07-b010-485c-83f0-fe3eb5b8fdd7','衡陽別妙喜老師','釋了演','宋','宋诗','song-poetry','','[]','倒騎鐵馬渡瀟湘，澗草巖花不覆藏。',32,'全唐诗/poet.song.103000.json','["倒騎鐵馬渡瀟湘，澗草巖花不覆藏。", "回雁峯高親到頂，了無佛法可商量。"]'),
('68651a61-9482-48b1-9487-cc617d2f88d3','寄育王廓和尚','釋了演','宋','宋诗','song-poetry','','[]','向來事業俱荒廢，即體生涯迥一空。',32,'全唐诗/poet.song.103000.json','["向來事業俱荒廢，即體生涯迥一空。", "漸愧此身無被蓋，百般癡鈍玷宗風。"]'),
('ae9e17ba-a667-4369-80fd-5c99cc1df74b','石佛','釋了演','宋','宋诗','song-poetry','','[]','積念有年瞻石佛，今朝一見絕疑猜。',32,'全唐诗/poet.song.103000.json','["積念有年瞻石佛，今朝一見絕疑猜。", "都盧面目只如此，却道三生鑿出來。"]'),
('6a50ab5a-c54a-486d-9343-52c5e6a39679','空谷','釋了演','宋','宋诗','song-poetry','','[]','谷空空谷谷空空，空谷全超萬象中。',32,'全唐诗/poet.song.103000.json','["谷空空谷谷空空，空谷全超萬象中。", "流水落花渾不見，清風明月却相容。"]'),
('18b1554d-e4d0-415a-86df-502ae28c81cf','與禪人','釋了演','宋','宋诗','song-poetry','','[]','家山有路應須到，到得家山未是歸。',32,'全唐诗/poet.song.103000.json','["家山有路應須到，到得家山未是歸。", "拈轉杖頭俱劃斷，好看午夜太陽輝。"]'),
('48f9c51e-714e-4a91-923a-a4b2da60cad3','頌古九首  其一','釋了演','宋','宋诗','song-poetry','','[]','二祖無端向少林，庭前立雪到腰深。',32,'全唐诗/poet.song.103000.json','["二祖無端向少林，庭前立雪到腰深。", "直饒覓得心無有，未免全身被陸沉。"]'),
('83281811-b88f-4add-ab4d-7e11805db594','頌古九首  其二','釋了演','宋','宋诗','song-poetry','','[]','不是心，不是佛，不是物，爲君擊碎精靈窟。',36,'全唐诗/poet.song.103000.json','["不是心，不是佛，不是物，爲君擊碎精靈窟。", "天上人間知不知，鼻孔依前空突兀。"]'),
('6a30a1d1-c7bb-44bb-86a8-9807fbc7d5e1','頌古九首  其三','釋了演','宋','宋诗','song-poetry','','[]','忽聞幕下哭哀哀，頓使天台對五臺。',32,'全唐诗/poet.song.103000.json','["忽聞幕下哭哀哀，頓使天台對五臺。", "風月一天今古在，通身是口也難開。"]'),
('d91f9fbe-658b-48da-b107-185fb0c397eb','頌古九首  其四','釋了演','宋','宋诗','song-poetry','','[]','溈山得體，仰山得用。',20,'全唐诗/poet.song.103000.json','["溈山得體，仰山得用。", "體用俱全，夢中說夢。"]'),
('ee162129-cb12-4e3f-82c6-591d25233ef6','頌古九首  其五','釋了演','宋','宋诗','song-poetry','','[]','黄蘗堂前喫棒去，大愚肋下築拳來。',32,'全唐诗/poet.song.103000.json','["黄蘗堂前喫棒去，大愚肋下築拳來。", "若言佛法無多子，到底分明眼未開。"]'),
('8ca7deab-6fe1-40b1-b9c2-0ae4683f8cfe','頌古九首  其六','釋了演','宋','宋诗','song-poetry','','[]','臨行特地揚家醜，带累傍人滿面慚。',32,'全唐诗/poet.song.103000.json','["臨行特地揚家醜，带累傍人滿面慚。", "霹靂一聲雲雨散，至今父子未相諳。"]'),
('a6d73f56-e997-45bd-887c-b4c255cf7978','頌古九首  其七','釋了演','宋','宋诗','song-poetry','','[]','靈雲親說悟桃花，端的無疑眼裏沙。',32,'全唐诗/poet.song.103000.json','["靈雲親說悟桃花，端的無疑眼裏沙。", "縱使玄沙言未徹，相逢且喫趙州茶。"]'),
('3b388be1-0971-4462-a133-3baa2f84c654','頌古九首  其八','釋了演','宋','宋诗','song-poetry','','[]','俱胝一指禪，古今成話欛。',24,'全唐诗/poet.song.103000.json','["俱胝一指禪，古今成話欛。", "打破鬼門關，露柱尋無罅。"]'),
('7daf72ec-d619-48c9-8069-29fab69e35e0','頌古九首  其九','釋了演','宋','宋诗','song-poetry','','[]','興化棒頭轟霹靂，克賓脚下走塵煙。',32,'全唐诗/poet.song.103000.json','["興化棒頭轟霹靂，克賓脚下走塵煙。", "若無塞外將軍令，那得嘉名四海傳。"]'),
('e9628bde-7330-44da-87f0-569ea16ffba9','偈','釋景暈','宋','宋诗','song-poetry','','[]','雲門一曲臘月二十五，瑞雪飄空積滿江山塢。',54,'全唐诗/poet.song.103000.json','["雲門一曲臘月二十五，瑞雪飄空積滿江山塢。", "峻嶺寒梅花正吐。", "手把須彌槌，笑打虛空鼓。", "驚起憍梵鉢提，冷汗透身如雨。"]'),
('7ebde71c-8a03-4f33-8c12-40744b503773','偈','釋宗演','宋','宋诗','song-poetry','','[]','猴王久受幽沉苦，法力冥資得上天。',32,'全唐诗/poet.song.103000.json','["猴王久受幽沉苦，法力冥資得上天。", "須信自心元是佛，靈光洞耀沒中邊。"]'),
('3fe14a3d-af7e-46ff-a38d-f078c3162010','偈頌三十二首  其一','釋宗演','宋','宋诗','song-poetry','','[]','今朝三月初十，大野和風襲襲。',28,'全唐诗/poet.song.103000.json','["今朝三月初十，大野和風襲襲。", "不用轉腦回頭，向此一時證入。"]'),
('d27f9052-34d7-49ae-a596-e41b8670e27b','偈頌三十二首  其二','釋宗演','宋','宋诗','song-poetry','','[]','空病有爲藥，有病空爲藥。',36,'全唐诗/poet.song.103000.json','["空病有爲藥，有病空爲藥。", "空有兩俱非，藥病何處著。", "無處著，萬里秋風飛一鶚。"]'),
('bbb023d1-a380-4ea8-80be-88eb2f19e2a6','偈頌三十二首  其三','釋宗演','宋','宋诗','song-poetry','','[]','九旬禁足精修，今朝休夏自恣。',72,'全唐诗/poet.song.103000.json','["九旬禁足精修，今朝休夏自恣。", "山僧不敢自瞞，於中罪過有五。", "一不合說大脫空，二不合拋沙撒土。", "三不合將龍眼核換人眼睛，四不合毀佛謗祖。", "五咄，洎合錯舉。"]'),
('7158a01c-f6e1-4ee8-bed9-d6c8348655e0','偈頌三十二首  其四','釋宗演','宋','宋诗','song-poetry','','[]','入聖超凡既有聲，卧龍誰顧碧潭清。',32,'全唐诗/poet.song.103000.json','["入聖超凡既有聲，卧龍誰顧碧潭清。", "快須鼓浪興雲雨，莫負從前濟物心。"]'),
('75e278dd-68f4-4e6b-9a61-8b13334d090f','偈頌三十二首  其五','釋宗演','宋','宋诗','song-poetry','','["\u592a\u6e56"]','今朝臘月初一，次第年窮歲畢。',60,'全唐诗/poet.song.103000.json','["今朝臘月初一，次第年窮歲畢。", "從教萬物凋零，這箇元無變易。", "諸禪老，知不知。", "孤迥迥，峭巍巍。", "拈來拋擲太湖裏，下載清風付與誰。"]'),
('8572a025-42a5-4c1c-81c9-1bf8785f3e32','偈頌三十二首  其六','釋宗演','宋','宋诗','song-poetry','','[]','大川欲濟須舟檝，大厦謀成必巨材。',32,'全唐诗/poet.song.103000.json','["大川欲濟須舟檝，大厦謀成必巨材。", "又是一年能事畢，山僧贏得笑咍咍。"]'),
('5fcdb81d-03a4-469e-abae-8bc126e531aa','偈頌三十二首  其七','釋宗演','宋','宋诗','song-poetry','','[]','人間鑠石流金，世外風高月冷。',44,'全唐诗/poet.song.103000.json','["人間鑠石流金，世外風高月冷。", "要知二無兩般，須是一回自肯。", "鑊湯爐炭橫身入，劍樹刀山信脚行。"]'),
('1f0c704f-030d-4eb2-bba3-6db9646270ad','偈頌三十二首  其八','釋宗演','宋','宋诗','song-poetry','','[]','一日一日復一日，次第年窮歲暮來。',48,'全唐诗/poet.song.103000.json','["一日一日復一日，次第年窮歲暮來。", "莫道東君無面目，梅花依舊雪中開。", "見便見，絕疑猜，燈籠沿壁上天台。"]'),
('0a8d4a03-d195-4df5-a0f3-13945571abc4','偈頌三十二首  其九','釋宗演','宋','宋诗','song-poetry','','[]','凡聖體真，猶存見隔。',20,'全唐诗/poet.song.103000.json','["凡聖體真，猶存見隔。", "見存即凡，情亡即佛。"]'),
('a9da4068-995a-4c53-8571-7c90c4616d6a','偈頌三十二首  其一○','釋宗演','宋','宋诗','song-poetry','','[]','今朝季冬朔旦，歲月不可把玩。',52,'全唐诗/poet.song.103000.json','["今朝季冬朔旦，歲月不可把玩。", "各請打辦精神，了却未了公案。", "有我即病生，無我即病滅。", "我病兩俱非，萬里一條鐵。"]'),
('8146ee66-c05c-45ec-a186-3c10f5405200','偈頌三十二首  其一一','釋宗演','宋','宋诗','song-poetry','','[]','雲門一曲子，臘月二十五。',24,'全唐诗/poet.song.103000.json','["雲門一曲子，臘月二十五。", "唱高和得齊，大棒揸出去。"]'),
('13aead2b-d407-4968-9916-8b4c217c2b61','偈頌三十二首  其一二','釋宗演','宋','宋诗','song-poetry','','[]','善財童子採來親，大智文殊用得靈。',32,'全唐诗/poet.song.103000.json','["善財童子採來親，大智文殊用得靈。", "今日青山端午節，不勞拈出再施呈。"]'),
('9881d4eb-8463-479e-a541-b8ad79a4440f','偈頌三十二首  其一三','釋宗演','宋','宋诗','song-poetry','','[]','今朝臘月十有五，摩那擊動三通鼓。',72,'全唐诗/poet.song.103000.json','["今朝臘月十有五，摩那擊動三通鼓。", "諸人不是不將來，山僧不是不分付。", "麻三斤，柏樹子。", "德山歌，道吾舞。", "此道今人棄如土。", "阿呵呵，較些子，發機須是千鈞弩。"]'),
('0922aa2b-1632-49db-85c5-cffe6535559e','偈頌三十二首  其一四','釋宗演','宋','宋诗','song-poetry','','[]','有一語，沒人知。',28,'全唐诗/poet.song.103000.json','["有一語，沒人知。", "最親切，又希奇。", "曉來和露看，只欠一聲啼。"]'),
('507bc748-ba15-4087-aeb8-75689f9086bc','偈頌三十二首  其一五','釋宗演','宋','宋诗','song-poetry','','[]','無邊不動虛空體，不拒陰陽去復來。',32,'全唐诗/poet.song.103000.json','["無邊不動虛空體，不拒陰陽去復來。", "誰道一雙窮相手，未嘗容易舞三臺。"]'),
('adcf63a2-e673-46cb-b6e2-6a763efbfea5','偈頌三十二首  其一六','釋宗演','宋','宋诗','song-poetry','','[]','張侯白，李侯黑。',32,'全唐诗/poet.song.103000.json','["張侯白，李侯黑。", "硬如綿，軟如鐵。", "驀路相逢兩會家，臨濟未是白拈賊。"]'),
('b9982173-feb5-48a7-b6b1-c6b4c73e2795','偈頌三十二首  其一七','釋宗演','宋','宋诗','song-poetry','','[]','一九與二九，相逢不出手。',64,'全唐诗/poet.song.103000.json','["一九與二九，相逢不出手。", "面面各相看，人人自知有。", "你若野犴鳴，我便獅子吼。", "我若野犴鳴，你亦獅子吼。", "十字縱橫自在行，切忌隨人背後走。"]'),
('6d6e9261-ac4d-4468-8603-1989ad4f4754','偈頌三十二首  其一八','釋宗演','宋','宋诗','song-poetry','','[]','摩尼珠，人不識，如來藏裏親收得。',58,'全唐诗/poet.song.103000.json','["摩尼珠，人不識，如來藏裏親收得。", "收者易，見者難。", "見者易，用則難。", "見得用得，二無兩般。", "閒把一枝歸去笛，夜深吹過汨羅灣。"]'),
('4de947da-067f-4da2-b730-7f74e72d4fc6','偈頌三十二首  其一九','釋宗演','宋','宋诗','song-poetry','','["\u592a\u6e56"]','今朝四月一，春去無蹤跡。',75,'全唐诗/poet.song.103000.json','["今朝四月一，春去無蹤跡。", "衲僧拄杖子，依舊光黑漆。", "看看，旋嵐偃嶽而常靜，江河競注而不流。", "野馬飄鼓而不動，日月歷天而不周。", "盡情拋擲太湖裏，下載清風孰與儔。"]'),
('e140d5da-041c-4086-af8c-24dcb3a9124c','偈頌三十二首  其二○','釋宗演','宋','宋诗','song-poetry','','[]','觀音大士弘悲願，千臂莊嚴千眼明。',32,'全唐诗/poet.song.103000.json','["觀音大士弘悲願，千臂莊嚴千眼明。", "定慧慈威咸具足，山僧贏得不惺惺。"]'),
('2e670599-c84a-4516-8490-cf289397694b','偈頌三十二首  其二一','釋宗演','宋','宋诗','song-poetry','','[]','今朝十月十五，有誤諸人來此。',52,'全唐诗/poet.song.103000.json','["今朝十月十五，有誤諸人來此。", "山僧口似匾擔，說禪煩拄杖子。", "一擊忘所知，更不假修持。", "黑蛇當大路，獅子逞全威。"]'),
('c18ba51a-3d72-4bf4-b8cc-7ef4580cc8b9','偈頌三十二首  其二二','釋宗演','宋','宋诗','song-poetry','','[]','有句無句，如藤倚樹。',36,'全唐诗/poet.song.103000.json','["有句無句，如藤倚樹。", "打破油甕，討甚老鼠。", "楖栗橫擔不顧人，直入千峰萬峰去。"]'),
('56609e6f-d871-44e0-a156-bcea3516e037','偈頌三十二首  其二三','釋宗演','宋','宋诗','song-poetry','','[]','無邊剎境，自他不隔毫端。',24,'全唐诗/poet.song.103000.json','["無邊剎境，自他不隔毫端。", "十世古今，始終不離當念。"]'),
('cdf85251-ede3-40a3-8600-a8c92c2e48ff','偈頌三十二首  其二四','釋宗演','宋','宋诗','song-poetry','','[]','今朝已是三月半，到處桃花開爛熳。',32,'全唐诗/poet.song.103000.json','["今朝已是三月半，到處桃花開爛熳。", "多少遊人眼不開，靈雲一見疑情斷。"]'),
('0b9a3926-e566-4993-b873-8add00606d23','辭亦菴相招','釋宗演','宋','宋诗','song-poetry','','[]','南北東西總亦菴，塵毛剎海悉包含。',32,'全唐诗/poet.song.103000.json','["南北東西總亦菴，塵毛剎海悉包含。", "山僧已住其中矣，更欲招邀即不堪。"]'),
('bba03871-3295-4931-8a49-86d7c38be027','行者化苔脯','釋宗演','宋','宋诗','song-poetry','','[]','琉璃田地無根草，信手拈來屬老盧。',32,'全唐诗/poet.song.103000.json','["琉璃田地無根草，信手拈來屬老盧。", "不似時人開著眼，再三撈摝費工夫。"]'),
('b2d24532-9378-4c3e-a5b6-e53529325da8','與雁山車嶺建接待僧','釋宗演','宋','宋诗','song-poetry','','[]','雁山孤頂絕攀躋，當念遊人困路歧。',32,'全唐诗/poet.song.103000.json','["雁山孤頂絕攀躋，當念遊人困路歧。", "暫與化城休歇地，莫教忘却轉身時。"]'),
('6c2cba5c-aa6e-483f-9bea-65fef59b647e','送定維那','釋宗演','宋','宋诗','song-poetry','','[]','興化當年爲克賓，棒頭敲出玉麒麟。',32,'全唐诗/poet.song.103000.json','["興化當年爲克賓，棒頭敲出玉麒麟。", "遯菴放過定禪者，只要渠儂眼自明。"]'),
('ea383a8b-34f1-4ffe-9d2d-9e04d26ea92b','題石勒王見佛圖澄畫像','釋宗演','宋','宋诗','song-poetry','','[]','立地成佛殺人漢，握節當胸更問誰。',32,'全唐诗/poet.song.103000.json','["立地成佛殺人漢，握節當胸更問誰。", "莫怪阿師佯瞌睡，要渠回首自知非。"]'),
('2b0a56a6-b928-46bc-abc7-acecb37fd959','與正弼侍者','釋宗演','宋','宋诗','song-poetry','','[]','三應三呼亘古今，遯菴無此老婆心。',32,'全唐诗/poet.song.103000.json','["三應三呼亘古今，遯菴無此老婆心。", "痛拳熱喝出門去，一聽渠儂怨恨深。"]'),
('735871ac-a141-45e0-ab34-bef90c7262ea','送元功居土歸溫陵','釋宗演','宋','宋诗','song-poetry','','[]','湖山相見笑顔開，知道仁從佛國來。',32,'全唐诗/poet.song.103000.json','["湖山相見笑顔開，知道仁從佛國來。", "敗闕盡情都納了，莫言無物送君回。"]'),
('f9b1a2eb-1f78-4f50-8efd-fe778ac03a89','示法震頭陀','釋宗演','宋','宋诗','song-poetry','','[]','頭陀事衆已多年，華藏無衣可得傳。',32,'全唐诗/poet.song.103000.json','["頭陀事衆已多年，華藏無衣可得傳。", "劈面三拳仁義絕，陳州人出許州門。"]'),
('fe9cbfff-ad54-4efd-acf1-5171ab25c670','偈','釋宗演','宋','宋诗','song-poetry','','[]','一九與二九，相逢不出手。',24,'全唐诗/poet.song.103000.json','["一九與二九，相逢不出手。", "世間出世間，無剩亦無少。"]'),
('3459e8a5-9b90-4779-9401-bf107b2d6930','頌古十七首  其一','釋宗演','宋','宋诗','song-poetry','','[]','從前七佛儀式，慶喜何曾欠少。',28,'全唐诗/poet.song.103000.json','["從前七佛儀式，慶喜何曾欠少。", "堪笑黄面瞿曇，無端打箇之繞。"]'),
('08181f89-959f-44c8-a614-8182e4b84471','頌古十七首  其二','釋宗演','宋','宋诗','song-poetry','','[]','色空明暗本無因，見見由來亦誤人。',32,'全唐诗/poet.song.103000.json','["色空明暗本無因，見見由來亦誤人。", "見不及時猶未瞥，那知殃祟是家親。"]'),
('d41e224f-0fda-41bb-b9b2-9938f2121324','頌古十七首  其三','釋宗演','宋','宋诗','song-poetry','','[]','相見錦江頭，相携上酒樓。',24,'全唐诗/poet.song.103000.json','["相見錦江頭，相携上酒樓。", "月闌歌笑罷，回首上扁舟。"]'),
('6ef54cb8-28f7-43b2-942f-530bb4726af2','頌古十七首  其四','釋宗演','宋','宋诗','song-poetry','','[]','紅輪决定沉西去，未委魂靈往那方。',44,'全唐诗/poet.song.103000.json','["紅輪决定沉西去，未委魂靈往那方。", "孝子盡情宣說了，槃山無處可遮藏。", "藏不得，堪與人天爲軌則。"]'),
('1a57dacc-264a-40f8-a9b9-6b02ce84c30a','頌古十七首  其五','釋宗演','宋','宋诗','song-poetry','','[]','一按牛喫草，一與賊過梯。',24,'全唐诗/poet.song.103000.json','["一按牛喫草，一與賊過梯。", "早知燈是火，飯熱也多時。"]'),
('7883800e-f41d-4a9f-b843-a31fd8b3e434','頌古十七首  其六','釋宗演','宋','宋诗','song-poetry','','[]','棒下承當早自欺，聽人饒舌固非宜。',32,'全唐诗/poet.song.103000.json','["棒下承當早自欺，聽人饒舌固非宜。", "縱知佛法無多子，爭似當時未問時。"]'),
('c5bfae1b-2f0b-4ab3-beae-04ea3db6c2bd','頌古十七首  其七','釋宗演','宋','宋诗','song-poetry','','[]','潭不見，龍不現，親到龍潭須活薦。',48,'全唐诗/poet.song.103000.json','["潭不見，龍不現，親到龍潭須活薦。", "莫學承虛接響人，守株待兔亡機變。", "知機變，盞子撲落地，楪子成七片。"]'),
('728a4643-79ed-401e-baa4-5c50b70dda5a','頌古十七首  其八','釋宗演','宋','宋诗','song-poetry','','[]','動絃別曲，落葉知秋。',36,'全唐诗/poet.song.103000.json','["動絃別曲，落葉知秋。", "人平不語，水平不流。", "只因脚底無羈絆，去住縱橫得自由。"]'),
('e08f3bff-84ca-417b-906e-89f690b7cd74','頌古十七首  其九','釋宗演','宋','宋诗','song-poetry','','[]','動絃別曲，葉落知秋。',36,'全唐诗/poet.song.103000.json','["動絃別曲，葉落知秋。", "不肯子放，只肯子收。", "來年更有新條在，惱亂春風卒未休。"]'),
('8a489047-d5da-4e1d-a4c9-a7b58fcb933b','頌古十七首  其一○','釋宗演','宋','宋诗','song-poetry','','[]','未離閩底已還家，纔跨飛鳶又眼花。',32,'全唐诗/poet.song.103000.json','["未離閩底已還家，纔跨飛鳶又眼花。", "堪笑曾郎更心毒，烏藤輕放老玄沙。"]'),
('72fccb61-189a-4f12-8659-7eacbd83c392','頌古十七首  其一一','釋宗演','宋','宋诗','song-poetry','','[]','祖父田園俱屬我，中間樹子豈由他。',32,'全唐诗/poet.song.103000.json','["祖父田園俱屬我，中間樹子豈由他。", "連枝带葉和根拔，要見兒孫意氣豪。"]'),
('6fe4ca76-3040-4d26-8ba3-0e57793c60bd','頌古十七首  其一二','釋宗演','宋','宋诗','song-poetry','','[]','黑漆竹箆非觸背，大地山河俱粉碎。',32,'全唐诗/poet.song.103000.json','["黑漆竹箆非觸背，大地山河俱粉碎。", "咬人師子急反身，莫學韓獹猶逐塊。"]'),
('66e67da7-8cc0-43b5-9f74-d2b759d06e7d','頌古十七首  其一三','釋宗演','宋','宋诗','song-poetry','','[]','黄龍一唾絕遲疑，笑殺傍觀又可悲。',32,'全唐诗/poet.song.103000.json','["黄龍一唾絕遲疑，笑殺傍觀又可悲。", "姹女已歸霄漢去，獃郎猶向火邊棲。"]'),
('870981e1-4143-4cfa-a3a3-734b82e03843','頌古十七首  其一四','釋宗演','宋','宋诗','song-poetry','','[]','白雲舉古，直是希奇。',36,'全唐诗/poet.song.103000.json','["白雲舉古，直是希奇。", "口堪喫飯，少有人知。", "諸禪老，莫遲疑，一飽自然忘百饑。"]'),
('40f430b7-7d76-4e67-98e6-9fd8e24c03c7','頌古十七首  其一五','釋宗演','宋','宋诗','song-poetry','','[]','山前田地賣還買，松竹清風痛自憐。',32,'全唐诗/poet.song.103000.json','["山前田地賣還買，松竹清風痛自憐。", "堪笑夢中誇富貴，覺來那直半分錢。"]'),
('e68e20fe-e9c0-4e60-82fc-ac1182cb446d','頌古十七首  其一六','釋宗演','宋','宋诗','song-poetry','','[]','大藏教文爲切脚，鉢囉娘義最深幽。',32,'全唐诗/poet.song.103000.json','["大藏教文爲切脚，鉢囉娘義最深幽。", "孔門弟子無人識，碧眼胡僧暗點頭。"]'),
('fd6f5201-b020-4fe0-bc1e-fa4d213ebc6b','頌古十七首  其一七','釋宗演','宋','宋诗','song-poetry','','[]','年窮王老夜燒錢，斷送難逢下水船。',32,'全唐诗/poet.song.103000.json','["年窮王老夜燒錢，斷送難逢下水船。", "懵底不知身到岸，隨他寒暑謾推遷。"]'),
('d0561e8a-0d74-453e-9cb1-8639abc65e88','偈二首  其一','釋道印','宋','宋诗','song-poetry','','[]','大雄山下虎，南山鼈鼻蛇。',36,'全唐诗/poet.song.103000.json','["大雄山下虎，南山鼈鼻蛇。", "等閑撞著，抱賞歸家。", "若也不惜好手，便與拔出重牙。"]'),
('ccaa6c11-aec3-4e73-b9fc-a11487a8753d','偈二首  其二','釋道印','宋','宋诗','song-poetry','','[]','五五二十五，擊碎虛空鼓。',40,'全唐诗/poet.song.103000.json','["五五二十五，擊碎虛空鼓。", "大地不容針，十方無寸土。", "春生夏長復何云，甜者甜兮苦者苦。"]'),
('e6f19ddc-61a5-46e5-bd79-c70dbe474f24','頌古八首  其一','釋道印','宋','宋诗','song-poetry','','[]','霹靂未收聲，閃電不留影。',40,'全唐诗/poet.song.103000.json','["霹靂未收聲，閃電不留影。", "三更月到窗，半夜驢覷井。", "快騎駿馬驟高樓，一塵不動須彌頂。"]'),
('dd29861d-538a-4bfc-97e4-93b9736de44f','頌古八首  其二','釋道印','宋','宋诗','song-poetry','','[]','有伴即來，地闢天開。',38,'全唐诗/poet.song.103000.json','["有伴即來，地闢天開。", "冷光重出匣，古路絕纖埃。", "萬象森羅齊合掌，須彌岌崿舞三臺。"]'),
('f74c4d4a-f3b0-4d06-bc4e-55fa00d3487f','頌古八首  其三','釋道印','宋','宋诗','song-poetry','','[]','握不成團撥不開，德雲幾度下崔嵬。',32,'全唐诗/poet.song.103000.json','["握不成團撥不開，德雲幾度下崔嵬。", "有時行到海南岸，密密還從舊路回。"]'),
('2ad9b357-5c46-4c5d-b9fb-c82d07f1ae0c','頌古八首  其四','釋道印','宋','宋诗','song-poetry','','[]','推倒扶起，覿面千里。',61,'全唐诗/poet.song.103000.json','["推倒扶起，覿面千里。", "唯小釋迦，風前按指。", "直饒海印發光，也是雪峯道底。", "遍界是文殊，遍界是慈氏。", "樓閣門開竟日閑，誰識善財童子。"]'),
('17a1cfae-f969-4da2-ab29-4692136227bc','頌古八首  其五','釋道印','宋','宋诗','song-poetry','','[]','接得與識得，誰復較錙銖。',39,'全唐诗/poet.song.103000.json','["接得與識得，誰復較錙銖。", "若問堂中事，堂中事轉疏。", "只如雲蓋悟去，又作麽蘇嚕蘇嚕。"]'),
('c4d8c0ff-49f4-469f-9c7a-3ec9c6499b97','頌古八首  其六','釋道印','宋','宋诗','song-poetry','','[]','大鵬摶風，蒼龍出海。',36,'全唐诗/poet.song.103000.json','["大鵬摶風，蒼龍出海。", "手擡手搦，日上月下。", "霜雪嚴凝識歲寒，雙陸盆邊須喝采。"]'),
('1e9efdf9-6046-4ee2-baa5-bfa9c80feacc','頌古八首  其七','釋道印','宋','宋诗','song-poetry','','[]','何必不必，方圓曲直。',48,'全唐诗/poet.song.103000.json','["何必不必，方圓曲直。", "眉目分明，若爲辨的。", "影草既隨身，覿面當機疾。", "一雙孤雁忽高飛，兩隻鴛鴦還獨立。"]'),
('98fa9d9f-b34f-42e1-870c-f25cb4a8ae38','頌古八首  其八','釋道印','宋','宋诗','song-poetry','','[]','踏破草鞋赤脚走，堂堂向外揚家醜。',32,'全唐诗/poet.song.103000.json','["踏破草鞋赤脚走，堂堂向外揚家醜。", "只知歛袂出人前，不覺衣穿露兩肘。"]'),
('36e5c2a7-fb11-4c92-ae33-c35b75f65efc','浴佛','釋悟本','宋','宋诗','song-poetry','','[]','今日當年佛降生，當年今日不多爭。',32,'全唐诗/poet.song.103000.json','["今日當年佛降生，當年今日不多爭。", "若言八十還歸滅，有眼分明特地盲。"]'),
('19232bae-74b0-4366-b1bc-ac9ebf07ac6f','遣僧通嗣書','釋悟本','宋','宋诗','song-poetry','','[]','射殺南山老大蟲，行人從此路頭通。',32,'全唐诗/poet.song.103000.json','["射殺南山老大蟲，行人從此路頭通。", "年來獵犬渾無用，卧對千峰與萬峰。"]'),
('84a1827a-4948-42c5-8ee7-ebb64d2ae1a4','偈','釋悟本','宋','宋诗','song-poetry','','[]','乾闥婆王曾奏樂，山河大地皆作舞。',32,'全唐诗/poet.song.103000.json','["乾闥婆王曾奏樂，山河大地皆作舞。", "爭如跛脚老雲門，解道臘月二十五。"]'),
('319599bd-0b62-4059-93a9-c5fa50885886','偈','釋了性','宋','宋诗','song-poetry','','[]','一葦江頭楊柳春，波心不見昔時人。',32,'全唐诗/poet.song.103000.json','["一葦江頭楊柳春，波心不見昔時人。", "雪庭要識安心士，鼻孔依前搭上唇。"]'),
('ab8980c0-36d8-449b-b48f-cc2cb4223eef','偈','釋智遠','宋','宋诗','song-poetry','','[]','從來打鼓弄琵琶，須是相逢兩會家。',32,'全唐诗/poet.song.103000.json','["從來打鼓弄琵琶，須是相逢兩會家。", "佩玉鳴鸞歌舞罷，門前依舊夕陽斜。"]'),
('c030a549-12c1-46fd-a821-bb82c7f936ad','偈','釋如本','宋','宋诗','song-poetry','','[]','久雨不晴，戊在丙丁。',40,'全唐诗/poet.song.103000.json','["久雨不晴，戊在丙丁。", "通身泥水，露出眼睛。", "且道是什麽眼睛，林間泥滑滑，時叫兩三聲。"]'),
('62b7c8c9-03e5-4992-80d8-079b50ad3840','偈','釋如本','宋','宋诗','song-poetry','','[]','李四有錢不解飲，張三解飲又無錢。',32,'全唐诗/poet.song.103000.json','["李四有錢不解飲，張三解飲又無錢。", "相招豐樂樓中看，不怕寒威雪滿天。"]'),
('4ad04e5a-9ea8-49c9-955b-00ba150766ab','頌古三十一首  其一','釋如本','宋','宋诗','song-poetry','','[]','纔出胞胎便逸羣，周行七步獨稱尊。',32,'全唐诗/poet.song.103000.json','["纔出胞胎便逸羣，周行七步獨稱尊。", "當時若見雲門老，不到如今累子孫。"]'),
('6e2954c6-565d-4d64-a7a5-002d2a1966d5','頌古三十一首  其二','釋如本','宋','宋诗','song-poetry','','[]','殃崫雄雄方勇銳，瞿曇住住息風波。',32,'全唐诗/poet.song.103000.json','["殃崫雄雄方勇銳，瞿曇住住息風波。", "殺人作佛當頭劄，覆雨翻雲在剎那。"]'),
