('9af8db85-23a1-41fc-9942-e8c14844f8df','句','廉布','宋','宋诗','song-poetry','','[]','獨倚寒巖生意絕，任他桃李自成蹊。',16,'全唐诗/poet.song.103000.json','["獨倚寒巖生意絕，任他桃李自成蹊。"]'),
('bc052cf3-c5da-4ed6-a330-5928be12f5ba','悟性寺','潘正夫','宋','宋诗','song-poetry','','[]','亂山深處出樓臺，秋入群松萬壑哀。',32,'全唐诗/poet.song.103000.json','["亂山深處出樓臺，秋入群松萬壑哀。", "嵐翠逼人清似霧，灘聲落石響如雷。"]'),
('8abbdec3-39a3-4041-b2ef-332aa6ec2554','題惠山','潘正夫','宋','宋诗','song-poetry','','[]','秋風蕭瑟浄巖扃，寂寂澄泉可鑒形。',64,'全唐诗/poet.song.103000.json','["秋風蕭瑟浄巖扃，寂寂澄泉可鑒形。", "比色未饒先玉乳，試甘應合跨中泠。", "夢迴春草花猶落，雪灑松窗酒乍醒。", "須碾月團三百片，不辭來此汲泓渟。"]'),
('f8a155d4-25dd-477e-9236-2636458cb7c3','澹巖六韻奉呈遜叔侍郎兼寄惠照禪老','潘正夫','宋','宋诗','song-poetry','','[]','祝融之南近湘濱，地出天開戡翠珉。',96,'全唐诗/poet.song.103000.json','["祝融之南近湘濱，地出天開戡翠珉。", "金闕不關塵世路，丹葩爭發洞宮春。", "遲留杖履尋真慣，悵望煙蘿入夢頻。", "弈罷空懷爛柯客，雲深多失避秦人。", "高懸石棧仙風迥，靜對巖扉濯色新。", "借問時翁與禪伯，如何導往許爲鄰。"]'),
('8fad0963-ae16-4bee-87bc-1a77b7902e8d','句','潘正夫','宋','宋诗','song-poetry','','[]','嶺開越嶠通交趾，路轉荆門入九疑。',16,'全唐诗/poet.song.103000.json','["嶺開越嶠通交趾，路轉荆門入九疑。"]'),
('bb74cde7-f282-4f8e-a162-d3432d5c08e6','存目','沈昭遠','宋','宋诗','song-poetry','','[]','詩題：無訟堂詩有序首句：欲爲袁人雪謗聲。',20,'全唐诗/poet.song.103000.json','["詩題：無訟堂詩有序首句：欲爲袁人雪謗聲。"]'),
('9691b362-aaa9-4d72-87dd-b3227ac74b44','南峰庵','趙不群','宋','宋诗','song-poetry','','[]','庵枕青溪四面山，爐烟未斷日初殘。',32,'全唐诗/poet.song.103000.json','["庵枕青溪四面山，爐烟未斷日初殘。", "高僧丈室修然靜，案上楞嚴久不看。"]'),
('2be6557c-4207-472a-9f3d-c20745694d96','乘暇率僚友訪澹山祇閱御書清談久之偶成以豁其思','黄同','宋','宋诗','song-poetry','','[]','棠陰蕭爽訟詞稀，乘暇齋莊一陟危。',64,'全唐诗/poet.song.103000.json','["棠陰蕭爽訟詞稀，乘暇齋莊一陟危。", "雲漢昭回神聖畫，珠璣晃燿古今詩。", "清談習習風聲起，薄噀霏霏雨脚垂。", "它日玉堂誇勝踐，畫圖應展淡山奇。"]'),
('87ddb0e1-b57a-4505-9423-09cca9bf0f28','壬寅七月二十二日予因過東□少休壽聖時秋陽炎亢大□可憂遂題是絕以謁靈巖如有其靈一霈膏澤以惠斯民','曹省','宋','宋诗','song-poetry','','[]','英靈何事卧雲深，一舉曾空萬里陰。',32,'全唐诗/poet.song.103000.json','["英靈何事卧雲深，一舉曾空萬里陰。", "阡陌相望苗就槁，蒼生應待作商霖。"]'),
('207c3449-6987-48bf-886a-69d10eec8334','靈巖','呂源','宋','宋诗','song-poetry','','[]','憶別老君洞，今逾二十年。',48,'全唐诗/poet.song.103000.json','["憶別老君洞，今逾二十年。", "重來持漢節，又復冒蠻烟。", "風物總仍舊，霜髯徒自憐。", "不如歸去好，趣辦五湖船。"]'),
('b6061863-6d20-4029-8c7e-4b88465c634e','和張洵蒙亭詩韻','呂源','宋','宋诗','song-poetry','','[]','九溪漓水接瀟湘，萬壑千岩羅水旁。',144,'全唐诗/poet.song.103000.json','["九溪漓水接瀟湘，萬壑千岩羅水旁。", "七星高聳生輝光，連天一色皆蒼蒼。", "倚江景物似錢塘，況有萬戶新醅香。", "古洞相對舉清觴，文淵遺迹徒悲凉。", "安得石枕與藤床，夢想昔人風味長。", "滿車薏苡勝琳琅，流傳千載事微芒。", "男兒生即志四方，將軍異代猶封王。", "感時撫事心茫茫，顧我豈有籌策良。", "報國志願不敢忘，此身未暇歸江鄉。"]'),
('ddb1a828-cd9a-41a9-bb24-07e1aceaa2ba','過武侯廟','陳古','宋','宋诗','song-poetry','','[]','群雄角逐自驅除，邂逅真龍起畏途。',64,'全唐诗/poet.song.103000.json','["群雄角逐自驅除，邂逅真龍起畏途。", "材並管蕭非亞匹，氣吞曹馬直庸奴。", "兩朝冠蓋尊元老，千載風雲屈壯圖。", "天欲鼎分終割據，可憐憂國竟捐軀。"]'),
('263f80f6-3df3-463b-a909-bc37330fa6cd','臨漳臺','李則','宋','宋诗','song-poetry','','[]','亭枕臨漳一水陰，半空雲霧鎖寒林。',32,'全唐诗/poet.song.103000.json','["亭枕臨漳一水陰，半空雲霧鎖寒林。", "山從天寶來鸞遠，基闢開元歷代深。"]'),
('3a3e375e-bd8b-42ea-b493-57ca5c4bc026','行縣憩九龍巖','黄朝散','宋','宋诗','song-poetry','','[]','金鱗玉角照人寒，何事清時此蟄蟠。',32,'全唐诗/poet.song.103000.json','["金鱗玉角照人寒，何事清時此蟄蟠。", "甘澤不辭膏品物，奚慚濟濟舜朝官。"]'),
('81e1cfb7-b720-4b95-98af-72beb558a267','再過九龍巖','黄朝散','宋','宋诗','song-poetry','','[]','臘盡春來氣應和，豐年嘉瑞作民歌。',32,'全唐诗/poet.song.103000.json','["臘盡春來氣應和，豐年嘉瑞作民歌。", "一杯龍洞梅花酒，□破牢愁埒太阿。"]'),
('658f7730-0fb6-414f-8666-20ef67a494ac','睹丞相曾公爲桂帥時經過留題','黄朝散','宋','宋诗','song-poetry','','[]','龍巖重到臘殘天，欲訪丹成行滿仙。',32,'全唐诗/poet.song.103000.json','["龍巖重到臘殘天，欲訪丹成行滿仙。", "因睹曾公題刻妙，氣騰忠誼拂雲烟。"]'),
('dc0a8515-7ebf-4bc9-b9f4-2860ff44b772','將到巖洞油雲忽作驟雨滂霈','黄朝散','宋','宋诗','song-poetry','','[]','寸心憂旱隱如焚，默念僖心閔雨勤。',32,'全唐诗/poet.song.103000.json','["寸心憂旱隱如焚，默念僖心閔雨勤。", "欲到九龍巖數里，霈然甘澤副油雲。"]'),
('a4c0a062-8cf7-4215-9b34-5b783a75bc59','得雨移刻即止惜乎不廣','黄朝散','宋','宋诗','song-poetry','','[]','驟雨滂沱若救焚，痡瘏時暫慰勞勤。',32,'全唐诗/poet.song.103000.json','["驟雨滂沱若救焚，痡瘏時暫慰勞勤。", "若教千里均霑渥，多稼看看勝□雲。"]'),
('d54a5bcc-54f0-4f9c-87d3-a3dc7fbbaee2','和阮倅正名九仙','黄朝散','宋','宋诗','song-poetry','','[]','采□形相異爲仙，識性誰知共一天。',32,'全唐诗/poet.song.103000.json','["采□形相異爲仙，識性誰知共一天。", "澤物度人均是道，瑞昭千載起祥烟。"]'),
('f875740b-e92c-4d13-ad4e-6d06ee615907','和士曹曹文林省題九龍巖','黄朝散','宋','宋诗','song-poetry','','[]','不爲魚計伏藏深，鳴和奚慚鶴在陰。',32,'全唐诗/poet.song.103000.json','["不爲魚計伏藏深，鳴和奚慚鶴在陰。", "千里秋苗如普潤，何妨信史一書霖。"]'),
('44062b06-2a3c-4603-a4b7-f469fc29e84d','五年二月朔投曉到巖寺適值亡女忌日因而飯僧','黄朝散','宋','宋诗','song-poetry','','[]','沐雨衝風夜向晨，九龍巖畔報中春。',32,'全唐诗/poet.song.103000.json','["沐雨衝風夜向晨，九龍巖畔報中春。", "行庖一供山僧飯，下咽甘□不笑貧。"]'),
('2bfd7749-cd0f-4e48-ad5f-46996f99dc70','題九龍巖','錢懷哲','宋','宋诗','song-poetry','','[]','瀟湘行邁遇初秋，何幸因官得一遊。',32,'全唐诗/poet.song.103000.json','["瀟湘行邁遇初秋，何幸因官得一遊。", "無異醴陵三室洞，九仙羽客是吾儔。"]'),
('64837c60-0280-4054-8a69-b86229809bd1','福延院','許操','宋','宋诗','song-poetry','','[]','一山屈曲如回肘，前有虎眠當水口。',64,'全唐诗/poet.song.103000.json','["一山屈曲如回肘，前有虎眠當水口。", "陰森萬木綠參天，秀色崢嶸欲飛走。", "神仙渺邈不可問，簫鼓尚能喧耳否。", "朝風暮雨無歲年，應是蒼苔暗科斗。"]'),
('c72e4576-99dd-4e89-a49c-d966fd3bdec2','句','劉彥祖','宋','宋诗','song-poetry','','[]','別後頻芳草，愁邊更落花。',12,'全唐诗/poet.song.103000.json','["別後頻芳草，愁邊更落花。"]'),
('a3e3da21-135c-4d80-af4d-1c9392903724','雙溪驛','何恭直','宋','宋诗','song-poetry','','[]','唐山山下雙溪上，城堞參差圖不成。',64,'全唐诗/poet.song.103000.json','["唐山山下雙溪上，城堞參差圖不成。", "已許開簾見山色，何妨欹枕聽溪聲。", "疏泉尚想前賢意，美俗猶存太古情。", "試向丹樓望原野，青青菖葉正催耕。"]'),
('ad712ab4-fabd-4c72-8ca6-3cb33233d6c3','祈雨洩潭','劉佖','宋','宋诗','song-poetry','','[]','未躍天衢卧寂寥，碧潭流溢海山腰。',64,'全唐诗/poet.song.103000.json','["未躍天衢卧寂寥，碧潭流溢海山腰。", "埋藏頭角雖多日，鼓動風雷在一朝。", "既若有心成變化，豈能無意澤枯焦。", "神蹤許爲蒼生起，願擊香車上九霄。"]'),
('182cf112-a71b-45dc-8167-741f7519e500','龍脊','陳似','宋','宋诗','song-poetry','','[]','峽水淵流測益深，砥平鼇脊介江心。',64,'全唐诗/poet.song.103000.json','["峽水淵流測益深，砥平鼇脊介江心。", "簿書叢裏逢休假，雲水光中欣訪尋。", "拂石四題雞子卜，檥舟三聽竹枝音。", "時和撾鼓同民樂，快喜春陽逐衆陰。"]'),
('44b50e1e-c638-455d-b524-4c6a06ac902a','經略龍圖開拓曾公巖景物一新遂爲諸巖之冠因成拙詩投之','楊損','宋','宋诗','song-poetry','','[]','陽巖高敞納晨曦，鶴駕雲軿或可期。',64,'全唐诗/poet.song.103000.json','["陽巖高敞納晨曦，鶴駕雲軿或可期。", "神物雕鎸元入妙，人工開闢更增奇。", "須知水石清凉處，絕勝塵沙熱惱時。", "紅旆碧幢勞小駐，多慚下客濫追隨。"]'),
('d73f6bff-46e4-49d2-86f2-d3831b192181','次陳彥育遊鍾山韻','周邦','宋','宋诗','song-poetry','','[]','雄壓吳頭控楚腰，千峯環拱冶城橋。',64,'全唐诗/poet.song.103000.json','["雄壓吳頭控楚腰，千峯環拱冶城橋。", "黄旗紫蓋旋歸漢，古剎凄凉尚號蕭。", "北嶽經行匪濫巾，相陪來現隱淪身。", "春蘿秋桂還吾輩，白浪紅塵付若人。"]'),
('4da76487-0f79-438a-baac-28964e7172c5','郎官湖春日四首  其一','李祁','宋','宋诗','song-poetry','','[]','兩山收雨暗平沙，遮斷溪梅隔水花。',32,'全唐诗/poet.song.103000.json','["兩山收雨暗平沙，遮斷溪梅隔水花。", "留得烟林作圖畫，依稀松磴有人家。"]'),
('7173c460-acbc-4799-8f3e-9fdc9125006e','郎官湖春日四首  其二','李祁','宋','宋诗','song-poetry','','[]','空山玉蕊照瓊瑰，到處尋花共往回。',32,'全唐诗/poet.song.103000.json','["空山玉蕊照瓊瑰，到處尋花共往回。", "欲識春風最奇處，試來同看雨中梅。"]'),
('b18d6bca-b488-46c5-a51f-d6689385a0a9','郎官湖春日四首  其三','李祁','宋','宋诗','song-poetry','','[]','朦朧花影月黄昏，著意春風入酒痕。',32,'全唐诗/poet.song.103000.json','["朦朧花影月黄昏，著意春風入酒痕。", "知是江梅喜佳客，倒垂花蕊照清樽。"]'),
('05347524-6a2b-4ef6-9dab-4d66efe73fc2','郎官湖春日四首  其四','李祁','宋','宋诗','song-poetry','','[]','十日春陰到水亭，水邊楊柳一時青。',32,'全唐诗/poet.song.103000.json','["十日春陰到水亭，水邊楊柳一時青。", "梅花過盡桃花惡，乞取山礬入浄瓶。"]'),
('2610ec2c-51c8-4ec7-88a0-746f1d364b4f','題朱澤民山水','李祁','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭之南湘水東，青山奕奕蟠蒼龍。',128,'全唐诗/poet.song.103000.json','["洞庭之南湘水東，青山奕奕蟠蒼龍。", "雲陽峰高七十一，欲與衡岳爭爲雄。", "我家近在雲陽下，來往看山如看畫。", "十年塵土走西風，每憶雲陽動悲咤。", "吳中勝士朱隱君，筆精墨妙天下聞。", "畫圖畫出湘江水，青山上有雲陽雲。", "雲陽山高湘水綠，十年不見勞心目。", "只今看畫如看山，萬里歸情寄鴻鵠。"]'),
('1068768b-a24b-44a7-90c0-af92e0fda90b','句  其一','李祁','宋','宋诗','song-poetry','','[]','歸家勿憂御史雨，明月正滿郎官湖。',16,'全唐诗/poet.song.103000.json','["歸家勿憂御史雨，明月正滿郎官湖。"]'),
('b0fe5610-ad8b-4d79-a67e-10ae2b0ae4b0','句  其二','李祁','宋','宋诗','song-poetry','','[]','詩應是遊戲。',6,'全唐诗/poet.song.103000.json','["詩應是遊戲。"]'),
('7c484327-938a-4340-a647-3216d6ecc77b','送孫伯野','楊适','宋','宋诗','song-poetry','','[]','清議豈徒光四戶，直聲應已到三韓。',32,'全唐诗/poet.song.103000.json','["清議豈徒光四戶，直聲應已到三韓。", "黄門有手能批敕，太學無人爲舉幡。"]'),
('b4a4878c-1d1b-4d48-9b19-1f9fd3063714','雪','楊适','宋','宋诗','song-poetry','','[]','渡橋已看銀河凍，上馬爭如玉鳳飛。',32,'全唐诗/poet.song.103000.json','["渡橋已看銀河凍，上馬爭如玉鳳飛。", "莫說兔園延賦客，不須鶴氅作仙衣。"]'),
('f53ed12a-3cd0-4229-a58f-df55be71ae15','梅','楊适','宋','宋诗','song-poetry','','[]','冷冷疏疏雪裏春，不輕吹笛付伶倫。',32,'全唐诗/poet.song.103000.json','["冷冷疏疏雪裏春，不輕吹笛付伶倫。", "出牆幽獨窺鄰女，臨水橫斜覽鏡人。"]'),
('8fa60126-7077-4671-9324-85220425bd6b','絕句','楊适','宋','宋诗','song-poetry','','[]','尖頭奴有五兄弟，十八公生四客卿。',32,'全唐诗/poet.song.103000.json','["尖頭奴有五兄弟，十八公生四客卿。", "過我書齋無一事，似應終日待陶泓。"]'),
('1fa4f5f1-71e2-4c6d-9ef5-fa1386405c17','中秋夜與趙鼎臣狄端叔月下聯句句  其一','楊适','宋','宋诗','song-poetry','','[]','春草隔溪看。',6,'全唐诗/poet.song.103000.json','["春草隔溪看。"]'),
('632209e3-68a0-4008-872f-86223a503b3c','中秋夜與趙鼎臣狄端叔月下聯句句  其二','楊适','宋','宋诗','song-poetry','','[]','冰肌銷瘦爲誰愁。',8,'全唐诗/poet.song.103000.json','["冰肌銷瘦爲誰愁。"]'),
('bab92186-1c21-4348-b775-0652553ebf85','催妝詩','成郎中','宋','宋诗','song-poetry','','[]','一床兩好世間無，好女如何得好夫。',32,'全唐诗/poet.song.103000.json','["一床兩好世間無，好女如何得好夫。", "高捲珠簾明點燭，試教菩薩看麻胡。"]'),
('f86f20ec-26f1-4299-9b23-d34ef808d162','題資州東巖','鄭鋼','宋','宋诗','song-poetry','','[]','逕轉得幽谷，雲巖屹相向。',144,'全唐诗/poet.song.103000.json','["逕轉得幽谷，雲巖屹相向。", "谽谺偃重檐，彎環依疊嶂。", "緬想融結初，鎸鑱自天匠。", "了無斧鑿跡，但覺盤根壯。", "深可數千尺，廣逾八九丈。", "洞穴既窈窕，松門亦昭曠。", "廓舍三千界，中列五百像。", "巨楠布幢蓋，翠蔓垂帷帳。", "木靈不知名，境幽或難狀。", "我時馳征軺，奔走倦塵鞅。", "獲此一段奇，欣然愜微尚。", "欲去興未闌，行行重回望。"]'),
('c1582b89-218b-4894-b7f2-fa582afa52f0','句','袁祹','宋','宋诗','song-poetry','','[]','金瓶芍藥三千朵，玉軸琵琶四百弦。',16,'全唐诗/poet.song.103000.json','["金瓶芍藥三千朵，玉軸琵琶四百弦。"]'),
('07cdf5d1-e2f0-4f39-96f2-e6dd76cca2a2','五馬山','李從訓','宋','宋诗','song-poetry','','[]','北山從何來，崑岷而鼻祖。',180,'全唐诗/poet.song.103000.json','["北山從何來，崑岷而鼻祖。", "並包河與江，考歷不能譜。", "近推連括蒼，繼乃至天姥。", "既而南入台，盤桓遂東下。", "嵯峨起東峁，沃洲兀牆堵。", "孟塘五山頂，樂祖舊遊處。", "時髦集松下，抵掌道今古。", "秀分爲五龍，駢首飲平楚。", "環縣如負扆，爲縣護生聚。", "隱岳聳其南，西隅列旗鼓。", "其間諸名流，晉宋最旁午。", "我慚貂尾續，於汝竟何補。", "登樓覽清秋，黄菊滿樽俎。", "持螯送新酒，醉爲山起舞。", "人生行樂耳，無徒與羊祜。"]'),
('4b000741-b9fb-4947-a4a0-4d864e91e0ac','句','何絳','宋','宋诗','song-poetry','','[]','一江分兩界，二寺對雙蓬。',12,'全唐诗/poet.song.103000.json','["一江分兩界，二寺對雙蓬。"]'),
('a438ef95-6514-4117-ac99-ba3a2baae19a','句','房與之','宋','宋诗','song-poetry','','[]','江水遠流千古恨，峽雲長作四時容。',16,'全唐诗/poet.song.103000.json','["江水遠流千古恨，峽雲長作四時容。"]'),
('a5ea6b7f-9fdb-4a37-ba6b-f6524ccb137e','戲作','陳彥才','宋','宋诗','song-poetry','','[]','賦命安能比鉅公，偶然年月與時同。',32,'全唐诗/poet.song.103000.json','["賦命安能比鉅公，偶然年月與時同。", "只因日上爭些子，笑向連江作醉翁。"]'),
('ba037f7c-335c-45e6-a074-4765fdfa3ff1','送吳將軍元瑜','李芬','宋','宋诗','song-poetry','','[]','秦皇寤寐茅盈語，銳意長生欲輕舉。',192,'全唐诗/poet.song.103000.json','["秦皇寤寐茅盈語，銳意長生欲輕舉。", "徐福藥就仙骨成，雲海茫茫但延佇。", "東西日月秋復春，海變桑田更幾人。", "忽思重看舊寰宇，驂鸞直下江淮濱。", "布衣野叟不耕藝，自向琳宮操祓篲。", "祕語親書悟世人，一坐忽驚三十歲。", "淮南奉道聞真蹟，命使扁舟訪消息。", "畫手從來獨擅長，一見仙風心自得。", "歸來目斷蒼烟垠，三尺生綃醉墨翻。", "軸上神翁不解語，彷彿白鶴乘孤雲。", "海陵相望一千里，嗟我塵勞未云已。", "授書圯上會有期，誠心願取黄公履。"]'),
('1ecbb04d-5de9-4fb4-abec-d123c40a0c58','句  其一','莫蒙','宋','宋诗','song-poetry','','[]','火輪方擊轂，風劍已飛鋩。',12,'全唐诗/poet.song.103000.json','["火輪方擊轂，風劍已飛鋩。"]'),
('c0a50a4c-9a64-4d34-a691-5ae631a257dd','句  其二','莫蒙','宋','宋诗','song-poetry','','[]','諸天互魔擾，救護世尊忙。',12,'全唐诗/poet.song.103000.json','["諸天互魔擾，救護世尊忙。"]'),
('77e9c834-3748-4c61-b4b0-696cb4b29572','夢筆驛','姚宏','宋','宋诗','song-poetry','','[]','一宵短夢驚流俗，千里高名掛里閭。',32,'全唐诗/poet.song.103000.json','["一宵短夢驚流俗，千里高名掛里閭。", "遂使晚生矜此意，癡眠不讀半行書。"]'),
('e1450c88-e19e-4d10-8b47-7f064868d1b3','黄石公祠','劉先生','宋','宋诗','song-poetry','','[]','我昔讀漢史，心師張子房。',144,'全唐诗/poet.song.103000.json','["我昔讀漢史，心師張子房。", "從容輔漢室，功成復翱翔。", "皆由受師訓，知進退存亡。", "我本田舍兒，本志在退藏。", "因緣遇真主，招聘助發揚。", "五年寄京國，心志不皇皇。", "亦由宿志定，萬事皆粃糠。", "今日得歸來，素志今得償。", "艤舟阿縣下，騎馬達祠堂。", "伏行仙遺像，我志愈激昂。", "誓歸東村住，心祈契空蒼。", "庶可見張子，侍翁入帝鄉。"]'),
('6494cd0d-445a-457b-b382-0fbba8857baa','題長興吳城','邵緝','宋','宋诗','song-poetry','','[]','高臺無地曲池平，漂泊勾吳宿古城。',32,'全唐诗/poet.song.103000.json','["高臺無地曲池平，漂泊勾吳宿古城。", "一岸溼雲沈夜色，四山凉葉下秋聲。"]'),
('bf42a6f0-e8c8-4b4b-bf9f-f082e58803aa','題神霄宮壁','李抱一','宋','宋诗','song-poetry','','[]','一粒金丹續命基，算來由我更由誰。',64,'全唐诗/poet.song.103000.json','["一粒金丹續命基，算來由我更由誰。", "神龜移入雲端去，彩鳳摶歸地母騎。", "溟涬浪中求白雪，崑崙山裏采瓊枝。", "只消千日工夫足，養個長稜八角兒。"]'),
('0c3e3819-fa11-4fc7-a27e-85b1881fe1ac','獻詩','馬賢良','宋','宋诗','song-poetry','','[]','破敵將軍曉入燕，滿城和氣接堯天。',32,'全唐诗/poet.song.103000.json','["破敵將軍曉入燕，滿城和氣接堯天。", "油然靉靆三千里，洗盡塵氛二百年。"]'),
('c1e90fdb-fc49-42a2-90e5-22bee8f26493','宣和五年二月初九日偶書呈如公妙空禪師  其一','朱濟道','宋','宋诗','song-poetry','','[]','二年催遣向東州，見盡東州水石幽。',32,'全唐诗/poet.song.103000.json','["二年催遣向東州，見盡東州水石幽。", "不把尋常費心眼，靈巖消得少遲留。"]'),
('745b1b38-65d6-41ab-b072-740b61461c26','宣和五年二月初九日偶書呈如公妙空禪師  其二','朱濟道','宋','宋诗','song-poetry','','[]','東州山水亦堪遊，及至靈巖分外幽。',32,'全唐诗/poet.song.103000.json','["東州山水亦堪遊，及至靈巖分外幽。", "會有定師能指示，直須行到寶峰頭。"]'),
('04786248-1caf-486f-99c4-e5d7dbba7830','宣和癸卯登浮光山','郝某','宋','宋诗','song-poetry','','[]','呼舟入境陟崔嵬，今日登臨慰昔懷。',64,'全唐诗/poet.song.103000.json','["呼舟入境陟崔嵬，今日登臨慰昔懷。", "覽勝淩虛緣絕磴，憑高索句付磨崖。", "松聲夜落千年洞，山勢晴連萬里淮。", "仙蹟空遺丹井在，宦塵行歎老筋骸。"]'),
('bbc5f692-b499-4ff4-ace1-e5db7a1acff5','鐵袈裟','白彥惇','宋','宋诗','song-poetry','','[]','步繞危峯渡翠崖，捫蘿初上更崔嵬。',32,'全唐诗/poet.song.103000.json','["步繞危峯渡翠崖，捫蘿初上更崔嵬。", "他年若有尋真分，定結茅廬傍此臺。"]'),
('7358f56d-c26f-4b13-be67-0f4b8bbb5018','靈巖','宋逸','宋','宋诗','song-poetry','','[]','抖擻塵衣訪古蹤，捫蘿涉嶮徹靈峰。',64,'全唐诗/poet.song.103000.json','["抖擻塵衣訪古蹤，捫蘿涉嶮徹靈峰。", "寒堆泰岳千巖雪，清繞方山十里松。", "泉頂客回聞法鼓，雲堂僧起動齋鐘。", "如來元現因明處，直在人天第一重。"]'),
('ff1dda0a-ba57-4657-abf4-7f8bdafb80d9','臨刑口占','邛州僧','宋','宋诗','song-poetry','','[]','宿業因緣人不知，如今啐啄與同時。',64,'全唐诗/poet.song.103000.json','["宿業因緣人不知，如今啐啄與同時。", "今生歡喜償他了，來世分明不欠伊。", "夢幻色身從敗壞，閑田虛樹已生枝。", "休休休也歸家去，石女懷胎產一兒。"]'),
('b1d78429-6640-49bd-a12f-8ce168d5920f','桃源','釋宗覺','宋','宋诗','song-poetry','','[]','深隱猶疑世上聞，桃花還洩洞中春。',32,'全唐诗/poet.song.103000.json','["深隱猶疑世上聞，桃花還洩洞中春。", "當時不得漁人入，將謂人問幾世秦。"]'),
('65e73cd4-3ec4-409e-a142-f3d0c8a33c98','詩一首','張珍奴','宋','宋诗','song-poetry','','[]','逢師許多時，不說些兒箇。',24,'全唐诗/poet.song.103000.json','["逢師許多時，不說些兒箇。", "及至如今悶，損我援筆末。"]'),
('4c638ca6-924f-45e2-a40c-2450c1ac7a6c','題汴邸','丁氏','宋','宋诗','song-poetry','','[]','西嶺雌雄鳥，雙雙覽德輝。',48,'全唐诗/poet.song.103000.json','["西嶺雌雄鳥，雙雙覽德輝。", "陽臺遲雨散，滄海會塵飛。", "夜月參差玉，春雲窈窕衣。", "君王宴阿母，却寄碧桃歸。"]'),
('89134574-e343-43d3-a2e4-b32c2b29474e','句','蘄春鄉人','宋','宋诗','song-poetry','','[]','園客有絲難比甕，鮫人無杼自成綃。',16,'全唐诗/poet.song.103000.json','["園客有絲難比甕，鮫人無杼自成綃。"]'),
('7a1d83e7-7cbb-4dbd-b0b6-1b79995d2b8c','句  其一','王輔','宋','宋诗','song-poetry','','[]','山光水色兩依依。',8,'全唐诗/poet.song.103000.json','["山光水色兩依依。"]'),
('999f81cf-7044-4932-930d-26aa20d05010','句  其二','王輔','宋','宋诗','song-poetry','','[]','莖抽銀線細，根結水晶寒。',12,'全唐诗/poet.song.103000.json','["莖抽銀線細，根結水晶寒。"]'),
('a566086d-bf1f-4306-a404-fc79f564591a','句  其三','王輔','宋','宋诗','song-poetry','','[]','入堂無復見雙親，建此來寧似在神。',16,'全唐诗/poet.song.103000.json','["入堂無復見雙親，建此來寧似在神。"]'),
('52cebb40-557d-49a2-8b3d-8ac9632df505','句  其四','王輔','宋','宋诗','song-poetry','','[]','陟彼南山采。',6,'全唐诗/poet.song.103000.json','["陟彼南山采。"]'),
('b963e5a2-902b-4c87-b885-ead2fdcc3d92','過浯溪觀中興磨崖因成一絕','李若虛','宋','宋诗','song-poetry','','[]','元顔文字照浯溪，神物於今長護持。',32,'全唐诗/poet.song.103000.json','["元顔文字照浯溪，神物於今長護持。", "崖邊尚有堪磨處，留刻中興第二碑。"]'),
('7cc8001d-dfff-4800-b552-a2f47e1a6c23','還山招陳希韓','高登','宋','宋诗','song-poetry','','[]','乾坤莽回互，日月相盪摩。',240,'全唐诗/poet.song.103000.json','["乾坤莽回互，日月相盪摩。", "百年纔瞬息，萬類總么麽。", "是身非吾有，造物如我何。", "觸事會心少，幽棲廢興多。", "眷言意所適，樂此山之阿。", "修篁擢新幹，老木榮舊柯。", "谷聲傳地籟，松韻答天和。", "獨石介而安，寒泉淡無波。", "園蔬掇纖嫩，名果仍駢羅。", "紅綻著雨花，碧卷受風荷。", "隨意坐莓苔，絺衣掛薜蘿。", "得酒即酩酊，作詩苦吟哦。", "嘯長情浩蕩，舞短影婆娑。", "妻奴鹿門趣，黄綺商山歌。", "崎嶇路辭遥，迢遞誰見過。", "交親憶同調，出處矢靡他。", "每憐傷弓禽，因感赴燭蛾。", "無心更□□，試藝趁投戈。", "自覺此身浮，相看雙鬢皤。", "人事何時休，歸來勿蹉跎。"]'),
('74235d67-6301-4594-aa5b-1a90f0051db8','偕學子遊都嶠','高登','宋','宋诗','song-poetry','','[]','甲子歲秋杪，負罪西南馳。',288,'全唐诗/poet.song.103000.json','["甲子歲秋杪，負罪西南馳。", "脚歷山萬重，身墜天一涯。", "茅茨蔽聚落，培塿圍孤埤。", "何處有洞天，玄真之所栖。", "維南頗挺拔，隱隱浮修眉。", "采菊東籬下，悠然一見之。", "欲往覺旌摇，兀坐嗟黏黐。", "彼美二三子，知我多愛奇。", "□□□□□，□□登翠微。", "天公喜我來，閣雨雲垂垂。", "坤靈喜我來，林壑迴春姿。", "山禽喜我來，上下鳴嚶吚。", "江梅喜我來，蓓蕾敷南枝。", "高興□幽尋，絕□□□□。", "□□□如許，鬰葱瑣煙□。", "誰遣衢聃徒，列此怪狀爲。", "□馮賢主人，痛□彌年非。", "我生逢百罹，不慕太廟犠。", "况從奪袍簡，欣若脫馬羈。", "投荒得勝踐，□與□分宜。", "清芬追六逸，餘齡寄三危。", "明時甘自誓，敢□□□詞。", "暫遊已難得，短畧仍易移。", "山脚趣回馭，□□□□□。"]'),
('6de6f3df-8f1e-440c-ac65-7277953d22d1','歸途歎','高登','宋','宋诗','song-poetry','','[]','孫吳攄將略，申甫翰王家。',24,'全唐诗/poet.song.103000.json','["孫吳攄將略，申甫翰王家。", "腐儒要底用，歸種東陵瓜。"]'),
('48ec8d4e-cb36-487f-83ba-986d0bfc641f','自歎','高登','宋','宋诗','song-poetry','','[]','平生無技能，素業□□□。',144,'全唐诗/poet.song.103000.json','["平生無技能，素業□□□。", "□□□□□，世期躋唐虞。", "憤嘗獻瞽言，□□□□□。", "□□□□□，寧憚攀虎鬚。", "由此隔□□，□□□□□。", "□□□□□，□束如囚拘。", "索米無處□，□□□□□。", "□□□□□，漫不分賢愚。", "梁竦知徒勞，淵明奈□□。", "□書獄訟簡，沈迷眩鉛朱。", "□□□□□，窗几羅蛛絲。", "簡編殘□□，□□□□□。"]'),
('7a81d819-2b6e-4723-9df9-a20d73586cf7','思歸','高登','宋','宋诗','song-poetry','','[]','忽忽已秋杪，言歸欣有期。',96,'全唐诗/poet.song.103000.json','["忽忽已秋杪，言歸欣有期。", "節物想吾廬，青蕊繁東籬。", "流匙白雲子，蘸甲黄鵝兒。", "對此憶羈旅，多應歌式微。", "喜慰倚門心，愁消舉案眉。", "稚子鬧檐隙，繞膝牽人衣。", "歸興念如許，兼程猶苦遲。", "明朝秋色裏，烏帽風披披。"]'),
('2ffd471c-8007-478e-a580-025dbcd320d2','似春閣','高登','宋','宋诗','song-poetry','','[]','二閣寧獨暖，萬家方號寒。',24,'全唐诗/poet.song.103000.json','["二閣寧獨暖，萬家方號寒。", "何當放春去，和氣滿人間。"]'),
('d0478356-ba86-4ae6-a679-15da8886ad84','留別','高登','宋','宋诗','song-poetry','','[]','丈夫四方志，肯作兒女別。',72,'全唐诗/poet.song.103000.json','["丈夫四方志，肯作兒女別。", "顧我差崛强，羨君真秀發。", "道義重千鈞，利名輕一葉。", "壯風吐虹蜺，忠誠貫日月。", "插劍露肝膽，看鏡念勳業。", "何當拔茅茹，同在陳力列。"]'),
('86e3a4b3-8d22-4209-a8b3-5f4870e96f31','冒寒行風雨有感','高登','宋','宋诗','song-poetry','','[]','號風撼枯枿，凍雨凝路塵。',48,'全唐诗/poet.song.103000.json','["號風撼枯枿，凍雨凝路塵。", "乾坤祕日月，八荒同一雲。", "遥知沙漠寒，黯淡愁殺人。", "天涯望不極，流涕滿衣巾。"]'),
('a106f218-10cc-457a-81ab-6a18553d1709','陳少陽贈官','高登','宋','宋诗','song-poetry','','[]','憶昔靖康初，厄運會中微。',288,'全唐诗/poet.song.103000.json','["憶昔靖康初，厄運會中微。", "嚴禁弛邊備，長驅來健兒。", "堂堂搗京闕，百萬呼鼓鼙。", "天地爲改色，日月晴晦迷。", "當宁猶未悟，聰明遭蔽欺。", "六賊久盤結，如山屹莫移。", "故人陳夫子，忠□□根資。", "拊髀惜機會，禍端良在茲。", "吾儕沐厚澤，顛危合扶持。", "不聞王蠋賢，絕脰由布衣。", "書成數千言，揮翰捷如飛。", "明朝伏闕下，儒冠翕相隨。", "种李奪兵權，憤痛社稷危。", "抱書再詣闕，慟哭聲猶悲。", "天意難遽回，人心□□離。", "時雍恣凶暴，縱兵欲屠之。", "馬前森利刃，此時命垂絲。", "要領兩不顧，相視情怡怡。", "虎口僅獲脫，好爵安能縻。", "俄起故鄉情，各歸天一涯。", "壯哉歐陽生，捨生誠所宜。", "聖主圖興復，忠誠蒙誅夷。", "宸心頃自責，疏節錄其遺。", "君乎死不亡，泉壤增光輝。"]'),
('92c578d5-873b-4bca-b17c-99ceedb62cc4','杜門','高登','宋','宋诗','song-poetry','','[]','故人方謝客，爲問意如何。',48,'全唐诗/poet.song.103000.json','["故人方謝客，爲問意如何。", "午枕清風足，夜窗明月多。", "易招惟酒聖，難遣是詩魔。", "一榻君家事，何妨獨我過。"]'),
('3a45897b-7642-4434-9aa8-d88802d0dab6','七夕','高登','宋','宋诗','song-poetry','','[]','天道杳難憑，人言殊不經。',48,'全唐诗/poet.song.103000.json','["天道杳難憑，人言殊不經。", "佳期傳七夕，歡事污雙星。", "女騃占蛛巧，兒癡托鵲靈。", "吾詩非好詆，聊與訂頑冥。"]'),
('8d8c5dbd-8051-4c94-82a4-8ad46ad1b306','夢遊故山','高登','宋','宋诗','song-poetry','','[]','風際氅披鶴，雲根杖策鳩。',48,'全唐诗/poet.song.103000.json','["風際氅披鶴，雲根杖策鳩。", "幽棲知好在，歸夢故難留。", "山放數峯出，泉分一派流。", "把茅何日辦，縛屋護松楸。"]'),
('81aff31c-11db-464b-8163-7b703e1f4d39','送元大','高登','宋','宋诗','song-poetry','','[]','但得身長健，何妨鬢已華。',48,'全唐诗/poet.song.103000.json','["但得身長健，何妨鬢已華。", "胸中翻錦繡，筆下走龍蛇。", "作掾只三語，讀書空五車。", "卷懷良得計，去去卧煙霞。"]'),
('d489b17c-a568-454e-aa8d-9db24b73c994','辭餽金','高登','宋','宋诗','song-poetry','','[]','劉君政成□□□，闔境歡謠騰載道。',128,'全唐诗/poet.song.103000.json','["劉君政成□□□，闔境歡謠騰載道。", "民不見吏犬無聲，持以百錢勤父老。", "嗟我官卑志未伸，於人何德人稱好。", "騰牒當途願丐留，餽贐交馳雜金寶。", "天涯百指携空囊，號寒啼饑日相惱。", "可取無取未傷廉，爲念易污惟皓皓。", "不如買書惠泮宮，聊助賢侯采芹藻。", "別後青衿倘見思，窗前黄卷宜探討。"]'),
('7eecb675-0c36-4cc0-a8b4-ec2b8940439d','水漲謝邑宰送米','高登','宋','宋诗','song-poetry','','[]','心知一字不堪煮，矻矻窮年黄卷中。',64,'全唐诗/poet.song.103000.json','["心知一字不堪煮，矻矻窮年黄卷中。", "食粥由來未爲過，儲瓶况乃嗟屢空。", "令君好賢媲韓愈，賤子受賜慚盧仝。", "春水從教繞舍北，癡兒不復啼門東。"]'),
('8778aadb-675b-43de-a9b0-df2e9be36689','中秋月','高登','宋','宋诗','song-poetry','','[]','繡江再見中秋月，歲去月圓人尚缺。',96,'全唐诗/poet.song.103000.json','["繡江再見中秋月，歲去月圓人尚缺。", "相望千里共嬋娟，苦恨亭亭照離別。", "今夕一尊誰與同，孟光舉案對梁鴻。", "衆雛立侍儼成列，以次持杯壽乃翁。", "乃翁看月揩病目，手足頑麻頭髮禿。", "但願團圞三十秋，不計東西與南北。"]'),
('e4128cf4-90a1-4302-87fa-fb2d55ab3a4f','臨別示子','高登','宋','宋诗','song-poetry','','[]','不能枉道取富貴，是致爾輩愁饑寒。',64,'全唐诗/poet.song.103000.json','["不能枉道取富貴，是致爾輩愁饑寒。", "頻年別離情更惡，兩地狼狽心何安。", "從人數寄安否問，使我相思懷抱寬。", "平生竊歎曹家兒，臨歧莫墮雙闌干。"]'),
('530e2f90-828f-44db-b8cc-bef5f4b96230','乞米','高登','宋','宋诗','song-poetry','','[]','臣饑欲死侏儒飽，方朔誰憐是歲星。',64,'全唐诗/poet.song.103000.json','["臣饑欲死侏儒飽，方朔誰憐是歲星。", "館下諸生笑豐暖，江頭漁父誚清醒。", "魯公已作乞米帖，陶令旋尋儲粟瓶。", "親舊依然眼相向，故應特地爲吾青。"]'),
('39c03b43-c310-471f-a933-904e0ec61359','覓蠹椽','高登','宋','宋诗','song-poetry','','[]','顧影低徊祇自憐，怕寒時聳作詩肩。',64,'全唐诗/poet.song.103000.json','["顧影低徊祇自憐，怕寒時聳作詩肩。", "全家食粥已數月，坐客無氈今幾年。", "君劈槽燒當止酒，我和琴爨况無絃。", "雪中送炭從來事，况爾羈躬覓蠹椽。"]'),
('b68db856-3386-498e-a57f-bea680246eee','小原欲歸','高登','宋','宋诗','song-poetry','','[]','潮頰香醪暈醉紅，𩍐敲歸路勒青驄。',64,'全唐诗/poet.song.103000.json','["潮頰香醪暈醉紅，𩍐敲歸路勒青驄。", "水涵萬頃曾孫稼，月逗盈衿少女風。", "大誤平生緣畫足，無聊中夜祇書空。", "擬將方宇難論事，直扣天門問化工。"]'),
('96ddef5c-4eb1-4620-9e4e-6887a1e186de','立冬道中','高登','宋','宋诗','song-poetry','','[]','黄茅時節瘴煙濃，人在山凹第幾重。',64,'全唐诗/poet.song.103000.json','["黄茅時節瘴煙濃，人在山凹第幾重。", "梁竦負才徒感慨，嵇康賦性本疏慵。", "此生自斷天休問，吾道頻年世不容。", "會脫幘巾還自隱，鹿門妻子慣相從。"]'),
('1375793f-a0d2-473b-8976-d9ebf92bb42b','言懷','高登','宋','宋诗','song-poetry','','[]','歸去東皋獨荷犁，筆床書卷有兒持。',64,'全唐诗/poet.song.103000.json','["歸去東皋獨荷犁，筆床書卷有兒持。", "一無可意身將老，百不如人心自知。", "夢寐摩娑元結頌，經從省憶少陵詩。", "體膚餓盡天應錯，依舊臞然山澤姿。"]'),
('42677652-6ca2-47ee-9f28-f3b416b53b0f','九日','高登','宋','宋诗','song-poetry','','[]','塞雁南飛度戍樓，一聲天地有餘秋。',64,'全唐诗/poet.song.103000.json','["塞雁南飛度戍樓，一聲天地有餘秋。", "家連滄海難窮目，人在蠻荒欲盡頭。", "莫效涓埃裨國計，况無毛髮爲身謀。", "所須菽水能多少，蹤跡飄然不繫舟。"]'),
('85a8283b-63a6-49c7-a416-773617e091e6','病中雜興  其一','高登','宋','宋诗','song-poetry','','[]','溶溶瘴霧暗朝暾，咫尺山關號鬼門。',32,'全唐诗/poet.song.103000.json','["溶溶瘴霧暗朝暾，咫尺山關號鬼門。", "疾病年年不相貸，朱顔凋盡赤心存。"]'),
('2104cadd-e552-4bdf-be65-98d8e3c308c0','病中雜興  其二','高登','宋','宋诗','song-poetry','','[]','垂老飄零萬里餘，肌膚瘦盡鬢毛疏。',32,'全唐诗/poet.song.103000.json','["垂老飄零萬里餘，肌膚瘦盡鬢毛疏。", "皇恩若許歸山去，豆地雖存不解鋤。"]'),
('765aec89-dc1d-48a0-94e4-1e197a6e8790','病中雜興  其三','高登','宋','宋诗','song-poetry','','[]','不羨雲霄欲網羅，百年人物總相磨。',32,'全唐诗/poet.song.103000.json','["不羨雲霄欲網羅，百年人物總相磨。", "死如歸耳生如寄，造物從今奈我何。"]'),
('03ff9bc6-119e-441c-b0a8-3085fb47361e','病中雜興  其四','高登','宋','宋诗','song-poetry','','[]','九死窮荒一病翁，曉來猶怯北窗風。',32,'全唐诗/poet.song.103000.json','["九死窮荒一病翁，曉來猶怯北窗風。", "誰知葵藿傾心切，待到日輪升太空。"]'),
('e5d9292c-9013-4539-b841-8ef8161654c0','病中雜興  其五','高登','宋','宋诗','song-poetry','','[]','不辭南北嘆飄零，俯仰乾坤一草亭。',32,'全唐诗/poet.song.103000.json','["不辭南北嘆飄零，俯仰乾坤一草亭。", "鳶墮水中從沓沓，鴻飛天外自冥冥。"]'),
('2733e289-3d84-47d4-aab7-81fdb397d299','病中雜興  其六','高登','宋','宋诗','song-poetry','','[]','長袖深藏批敕手，短筇斜倚作詩肩。',32,'全唐诗/poet.song.103000.json','["長袖深藏批敕手，短筇斜倚作詩肩。", "有時極目愧遼漢，興在孤鴻落照邊。"]'),
('59ce8ab1-a88a-4a6d-833f-412af4cadb7f','病中雜興  其七','高登','宋','宋诗','song-poetry','','[]','病損腰圍減未休，二毛垂領颯先秋。',32,'全唐诗/poet.song.103000.json','["病損腰圍減未休，二毛垂領颯先秋。", "夢中那復化爲蝶，林下不妨問鬬牛。"]'),
('f6631b81-e61a-4bd9-bafb-adb2bdbdbbd1','病中雜興  其八','高登','宋','宋诗','song-poetry','','[]','口腹相煎亦可羞，饑來欲食飽還憂。',32,'全唐诗/poet.song.103000.json','["口腹相煎亦可羞，饑來欲食飽還憂。", "一編地下我無用，須學留侯辟穀不。"]'),
('06773d9f-ec7b-40f2-8620-be8fa754e343','上元','高登','宋','宋诗','song-poetry','','[]','情感此宵元切恨，遣懷高唱一聲歌。',64,'全唐诗/poet.song.103000.json','["情感此宵元切恨，遣懷高唱一聲歌。", "清澄月滿鋪逵路，烜赫蓮開未綠荷。", "觥酒滯時追伴侶，袖香凝處想紈羅。", "更深候望遥腸斷，爽約人歸不我過。"]'),
('6e1338c0-cc5d-4e6c-b264-d05b50be7cf7','句  其一','高登','宋','宋诗','song-poetry','','[]','瘴侵玉骨終難起，魂斷巫山永不歸。',16,'全唐诗/poet.song.103000.json','["瘴侵玉骨終難起，魂斷巫山永不歸。"]'),
('8e629191-8e3b-4dbf-9f18-d8d6759d0cf1','句  其二','高登','宋','宋诗','song-poetry','','[]','無邪煩艾子，有慍賴桐孫。',12,'全唐诗/poet.song.103000.json','["無邪煩艾子，有慍賴桐孫。"]'),
('09821472-9aa4-45ab-aa07-9fababf2558e','雜詩六首  其一','李若水','宋','宋诗','song-poetry','','[]','風流李東山，磊落孔北海。',48,'全唐诗/poet.song.103000.json','["風流李東山，磊落孔北海。", "身逐煙雲飛，名與日月在。", "彼哉世上兒，平生抱慚悔。", "雖云官爵高，當以羊豕待。"]'),
('7e9eefb4-4464-4281-8ea0-1846b12d7a55','雜詩六首  其二','李若水','宋','宋诗','song-poetry','','[]','門前誰剝啄，云有故人至。',60,'全唐诗/poet.song.103000.json','["門前誰剝啄，云有故人至。", "殷勤具雞黍，莫辭今日醉。", "人生若飆馳，世事等鱗次。", "區區百無益，杯酒差可貴。", "故人首肯之，愛吾言有味。"]'),
('709f4cd6-a367-4efd-94c6-7eb22c35a95b','雜詩六首  其三','李若水','宋','宋诗','song-poetry','','[]','一飽百念休，挈席坐朝陽。',48,'全唐诗/poet.song.103000.json','["一飽百念休，挈席坐朝陽。", "陶然四肢春，興與飲酒長。", "夢蝶鼻聲小，捫虱衣縫光。", "雖非北窗下，亦足傲羲皇。"]'),
('d3b17d5b-7b55-4d22-9a55-e2d443083b05','雜詩六首  其四','李若水','宋','宋诗','song-poetry','','[]','相如貧立壁，淵明老經邱。',48,'全唐诗/poet.song.103000.json','["相如貧立壁，淵明老經邱。", "文字照千祀，何人與之儔。", "我生造化間，一萍寄洪流。", "收心短檠底，要陪古人遊。"]'),
('39d509fc-8943-4082-b6af-8cbae03e97e0','雜詩六首  其五','李若水','宋','宋诗','song-poetry','','[]','明月如幽人，邈有出世姿。',60,'全唐诗/poet.song.103000.json','["明月如幽人，邈有出世姿。", "吾欲從之遊，開門曳藤枝。", "得酒袖自舉，賞此一段奇。", "人生要行樂，戚戚竟何爲。", "君看李太白，高風謝塵羈。"]'),
('e5f58e93-babe-4a2f-ad61-6e65492d208c','雜詩六首  其六','李若水','宋','宋诗','song-poetry','','[]','禦戎如禦寇，愛民如愛子。',36,'全唐诗/poet.song.103000.json','["禦戎如禦寇，愛民如愛子。", "豈不有公卿，脆弱非所倚。", "吾君儻擇賢，何病不可理。"]'),
('bf937838-3f3d-422a-8630-0216af71fc9c','諸剎以水激磑磨殊可觀爲賦此詩','李若水','宋','宋诗','song-poetry','','[]','疊石壅寒派，滿流瀉迴溪。',96,'全唐诗/poet.song.103000.json','["疊石壅寒派，滿流瀉迴溪。", "誰將方便智，成此圓妙機。", "輪輻互高下，波濤鬰翻飛。", "磨牙遞旋斡，磑杵紛昂低。", "玉粒已粲粲，瓊花亦霏霏。", "術存機械巧，利澤成博施。", "試語漢陰老，使知渾沌非。", "惟當善用心，功與天地齊。"]'),
('f7aa9e97-f8d1-4a65-b4b1-6e62080768e2','離家','李若水','宋','宋诗','song-poetry','','[]','曙風入修檐，宿靄度遥嶺。',84,'全唐诗/poet.song.103000.json','["曙風入修檐，宿靄度遥嶺。", "遊子戀庭闈，延此須臾景。", "臨行懶加衣，上馬晨煙冷。", "歧路白日忙，氣候清夜永。", "前途寡親友，所晤唯瘦影。", "長風儻或借，逸翰當少騁。", "不然早旋歸，柴門保孤靜。"]'),
('4a7b0948-df1c-4e53-a9b7-4776d9f36bee','獄平堂','李若水','宋','宋诗','song-poetry','','[]','掌獄貴持平，萬議不能破。',48,'全唐诗/poet.song.103000.json','["掌獄貴持平，萬議不能破。", "夫子乃名堂，無愧橫案坐。", "皇家美化醲，小人亦寡過。", "朱墨儻餘暇，不妨歌楚些。"]'),
('be6c2d94-4527-482f-8524-14b3c9406bfb','綠漪軒遇雨與任才仲定韻賦','李若水','宋','宋诗','song-poetry','','[]','才到綠漪軒，逸興小寰宇。',108,'全唐诗/poet.song.103000.json','["才到綠漪軒，逸興小寰宇。", "岸斜水自環，樹缺山爲補。", "眼界萬象入，佳處難悉數。", "天公厭人閑，惱以催詩雨。", "凉飆拍窗戶，殘熾敢予侮。", "雲脚漏夕陽，反學新月吐。", "麈尾散銀毫，茶面噴雪乳。", "茲遊神所靳，而我已多取。", "何時理扁舟，歸作雲山主。"]'),
('616fdace-5256-47a6-b62e-1c55c9603487','中秋不見月二首  其一','李若水','宋','宋诗','song-poetry','','[]','明月如君子，隱見自有時。',72,'全唐诗/poet.song.103000.json','["明月如君子，隱見自有時。", "頑雲巧障之，光耀不得施。", "賞心無復樂，對酒翻成悲。", "樹頭號秋風，日夜無停期。", "胡不驅頑雲，放出玉一規。", "而乃窗几間，空將亂帙吹。"]'),
('48503e6b-4792-4433-a7b4-48952fbcbfc7','中秋不見月二首  其二','李若水','宋','宋诗','song-poetry','','[]','明月自不老，古今同一時。',72,'全唐诗/poet.song.103000.json','["明月自不老，古今同一時。", "尋常賞心薄，萬里清光施。", "茲夕反雲翳，庭烏亦長悲。", "人生得意處，每每乖所期。", "神仙不可學，富貴不可規。", "此心恐未了，付與秋風吹。"]'),
('81c5fa0d-430b-450e-a04d-811beac51877','平川道中','李若水','宋','宋诗','song-poetry','','[]','客子結征衣，伺明鞭瘦馬。',72,'全唐诗/poet.song.103000.json','["客子結征衣，伺明鞭瘦馬。", "時平路無虞，年豐村有社。", "歸雁嘶層雲，饑烏啄平野。", "牆花初壓枝，橋柳已盈把。", "春岸坐漁人，曉隴來耕者。", "風埃政無聊，懷抱何由寫。"]'),
('8ed57b87-9176-47b7-85a2-4580cb84aede','秋風','李若水','宋','宋诗','song-poetry','','[]','疏風舞天際，坐覺秋容開。',72,'全唐诗/poet.song.103000.json','["疏風舞天際，坐覺秋容開。", "新凉萬金直，竟從何許來。", "修梧脫老葉，槭槭投空階。", "故人渺雲水，音徽諒難諧。", "政恐歲華晚，便與人意乖。", "脫巾漉初熟，聊以洗此懷。"]'),
('37566f41-7589-4d7c-a0fe-08b5ef56f25f','送公實兄赴省試','李若水','宋','宋诗','song-poetry','','[]','吾君邁周王，於今盛文化。',96,'全唐诗/poet.song.103000.json','["吾君邁周王，於今盛文化。", "學郎紛萬輩，戰藝雙闕下。", "公乎筆如椽，風雨供飛灑。", "燕楚何足吞，此行定應霸。", "三世守墨莊，一朝騰紙價。", "况值求賢秋，宣室政延賈。", "輕雲飛隴頭，車輪去如馬。", "快哉上林春，杯酒須勤把。"]'),
('56455f79-5c5c-4221-8bd6-fb59a2711a3d','謁束先生廟','李若水','宋','宋诗','song-poetry','','[]','弔古懷騷人，接轡黄榆路。',72,'全唐诗/poet.song.103000.json','["弔古懷騷人，接轡黄榆路。", "疏風吹廣原，馬首飛埃度。", "荒祠止道旁，古木寒鴉聚。", "入門煙素橫，虛壁丹青污。", "再拜休廡下，追誦補亡句。", "興餘歸袖翻，低雲掛秋暮。"]'),
('65c0ab78-79cd-4d0e-b4fd-82a48c92dd70','次韻和友人竹石','李若水','宋','宋诗','song-poetry','','[]','厚德鎮囂浮，才高謝羈束。',48,'全唐诗/poet.song.103000.json','["厚德鎮囂浮，才高謝羈束。", "所賦雖不均，而皆堪比玉。", "此君非俗姿，終朝看不足。", "客至亦忘歸，裊裊茶烟綠。"]'),
('96ddaf75-e0e5-484f-bccf-9b1c316ac30e','受誓戒','李若水','宋','宋诗','song-poetry','','[]','秋月浄如璧，影著烏帽寒。',60,'全唐诗/poet.song.103000.json','["秋月浄如璧，影著烏帽寒。", "殘夢未辭睫，疲駑兀難安。", "龍津橋下路，燈火半斕斑。", "中臺門已敞，風細簾幕乾。", "有司謹苛禮，高人窘微官。"]'),
('95f0685f-e4e5-4f90-b6d3-c523970b3dd0','書懷','李若水','宋','宋诗','song-poetry','','[]','客裏百無營，一室等方丈。',48,'全唐诗/poet.song.103000.json','["客裏百無營，一室等方丈。", "行藏沙漠邊，志節煙霄上。", "歸思入新吟，閑愁付佳釀。", "何當把瘦藤，江山樂清放。"]'),
('b748d738-7b14-4cde-9f8f-720cbe2f203f','題畫','李若水','宋','宋诗','song-poetry','','[]','羃羃護雲衣，巉巉露山骨。',72,'全唐诗/poet.song.103000.json','["羃羃護雲衣，巉巉露山骨。", "老木依蒼岩，密布蔭清樾。", "乞我片席地，脫巾露華髮。", "橫竹呼秋風，脩藤步明月。", "茲焉甘終老，夢斷帝京闕。", "何必學王郎，昂首但拄笏。"]'),
('1bc2acd0-8027-4226-822d-f19aba2824aa','次韻雍節夫留別','李若水','宋','宋诗','song-poetry','','[]','東風政摇蕩，百鳥爭春鳴。',72,'全唐诗/poet.song.103000.json','["東風政摇蕩，百鳥爭春鳴。", "長亭楊柳弱，廣陌芳草平。", "遊子動行色，辛勤奔皇京。", "利名悲末路，合散笑浮生。", "望望陟前陂，隕涕空含情。", "勉哉振長策，扶摇雲翼輕。"]'),
('0e5c0477-42fd-4c9f-8e5e-4471c62b41b8','紅梅','李若水','宋','宋诗','song-poetry','','[]','東風一戲劇，會使紅綠爭。',120,'全唐诗/poet.song.103000.json','["東風一戲劇，會使紅綠爭。", "粲粲牆角花，朝霞翦芳英。", "自憐冰雪志，猥與桃杏并。", "未應素節改，但覺羞顔頳。", "孤標翳塵土，疏香掩蓬荆。", "遊蜂頗知己，飛繞千回輕。", "其奈逐臭夫，對之白眼橫。", "主人情不薄，愛君成瘦生。", "今來攝從事，吏課殊少程。", "何時把杯酒，一洗千枯榮。"]'),
('4177d20c-66a5-4024-ac67-3ce073a8bf76','次韻李子建春雨','李若水','宋','宋诗','song-poetry','','[]','玄雲駕雨來，垂垂勢未已。',96,'全唐诗/poet.song.103000.json','["玄雲駕雨來，垂垂勢未已。", "雙袖貯疏凉，六幕浄餘滓。", "錦飄風撼花，玉逗水循軌。", "窗峯碧巑巑，隴麥青靡靡。", "詩人筆欲髠，行子步難跬。", "虀鹽老青衫，文字亂烏几。", "咄咄怪書空，嗚嗚熱浮耳。", "不肯卧南陽，剛學蟄龍起。"]'),
('d999e56e-974d-4911-b9f9-b38b01fef665','何德休設冰茶','李若水','宋','宋诗','song-poetry','','[]','火雲撲不滅，餘熾欲燒天。',120,'全唐诗/poet.song.103000.json','["火雲撲不滅，餘熾欲燒天。", "江山散白日，草木含蒼烟。", "瑠璃八尺浄，邀我北窗眠。", "但問風雌雄，姑謝酒聖賢。", "明冰沃新茗，妙飲誇四筵。", "休論水第一，凜然香味全。", "凉飚生兩腋，坐上徑欲仙。", "塵襟快洗滌，詩情拍天淵。", "憑君杯勺許，置我崑閬前。", "搜攪玉雪腸，醞釀雲錦篇。"]'),
('b207e0d9-5f31-4697-ba29-01e002585a22','次韻李子建苦熱','李若水','宋','宋诗','song-poetry','','[]','金鎔日影活，絮擘雲態癡。',96,'全唐诗/poet.song.103000.json','["金鎔日影活，絮擘雲態癡。", "石膚然欲碎，禾末焦自萎。", "絲脆蛛停網，花枯蜜守脾。", "竹粉欠新潤，溪毛收故滋。", "瓠尊資酒釅，蘄席便軀肥。", "土膏龜坼裂，雨勢淚漣洏。", "革履委弗御，葛巾欹不持。", "松陰良可就，逭暑旋題詩。"]'),
('5fe5edcc-3031-4348-9ac2-d37b85d92e27','夜坐與高子文分韻得月字','李若水','宋','宋诗','song-poetry','','[]','笑問空中雲，乞我今夕月。',36,'全唐诗/poet.song.103000.json','["笑問空中雲，乞我今夕月。", "我是方外人，得此清興發。", "翩然駕黄鵠，飛入白銀闕。"]'),
('4c4a5271-70d5-4510-93df-13ecfa568af5','言志','李若水','宋','宋诗','song-poetry','','[]','我拙畏吏事，觀書度晨夕。',96,'全唐诗/poet.song.103000.json','["我拙畏吏事，觀書度晨夕。", "過眼輒成誦，掩卷不再歷。", "荒怪探禹穴，幽邈窺孔壁。", "俯首滯銅印，朋儕屢貽責。", "皇朝采疏逖，龐洪流慶澤。", "英俊藹雲趨，參隸金門籍。", "而我老紅塵，棄置誰復惜。", "徑欲賦歸歟，吳門晦聲跡。"]'),
('6ebc87c8-b1eb-4ae1-895c-748529f88b56','秋懷  其一','李若水','宋','宋诗','song-poetry','','[]','西風響窗扉，炎火煩一掃。',48,'全唐诗/poet.song.103000.json','["西風響窗扉，炎火煩一掃。", "天清露華滋，妍碧謝庭草。", "旅懷良獨難，缺月窺檐間。", "呼兒漉新酒，强欲朱衰顔。"]'),
('61c18dfd-1eb4-4648-b3d1-de473b648b00','秋懷  其二','李若水','宋','宋诗','song-poetry','','[]','鷗鳥戀江湖，麋鹿戀林藪。',48,'全唐诗/poet.song.103000.json','["鷗鳥戀江湖，麋鹿戀林藪。", "十年異鄉客，臨風一搔首。", "田園幸好在，三徑荒稂莠。", "何當愜歸興，短鉏還入手。"]'),
('90a437ab-97f6-499e-abfa-945d6a7f1af6','秋懷  其三','李若水','宋','宋诗','song-poetry','','[]','破扇委高壁，病骨蘇微凉。',48,'全唐诗/poet.song.103000.json','["破扇委高壁，病骨蘇微凉。", "羅階竹千挺，秀質頎而長。", "呼奴約疏箔，窗几延翠光。", "欠伸睡稍足，夕影上東牆。"]'),
('77da60cd-11c7-4937-a1d1-7de7e7f11fc0','秋懷  其四','李若水','宋','宋诗','song-poetry','','[]','疏筠易秋威，冉冉受風雨。',48,'全唐诗/poet.song.103000.json','["疏筠易秋威，冉冉受風雨。", "芙蕖抱枯香，頳顔羞不遇。", "草木自衰榮，歲月誰寒暑。", "老人岸烏紗，清坐閱今古。"]'),
('f8e67d49-ee31-42f8-bdb9-0dc7ba0ea79a','秋懷  其五','李若水','宋','宋诗','song-poetry','','[]','風高天宇寒，朝來幾鴻過。',48,'全唐诗/poet.song.103000.json','["風高天宇寒，朝來幾鴻過。", "長鋏訴新懷，短檠續舊課。", "霜梧觸階稜，鏗然警癡坐。", "吾髮半已白，功名况么麽。"]'),
('82ada18f-c2e8-40a1-8db6-fbc670c018f2','秋懷  其六','李若水','宋','宋诗','song-poetry','','[]','風細雲動鱗，雨餘山弄姿。',48,'全唐诗/poet.song.103000.json','["風細雲動鱗，雨餘山弄姿。", "淵明短籬下，漸覺秋芳萎。", "歲華任自老，酒杯亦須持。", "種種愧古人，此段差可期。"]'),
('8a68ff83-ec75-47fa-9328-cdf090897c2f','秋懷  其七','李若水','宋','宋诗','song-poetry','','[]','楚客賦秋風，表表千載師。',48,'全唐诗/poet.song.103000.json','["楚客賦秋風，表表千載師。", "衙官生惡謗，此語將誰欺。", "我欲踐逸軌，每苦抽思遲。", "譬彼款段足，焉能馳險巇。"]'),
('402628dd-c488-40ca-8fa5-7af268877d16','秋懷  其八','李若水','宋','宋诗','song-poetry','','[]','今古等朝暮，宇宙同咫尺。',48,'全唐诗/poet.song.103000.json','["今古等朝暮，宇宙同咫尺。", "安得坐忘人，相從遊八極。", "神仙六鰲背，富貴一蟬翼。", "君其儻悟此，在在獲所適。"]'),
('b007d8cf-82fc-4036-98b3-da0a14a33b8b','蓬萊行','李若水','宋','宋诗','song-poetry','','[]','君是神仙人，應識蓬萊路。',152,'全唐诗/poet.song.103000.json','["君是神仙人，應識蓬萊路。", "願將塵土客，共向蓬萊去。", "蓬萊高高東海東，煙波渺渺鞭飛龍。", "窗間棋罷一笑許，扶桑倒影千度紅。", "刀圭絳雪從君得，天風泠泠吹兩腋。", "竊桃小兒竟安在，乘駿天人何處覓。", "尚聞金母呼衆靈，瑶池夜晏千雲軿。", "金檛玉斧散光景，鳳歌鸞舞流芳馨。", "低頭再拜謝君力，謝君洗我塵土腥。", "千歲還家作鶴語，朝市不知人姓丁。"]'),
('44f3cd0e-4f7f-46da-8953-34b50ad0c280','次顔博士遊紫羅洞五首  其一','李若水','宋','宋诗','song-poetry','','[]','愛君秀句輕封侯，恨不捧杖從君遊。',128,'全唐诗/poet.song.103000.json','["愛君秀句輕封侯，恨不捧杖從君遊。", "高人豈合世間著，紫羅洞邊能少留。", "我今癡坐數椽底，飽閱炎凉祇如此。", "何當一葉弄雲濤，鷗鳥請盟波影裏。", "顔郎才思天下無，亦與我輩同朝晡。", "故鄉蕭疏不堪說，秋風落日號羣狐。", "百年駸駸行且樂，不必華堂圍繡幕。", "爛醉出門霜月孤，荷鍤休隨任填壑。"]'),
('d287db90-8074-4cb5-ac9c-19335e814c5f','次顔博士遊紫羅洞五首  其二','李若水','宋','宋诗','song-poetry','','[]','長藤呵路多公侯，我輩不應來宦遊。',128,'全唐诗/poet.song.103000.json','["長藤呵路多公侯，我輩不應來宦遊。", "平生流涎向雲水，此心已往形獨留。", "黄沙霏霏烏帽底，三載長安飽嘗此。", "何如閑把一莖絲，坐釣澄江月明裏。", "採芝仙人今豈無，踏遍山腰日已晡。", "白雲可衣蘭可佩，禦寒不必思豐狐。", "人生此段差可樂，風御徑須遊六幕。", "夜深何處鳳簫聲，留得餘音傳萬壑。"]'),
('65e95510-fa5d-43c7-b61b-0c0617ae676f','次顔博士遊紫羅洞五首  其三','李若水','宋','宋诗','song-poetry','','[]','休著青衫謁五侯，徑覓拄杖山中遊。',128,'全唐诗/poet.song.103000.json','["休著青衫謁五侯，徑覓拄杖山中遊。", "故山別來鬢毛禿，一飽累人成久留。", "碧嶂巉巉雲影底，儻得破茅甘老此。", "孤猿野鶴舊時聲，却到主人清夢裏。", "囊中試檢一錢無，但吟秀句忘朝晡。", "子夜沈沈甕無蟻，秋風策策裘非狐。", "得遂清閑貧亦樂，矯首飛鴻度天幕。", "隔溪應復有幽人，踏月相從嘯林壑。"]'),
('5da9e3e2-15c1-4c86-af6f-b8bc50c405a0','次顔博士遊紫羅洞五首  其四','李若水','宋','宋诗','song-poetry','','[]','自憐無骨可封侯，漫來學省陪英遊。',128,'全唐诗/poet.song.103000.json','["自憐無骨可封侯，漫來學省陪英遊。", "逸興未忘河朔飲，羈蹤已分周南留。", "久負雲山竟緣底，百指饑寒良坐此。", "鬢毛蒼蒼已難揀，何時却到雲山裏。", "休問歸囊金有無，采芝酌水延朝晡。", "未要學仙跨威鳳，况肯作詩嘲訓狐。", "藜杖芒鞋樂復樂，老藤懸花當羅幕。", "月明須上最高峯，橫竹一聲秋萬壑。"]'),
('f84c3c8d-5d48-4256-9329-47b1e8baa487','次顔博士遊紫羅洞五首  其五','李若水','宋','宋诗','song-poetry','','[]','金印如斗封王侯，何如爛漫江南遊。',128,'全唐诗/poet.song.103000.json','["金印如斗封王侯，何如爛漫江南遊。", "山能不老閱今古，雲自無心忘去留。", "我似孤松蟠澗底，斤斧之餘流落此。", "輕便却羨無根蓬，隨風直上青霄裏。", "壺中變態何所無，色色略同朝與晡。", "千里飛蠅政緣驥，百獸畏虎元非狐。", "置是休論且行樂，明月張燈天展幕。", "更持北斗𣂏酒泉，澆我胸中萬邱壑。"]'),
('f44e7ba3-74ba-4074-8604-a8c1937a4eb0','謝人惠魚兔蟹','李若水','宋','宋诗','song-poetry','','[]','昔時藜莧田隴頭，近時虀鹽學舍裏。',243,'全唐诗/poet.song.103000.json','["昔時藜莧田隴頭，近時虀鹽學舍裏。", "腹不成癭腸有雷，何郎萬錢其敢企。", "當年守株披褐衣，亦嘗臨淵羨赬尾。", "餘力種黍延霜螯，計拙謀粗何足紀。", "罷官三月突無煙，兩親白頭欠甘旨。", "此身分爲饑所驅，旋秣羸驂訴知己。", "蓬萊高人愛詩客，邀坐綠齋嘗玉蟻。", "敢嫌寸祿消息遲，數品珍羞供一喜。", "秦丞相追上蔡遊，張步兵對秋風起。", "盜鄰吏部手持杯，三子風流未當鄙。", "還家掃甑洗刀砧，大飫老饕沾婢使。", "邇來送米鄰無僧，長是覆羹窮有鬼。", "區區一飽豈易得，何時檳榔澡吾耻。", "君不見魯公從人乞鹿脯，留得銀鉤照千祀。", "猶勝金馬避世人，九尺長身饑欲死。"]'),
('af6c9f1a-0bf6-4f82-ab16-5269b4a82538','贈疊山老匠','李若水','宋','宋诗','song-poetry','','[]','山翁七十頭如雪，胸中泰華巧盤折。',96,'全唐诗/poet.song.103000.json','["山翁七十頭如雪，胸中泰華巧盤折。", "平生兩手展不盡，臨老更欲矜奇絕。", "吾家有堂面危壁，衮衮黄埃眼界窄。", "呼來摶沙淺拂黛，倏驚突出千峯碧。", "倚藜矯首一長吟，蕭然徑與人寰隔。", "何當諱姓吳門去，踏遍東南萬山春。"]'),
('2627334a-b7ff-4bfd-84b5-495d18dd5717','送唐彥英','李若水','宋','宋诗','song-poetry','','[]','一鞭行色黄榆路，望斷遥天垂地處。',32,'全唐诗/poet.song.103000.json','["一鞭行色黄榆路，望斷遥天垂地處。", "嗚嗚流水如有情，瀉我離愁向東去。"]'),
('c7607deb-e754-43aa-b42f-86944a3c66e6','竹宮長句','李若水','宋','宋诗','song-poetry','','[]','斷雲托月天南東，夢魂初下蓬萊峯。',160,'全唐诗/poet.song.103000.json','["斷雲托月天南東，夢魂初下蓬萊峯。", "繞街敲金戒天曉，烏帽遡凉奔竹宮。", "神明之囿嚴且邃，踵門已覺塵凡空。", "溫溫妙友隔窗語，徐徐好日當庭紅。", "案頭書帙萬卷富，門外簾影三秋風。", "東家所慎蓋先此，小人曷敢不精衷。", "緋衣贊者趣行事，升降拜起莊微躬。", "丁東環佩衆泉咽，熒煌星斗千炬烘。", "瘦羊端笑古人細，肥馬暫逐兒曹雄。", "指日欃槍落天外，告廟還看禮更豐。"]'),
('cf3a8273-f4ff-4f98-9964-82191bc9430a','村婦謠','李若水','宋','宋诗','song-poetry','','[]','村婦相將入城去，呵之不止問其故。',64,'全唐诗/poet.song.103000.json','["村婦相將入城去，呵之不止問其故。", "我聞官中新糶米，比似民間較錢數。", "常平常平法甚良，先帝惠澤隆陶唐。", "願爾官吏且勤守，無使斯民流異方。"]'),
('1c004684-8a70-40af-8e8a-f7bc9011406a','伐桑歎','李若水','宋','宋诗','song-poetry','','[]','村家愛桑如愛兒，問爾伐此將何爲。',64,'全唐诗/poet.song.103000.json','["村家愛桑如愛兒，問爾伐此將何爲。", "幾年年荒欠官債，賣薪輸賦免鞭笞。", "來春葉子應不惡，鄰家宜蠶有衣著。", "我獨凍坐還歔欷，長官打人血流地。"]'),
('bbc463b9-6ebf-40fe-a569-413923cc04b9','春日途中','李若水','宋','宋诗','song-poetry','','[]','詩書學郎風騷客，奚奴控馬黄塵陌。',64,'全唐诗/poet.song.103000.json','["詩書學郎風騷客，奚奴控馬黄塵陌。", "頹陽半嶺促歸鴉，斷雲無意橫山碧。", "樹頭白塔孤城小，東風幾度行人老。", "夾路桃花春雨餘，落紅萬點無人掃。"]'),
('64fa2483-367e-4050-9d1d-626aa7eafb5f','村家引','李若水','宋','宋诗','song-poetry','','[]','村翁七十倚柴扉，手障夕陽望牧兒。',64,'全唐诗/poet.song.103000.json','["村翁七十倚柴扉，手障夕陽望牧兒。", "牧兒歸來問牛飽，屋東幾畝田未犂。", "鄰老相邀趁秋社，神巫簫鼓歡連夜。", "明年還似今年熟，更拚醉倒籬根下。"]'),
('b5088ae5-5b92-4799-9e3a-c076eda3e158','贈陳承務','李若水','宋','宋诗','song-poetry','','[]','白馬津北千里疆，郡縣交錯旗布方。',384,'全唐诗/poet.song.103000.json','["白馬津北千里疆，郡縣交錯旗布方。", "廣平僻峙黄流旁，蓄兵萬指紅滿倉。", "守將恃才政弗臧，公掊私取貪如狼。", "扼兵之喉奪其糧，掊克帑藏資晏荒。", "羣兇叫呶計則狂，敢以寸草驕太陽。", "遂擁鷙猛爲主張，遂嚴統押分隊行。", "遂排武庫擇刃鋩，絳巾繡裳馬龍驤。", "縻執守將如驅羊，面疏隱惡衆踣傷。", "傳呼戒關戍城隍，枚計豪戶恣劫攘。", "金珠之餘重弗將，老稚踐蹂紛驚惶。", "潛掛巨索投壕牆，小斯流血大仆僵。", "或坐暗室遮屏床，或走曲巷雜病尪。", "九重聞之駭非常，急詔將士趨衡漳。", "鯨奔虎吼未就韁，擇肉而食誰敢當。", "陳侯半世耽文章，再隨計吏觀國光。", "才則有餘命不償，時吐憤氣干穹蒼。", "古人一言靖猾强，牋簡萬世名飛揚。", "誰能幽窗勘鉛黄，俯與羣蟻爭毫芒。", "乃袖空手赴賊場，吾有寸舌充劍槍。", "剖析禍福聲琅琅，儻昏不從死亦昌。", "輦錢五萬倡厥鄉，少頃倚疊平山岡。", "徽長鉤大餌鮮香，彼其喁喁果爭嘗。", "戢牙伏爪威弭藏，再拜稱謝君策良。", "徑取渠帥衆共戕，氛霾卷剝清風颺。"]'),
('ce426d8c-9462-441a-ab9d-b322eea98219','農夫歎','李若水','宋','宋诗','song-poetry','','[]','傷哉野老村下居，瘠田幾畝聊自鉏。',64,'全唐诗/poet.song.103000.json','["傷哉野老村下居，瘠田幾畝聊自鉏。", "卒歲辛勤輸稅外，倒囷試量無斗儲。", "牽衣索飯兒啼苦，婦姑相將挑葉煮。", "携家趁食奔四方，拚却餓死官路旁。"]'),
('2c3ca5e9-d7bd-440b-9e1e-5a1ecdbcc480','醉中偶題','李若水','宋','宋诗','song-poetry','','[]','小人拙直頗近真，放論動取兒曹嗔。',32,'全唐诗/poet.song.103000.json','["小人拙直頗近真，放論動取兒曹嗔。", "何似飲醇澆舌本，醉來卧唱江南春。"]'),
('6ca25aae-0451-41f0-a518-63d6d3524df6','徐太宰生日','李若水','宋','宋诗','song-poetry','','[]','潭潭相府開日邊，瑞光錯落勝非煙。',384,'全唐诗/poet.song.103000.json','["潭潭相府開日邊，瑞光錯落勝非煙。", "珊鞭皂帽千騎聯，袖中各有崧高篇。", "惟公妙年少比肩，筆底詞藻爭春妍。", "千佛經上名高懸，層霄未許孤鴻鶱。", "牛刀稍奏驚九天，召對紫殿席爲前。", "舌本治道如湧泉，重瞳屢矚眷予偏。", "駸駸臺省難淹延，徑躋政府持論堅。", "彼姦不容外蕃宣，寺人炎炎國柄專。", "力嘗抗之甘下遷，吾道不行乃命邅。", "豈能俯首學阿諞，青雲斜飛二十年。", "皇家累聖寶籙傳，太平推在商周先。", "金人穹帳鄰幽燕，覘我弛備紛振鞭。", "長驅近甸羅戈鋋，赤子枕藉吁可憐。", "肉食者鄙議拘攣，金帛寶玩平山巔。", "併割三鎮充垂涎，縣官聰明新位乾。", "搜舉真相窮八埏，公鎮北門惠化沿。", "左右國人皆曰賢，賜環歸來胡不遄。", "父老泣把衣裙牽，白麻疏詔光台躔。", "挈提宇宙歸陶甄，西北兩路尚控弦。", "雖有盟好數棄捐，民貧到骨瘼未痊。", "宿弊如毛費除蠲，仁祖良規人所便。", "熙豐法誤今判然，斡旋鴻鈞須至權。", "規規小手徒自纏，昔欲裕民反招愆。", "茲其時矣盍勉旃，無使治行專潁川。"]'),
('255cb373-d094-49a1-809d-6ed67c039b74','開德天王臺詩','李若水','宋','宋诗','song-poetry','','["\u897f\u6e56"]','還家十日坐井底，北風吹我上高臺。',160,'全唐诗/poet.song.103000.json','["還家十日坐井底，北風吹我上高臺。", "亭亭寒日光彩薄，幕空雲影低徘徊。", "半折老木卧崖腹，銜枯野鵲時到來。", "沙飛客眼展不盡，雉樓向我爭崔嵬。", "故人天涯雲水隔，童背酒壺聊自開。", "胸中疊砢澆不下，旁人已嘲紅滿腮。", "西湖百步水作界，北城萬瓦煙成堆。", "十年黄土涴雙足，把筇今日踏霜苔。", "登高能賦我輩事，莫惜淡墨留牆隈。", "後日重來拂石坐，山陰陳迹空自哀。"]'),
('b813ca3a-178e-49cd-8897-6e25fa998464','謝劉德謙惠疊翠峰詩','李若水','宋','宋诗','song-poetry','','[]','我聞劉綱古仙子，此郎無乃渠耳孫。',160,'全唐诗/poet.song.103000.json','["我聞劉綱古仙子，此郎無乃渠耳孫。", "平生邱壑有真趣，脫口誤與兒輩論。", "杖藜乘興繞山腹，撥碎松影尋雲根。", "一拳疏翠萬巒足，見之驚喜雙頰溫。", "挈來珍護等完璧，浸以清泚供金盆。", "窗前細看坐忘食，冷碧尚带煙嵐痕。", "斗量明珠問君買，刮我十年塵眼昏。", "莫學衛公作癡計，苛戒直欲傳後昆。", "高懷脫落萬事細，一笑付余無吝言。", "手捫心玩挽歸興，夜來清夢驚哀猿。"]'),
('c36e5151-b049-4c85-b1e2-ab21961581d0','歸家','李若水','宋','宋诗','song-poetry','','[]','隴頭一片白雲飛，僕乎束裝吾欲歸。',64,'全唐诗/poet.song.103000.json','["隴頭一片白雲飛，僕乎束裝吾欲歸。", "故人故人莫强挽，篋中流塵昏淚衣。", "淚衣雖昏尚堪著，庭前兒戲慈顔樂。", "官高如天印如斗，問君此樂應還有。"]'),
('3fcc63fe-a69e-4027-93c2-164314990ac0','夜坐瓶忽成韻作詩記之','李若水','宋','宋诗','song-poetry','','[]','虛堂夜坐燈微明，家無婢子誰學笙。',128,'全唐诗/poet.song.103000.json','["虛堂夜坐燈微明，家無婢子誰學笙。", "徐而得之笑絕倒，數杴爐火圍短罌。", "君勢炎炎方得計，緣底不平爲此鳴。", "詩人耳冷教坊樂，蟲歌蛙吹聊娛情。", "天公有意慰酸冷，勺水便成鸞鳳聲。", "抽牽狂緒挽不斷，呼兒漉酒飛銀觥。", "須臾火盡竟何有，枕書酣卧衰顔頳。", "尚疑魂夢带餘想，齁齁鼻息旁人驚。"]'),
('f71782f5-5e2b-4c4c-b834-f5839a6a5655','捕盜偶成','李若水','宋','宋诗','song-poetry','','[]','去年宋江起山東，白晝橫戈犯城郭。',160,'全唐诗/poet.song.103000.json','["去年宋江起山東，白晝橫戈犯城郭。", "殺人紛紛翦草如，九重聞之慘不樂。", "大書黄紙飛敕來，三十六人同拜爵。", "獰卒肥驂意氣驕，士女駢觀猶駭愕。", "今年楊江起河北，戰陣規繩視前作。", "嗷嗷赤子陰有言，又願官家早招却。", "我聞官職要與賢，輒啗此曹無乃錯。", "招降况亦非上策，政誘潛兇嗣爲虐。", "不如下詔省科繇，彼自歸來守條約。", "小臣無路捫高天，安得狂詞裨廟略。"]'),
('0dc6cb72-2c3d-4331-b16b-53d497345223','題趙進夫勝軒詩','李若水','宋','宋诗','song-poetry','','[]','山色堆藍重，水光拖練寒。',24,'全唐诗/poet.song.103000.json','["山色堆藍重，水光拖練寒。", "主人看不足，終日憑欄干。"]'),
('e38bc292-cff3-4ba0-9fe5-944f2fdcef7a','震山巖','李若水','宋','宋诗','song-poetry','','[]','翠石黏雲濕，寒巖带蘚深。',48,'全唐诗/poet.song.103000.json','["翠石黏雲濕，寒巖带蘚深。", "樹函懷古意，水印讀書心。", "經濟神猶在，幽棲逕可尋。", "青氈吾舊物，稅駕卧山陰。"]'),
('b2e04ef6-0768-43f0-af05-e0932265f6bb','博士舉陳東秀才雪詩云已成堆積勢應費掃除功句甚佳惜不見其全數日雪作無事輒用其韻','李若水','宋','宋诗','song-poetry','','[]','寒意連朝進，祥霙萬里通。',48,'全唐诗/poet.song.103000.json','["寒意連朝進，祥霙萬里通。", "潔身原有道，潤物又成功。", "餘靄猶吞日，狂飆漫走空。", "田翁鉤膝語，貧裏幸年豐。"]'),
('e6fc1bd5-d2b4-4e85-9512-74c34848d612','送行','李若水','宋','宋诗','song-poetry','','[]','去意浮長汴，離懷詠曉燈。',48,'全唐诗/poet.song.103000.json','["去意浮長汴，離懷詠曉燈。", "明時非不遇，幽黜坐無能。", "歲月驚雙鬢，林泉許曲肱。", "從今藏羽翼，敢復覬飛騰。"]'),
('2c8bbb6b-4dd9-48b5-b4e2-5f0ab75c7200','種荔枝核有感','李若水','宋','宋诗','song-poetry','','[]','荔子欲傳種，他年養老饕。',48,'全唐诗/poet.song.103000.json','["荔子欲傳種，他年養老饕。", "試將千顆植，已喜寸萌高。", "豈耐雪霜苦，空慚澆灌勞。", "何殊茂陵客，藏核種蟠桃。"]'),
('409af3fa-4d68-41c6-ae77-670d4810e8b1','別向德深','李若水','宋','宋诗','song-poetry','','[]','歲晚霜風勁，束裝千里行。',48,'全唐诗/poet.song.103000.json','["歲晚霜風勁，束裝千里行。", "別離交義重，老大宦情輕。", "歧路共人遠，關山空月明。", "旗亭有濁酒，揮淚與君傾。"]'),
('b52c3c37-7530-4285-86a6-d1eb9a646a62','次韻高子文留別','李若水','宋','宋诗','song-poetry','','[]','之子欲西笑，我懷難具陳。',48,'全唐诗/poet.song.103000.json','["之子欲西笑，我懷難具陳。", "從來妙風雅，此去脫埃塵。", "擬倩杯中物，暫留燈下人。", "可堪分手處，月色半林新。"]'),
('1a3af3e9-880a-4577-8e55-0d9d68739981','途中','李若水','宋','宋诗','song-poetry','','[]','馬足疲長路，林端霽色開。',48,'全唐诗/poet.song.103000.json','["馬足疲長路，林端霽色開。", "客程經十驛，村酒只三杯。", "病葉迎秋落，疏雲送雨回。", "何當旋故里，趁日坐牆隈。"]'),
('73298686-a17a-4a90-af67-ba6d553f56c6','次韻高子文秋盡懷歸','李若水','宋','宋诗','song-poetry','','[]','把酒送秋去，此懷難具陳。',48,'全唐诗/poet.song.103000.json','["把酒送秋去，此懷難具陳。", "十年江海夢，一几簿書塵。", "自歎栖栖者，誰憐落落人。", "淵明歸思切，籬菊带霜新。"]'),
('e76119c8-cc9a-40d8-b22a-6f622ddfe9c2','太行道中','李若水','宋','宋诗','song-poetry','','[]','千山倚奇峭，十日寄登臨。',48,'全唐诗/poet.song.103000.json','["千山倚奇峭，十日寄登臨。", "宇宙蜂房小，功名虎穴深。", "詩多馬上得，家只夢中尋。", "頭白雙親健，飄零寸草心。"]'),
('4404a495-da38-4be0-997e-d40383fd78e2','次韻李嗣表夜坐','李若水','宋','宋诗','song-poetry','','[]','霜梧一葉落，塵鬢幾莖秋。',48,'全唐诗/poet.song.103000.json','["霜梧一葉落，塵鬢幾莖秋。", "夜久燈仍暗，人閒室自幽。", "文書遮眼具，仕宦活身謀。", "此話有誰領，寸心橫百憂。"]'),
('9b7864ad-168d-4b6a-92b0-35b991b2ff68','次韻高子文村居','李若水','宋','宋诗','song-poetry','','[]','幽人厭城市，結屋近松蘿。',48,'全唐诗/poet.song.103000.json','["幽人厭城市，結屋近松蘿。", "一笛秋風急，千岩晚照多。", "竹根鄰叟醉，牛背牧兒歌。", "笑殺青雲友，朝紳換短蓑。"]'),
('d5aa99a9-25a0-4b29-9b36-f4c2f30abf29','次韻宋周臣留別','李若水','宋','宋诗','song-poetry','','[]','行旌此去隔關山，頓覺幽齋笑語闌。',32,'全唐诗/poet.song.103000.json','["行旌此去隔關山，頓覺幽齋笑語闌。", "後夜月明空似水，孤桐橫膝向誰彈。"]'),
('1604d38c-95f5-42c6-bb1b-130d827eb5d0','秋日書齋','李若水','宋','宋诗','song-poetry','','[]','晝閑人靜睡相尋，幽鳥時時薦好音。',32,'全唐诗/poet.song.103000.json','["晝閑人靜睡相尋，幽鳥時時薦好音。", "喚起新秋一襟恨，南窗摇膝費孤吟。"]'),
('dc0faa13-2870-4d59-b810-9767d56bc03f','夜坐','李若水','宋','宋诗','song-poetry','','[]','暮凉浮座暑光微，竹底風來暗舉衣。',32,'全唐诗/poet.song.103000.json','["暮凉浮座暑光微，竹底風來暗舉衣。", "假寐不知清夜久，掛檐星斗向人稀。"]'),
('652ad3c4-027d-43dd-a2a5-5c8628477d6c','春日郊外  其一','李若水','宋','宋诗','song-poetry','','[]','毿毿官柳綠藏鴉，傍郭人煙三五家。',32,'全唐诗/poet.song.103000.json','["毿毿官柳綠藏鴉，傍郭人煙三五家。", "見說今年寒食好，踏青歸路看梨花。"]'),
('2e872c40-b3bc-4e87-a898-ec22d5009363','春日郊外  其二','李若水','宋','宋诗','song-poetry','','[]','誰家臨水亞朱扉，樓外風閑柳線垂。',32,'全唐诗/poet.song.103000.json','["誰家臨水亞朱扉，樓外風閑柳線垂。", "昨夜濛濛春雨小，杏花開到背陰枝。"]'),
('03497eb5-0fba-4c8e-8282-265f484b4409','次韻高子文','李若水','宋','宋诗','song-poetry','','[]','歸計茫然殊未涯，倦遊日久似無家。',32,'全唐诗/poet.song.103000.json','["歸計茫然殊未涯，倦遊日久似無家。", "十年燈火有何效，贏得眼前生眩花。"]'),
('6eb1cc6e-34a2-43f7-9f27-b1560c04a7a2','用張濟川所舉詩韻漫作','李若水','宋','宋诗','song-poetry','','[]','經霜落葉金堆地，過雨奇峯碧滿門。',32,'全唐诗/poet.song.103000.json','["經霜落葉金堆地，過雨奇峯碧滿門。", "要識豐年在何處，牧兒橫笛下煙村。"]'),
('2bcb5a00-7807-45b7-8a42-6f6363e9f427','次韻王深之二首  其一','李若水','宋','宋诗','song-poetry','','[]','事縱未涯心已老，山雖許遠夢能歸。',32,'全唐诗/poet.song.103000.json','["事縱未涯心已老，山雖許遠夢能歸。", "團蒲穩坐亦不惡，捫虱工夫趁早暉。"]'),
('6007ab69-5d00-41d4-9875-66a166d1caa7','次韻王深之二首  其二','李若水','宋','宋诗','song-poetry','','[]','酒薄僅能浮頰赤，燈寒故意學山青。',32,'全唐诗/poet.song.103000.json','["酒薄僅能浮頰赤，燈寒故意學山青。", "新來鼻觀無遮礙，覺得功名一味腥。"]'),
('9d5eb98b-ea96-428e-97f4-888b2e6eb773','次韻張濟川二首  其一','李若水','宋','宋诗','song-poetry','','[]','澗底戰骸霜雪枯，籠煙萬瓦半荒墟。',32,'全唐诗/poet.song.103000.json','["澗底戰骸霜雪枯，籠煙萬瓦半荒墟。", "流離赤子馬前泣，爭問九重知也無。"]'),
('b9c733d8-0d1b-47d8-ad94-638adceaab36','次韻張濟川二首  其二','李若水','宋','宋诗','song-poetry','','[]','父老霑襟訟不平，千岩鬼哭亂泉聲。',32,'全唐诗/poet.song.103000.json','["父老霑襟訟不平，千岩鬼哭亂泉聲。", "烏鳶誤飽忠義肉，點檢戰功誰眼明。"]'),
('a9f3702c-972d-4275-96b8-37c035a7f75e','喜雪','李若水','宋','宋诗','song-poetry','','[]','皇家有道歲不惡，雪花如絮千里飛。',32,'全唐诗/poet.song.103000.json','["皇家有道歲不惡，雪花如絮千里飛。", "老農誇殺麥本綠，一杯湯餅令汝肥。"]'),
('30786b54-75e2-4b47-955b-2d53293b95a4','次韻公實兄途中','李若水','宋','宋诗','song-poetry','','[]','斷雲橫碧暗平野，落照曳紅明遠村。',32,'全唐诗/poet.song.103000.json','["斷雲橫碧暗平野，落照曳紅明遠村。", "回首半天雲破處，一眉新月報黄昏。"]'),
('765e9ebe-d02a-46a4-a90d-8aff5a2e2a20','從趙彥特求茶','李若水','宋','宋诗','song-poetry','','[]','飯餘日影轉修廊，欹枕桐花墮小窗。',32,'全唐诗/poet.song.103000.json','["飯餘日影轉修廊，欹枕桐花墮小窗。", "爲覓春風洗殘夢，要令詩思敵澄江。"]'),
('56bcdc9f-7e2b-4620-b59d-86ca84ebe3fa','西遊','李若水','宋','宋诗','song-poetry','','[]','綠暗紅疏春事休，此身孑孑又西遊。',32,'全唐诗/poet.song.103000.json','["綠暗紅疏春事休，此身孑孑又西遊。", "不堪回首斜陽外，一片黄雲萬古愁。"]'),
('746be8bc-bcb3-49dd-9bce-38ad596601c3','次韻馬循道春懷','李若水','宋','宋诗','song-poetry','','[]','何郎風味梅花瘦，楚客孤高蕙草芳。',32,'全唐诗/poet.song.103000.json','["何郎風味梅花瘦，楚客孤高蕙草芳。", "二子寥寥去人遠，一編青竹姓名香。"]'),
('a9a04a3d-b320-487e-835d-9c650b5d5587','次韻倪巨濟春懷  其一','李若水','宋','宋诗','song-poetry','','[]','青衫一領縛閑身，飽識官街肥馬塵。',32,'全唐诗/poet.song.103000.json','["青衫一領縛閑身，飽識官街肥馬塵。", "昨日友生雙鯉至，怪人不憶故溪春。"]'),
('fdead9c1-9f80-4856-a2a6-3f5cb2a2e9a0','次韻倪巨濟春懷  其二','李若水','宋','宋诗','song-poetry','','[]','近郭一廛殊未涯，不堪眼底又春華。',32,'全唐诗/poet.song.103000.json','["近郭一廛殊未涯，不堪眼底又春華。", "宦遊趁食負慚色，大似田頭拾粒鴉。"]'),
('b5b2a80b-03de-4e86-9746-9fa12434d285','江行值暴風雨','李若水','宋','宋诗','song-poetry','','[]','風狂雨暗舟人懼，自委神明志不邪。',32,'全唐诗/poet.song.103000.json','["風狂雨暗舟人懼，自委神明志不邪。", "投得葦灣波浪息，岸頭煙火近人家。"]'),
('fed59817-874f-4e8a-9b92-084306242520','次友人韻題墨梅  其一','李若水','宋','宋诗','song-poetry','','[]','南枝春色弄微溫，記得清香撲酒樽。',32,'全唐诗/poet.song.104000.json','["南枝春色弄微溫，記得清香撲酒樽。", "今日相逢隔煙霧，揚州殘夢足銷魂。"]'),
('6f2c5f1f-6b29-45c1-aaa1-6a25b850f71d','次友人韻題墨梅  其二','李若水','宋','宋诗','song-poetry','','[]','長愛孤標似君子，不禁橫竹巧擠排。',32,'全唐诗/poet.song.104000.json','["長愛孤標似君子，不禁橫竹巧擠排。", "短幅離離乃遺像，至今寒蝶誤飛來。"]'),
('6ec78f76-40e4-4731-8ad0-1cef01110865','題觀城驛壁','李若水','宋','宋诗','song-poetry','','[]','半篙寒碧秋垂釣，一笛疏風夜倚樓。',32,'全唐诗/poet.song.104000.json','["半篙寒碧秋垂釣，一笛疏風夜倚樓。", "多少巫山舊家事，老來分付與東流。"]'),
('349d6f57-d9ea-4b16-bdf8-4d6af6a23046','次韻舒伯源雪晴偶書四首  其一','李若水','宋','宋诗','song-poetry','','[]','朝陽飛影戰餘寒，樓上高人久屈蟠。',32,'全唐诗/poet.song.104000.json','["朝陽飛影戰餘寒，樓上高人久屈蟠。", "想見倚欄三盞後，醉橫詩眼與天寬。"]'),
('e70fdc0e-06df-4775-846a-c472c95eccdf','次韻舒伯源雪晴偶書四首  其二','李若水','宋','宋诗','song-poetry','','[]','化工錯玉滿京都，尚有癡雲似積酥。',32,'全唐诗/poet.song.104000.json','["化工錯玉滿京都，尚有癡雲似積酥。", "馬上官人凍顔赤，擁爐還羨老生無。"]'),
('5fe17202-5ad0-4278-a84e-836cb070d037','次韻舒伯源雪晴偶書四首  其三','李若水','宋','宋诗','song-poetry','','[]','雪意融融旋作泥，故山應是費攀躋。',32,'全唐诗/poet.song.104000.json','["雪意融融旋作泥，故山應是費攀躋。", "而今把笏謝樵子，馬踏御街聞曉雞。"]'),
('e728183b-6613-498e-b093-73c5edeb5600','次韻舒伯源雪晴偶書四首  其四','李若水','宋','宋诗','song-poetry','','[]','銀濤萬頃漲煙村，寂歷茅檐上曉暾。',32,'全唐诗/poet.song.104000.json','["銀濤萬頃漲煙村，寂歷茅檐上曉暾。", "春傲餘寒邀不住，夜來偷入杏花園。"]'),
('149d2013-8cd5-4930-9238-4b5e7114a115','雪後二首  其一','李若水','宋','宋诗','song-poetry','','[]','黄沙苦染鬢毛斑，乞得瓊瑰一寸慳。',32,'全唐诗/poet.song.104000.json','["黄沙苦染鬢毛斑，乞得瓊瑰一寸慳。", "徑欲南樓試鶴氅，拍天清氣月如環。"]'),
('6cca631b-70ef-4bb6-ad69-cdea3ba0710c','雪後二首  其二','李若水','宋','宋诗','song-poetry','','[]','玉霙著砌曉斑斑，天惜豐年特地慳。',32,'全唐诗/poet.song.104000.json','["玉霙著砌曉斑斑，天惜豐年特地慳。", "爽氣一屏山倚碧，冷光千疊水回環。"]'),
('2575e902-dc71-4b08-a42e-d14583e12859','睡覺','李若水','宋','宋诗','song-poetry','','[]','布衾紙帳餞殘冬，老眼俄驚曉日紅。',32,'全唐诗/poet.song.104000.json','["布衾紙帳餞殘冬，老眼俄驚曉日紅。", "好夢追尋忘首尾，但聞窗外竹摇風。"]'),
('d41a0bcb-7b61-4f3b-847c-9dc2939bf354','百井寨次高子文留題原韻','李若水','宋','宋诗','song-poetry','','[]','破籬殘屋是誰家，一片斜陽萬點鴉。',32,'全唐诗/poet.song.104000.json','["破籬殘屋是誰家，一片斜陽萬點鴉。", "駐馬岡頭無處問，漙漙清露濕黄花。"]'),
('e3d8dc27-e0a2-4145-9f82-4455034772ff','歸家','李若水','宋','宋诗','song-poetry','','[]','半載長安客意寒，一鞭歸興舊家山。',32,'全唐诗/poet.song.104000.json','["半載長安客意寒，一鞭歸興舊家山。", "妻孥問我成何事，買得虛名滿世間。"]'),
('08586ee3-889d-4d0f-b40c-67dc12d62e22','春日途中','李若水','宋','宋诗','song-poetry','','[]','一川晴日破春容，柳絮桃紅赴望中。',32,'全唐诗/poet.song.104000.json','["一川晴日破春容，柳絮桃紅赴望中。", "莫喜芳辰又來到，少年能耐幾東風。"]'),
('201b8ab5-1eac-4de4-88f2-4190244a1569','題畫扇','李若水','宋','宋诗','song-poetry','','[]','坡頭霜木秋半老，沙際水禽時一雙。',32,'全唐诗/poet.song.104000.json','["坡頭霜木秋半老，沙際水禽時一雙。", "乞我短篷歸去好，醉聽夜雨卧荒江。"]'),
('443e67d9-da2e-472a-8c5d-c5e4033b0f7c','次韻張濟川夜雪二首  其一','李若水','宋','宋诗','song-poetry','','[]','雪彩鱗鱗照夜徂，化工遊戲翦輕酥。',64,'全唐诗/poet.song.104000.json','["雪彩鱗鱗照夜徂，化工遊戲翦輕酥。", "竹聲摇破夢千里，蓬跡轉來天一隅。", "寒壓短檠花自落，風驚別浦雁相呼。", "平明携杖前溪去，誤入仙人白玉壺。"]'),
('e8d4d53f-7eab-4ddf-99af-64a7303c1f41','次韻張濟川夜雪二首  其二','李若水','宋','宋诗','song-poetry','','[]','天公應恐點瓊葩，先遣飛廉卷惡沙。',64,'全唐诗/poet.song.104000.json','["天公應恐點瓊葩，先遣飛廉卷惡沙。", "才短謬將身許國，歲寒還是客成家。", "故鄉親友馳清夢，老境文書眩碧花。", "須信玉妃儀衛肅，砌蛩庭鵲靜無譁。"]'),
('f04f5bca-7bb1-4dba-997a-d621251024df','次韻倪巨濟詩換怪石','李若水','宋','宋诗','song-poetry','','[]','紛紛兒輩只輕肥，不愛籠煙小黛眉。',64,'全唐诗/poet.song.104000.json','["紛紛兒輩只輕肥，不愛籠煙小黛眉。", "唯有幽人負高韻，爲憐奇物直新詩。", "塵埃不染溪山夢，冠蓋政妨麋鹿姿。", "何日茅檐列千嶂，倚藜細看碧參差。"]'),
('58e10b5e-f087-4e7c-9dee-fe619d6054ce','送宋周臣赴殿試','李若水','宋','宋诗','song-poetry','','[]','近侍傳呼到集英，參差宮殿曉霞明。',64,'全唐诗/poet.song.104000.json','["近侍傳呼到集英，參差宮殿曉霞明。", "丹墀日對三千字，雲翼風高九萬程。", "天子臨軒應動色，諸生閣筆總銷聲。", "臚傳指日承新渥，千佛名經第姓名。"]'),
('0a1f9a76-ba53-4058-aa79-e93f5026f994','寄題艾惠夫容膝軒詩','李若水','宋','宋诗','song-poetry','','[]','鄉人極口誇吾友，誇道新來葺妙居。',64,'全唐诗/poet.song.104000.json','["鄉人極口誇吾友，誇道新來葺妙居。", "東晉風流千載後，南窗瀟灑數椽餘。", "無腸可著猶貪酒，有眼能看肯廢書。", "記取魯人學柳下，不須辭米賦歸歟。"]'),
('b2625eea-6d17-413b-b387-90e4e01ef7cc','又次韻司空彥修送行','李若水','宋','宋诗','song-poetry','','[]','僕夫已飯車已巾，再拜別君愁始新。',64,'全唐诗/poet.song.104000.json','["僕夫已飯車已巾，再拜別君愁始新。", "一事未成雙鬢禿，百年能幾半生貧。", "雲山不斷駸駸暮，花柳無邊在在春。", "它日還家稍安穩，杖藜相過莫嫌頻。"]'),
('253b5a20-b956-4664-82fe-3eeacca0e70c','次韻馬循道遊長安東池詩','李若水','宋','宋诗','song-poetry','','[]','詩老逢人細細誇，一溪春色定能佳。',64,'全唐诗/poet.song.104000.json','["詩老逢人細細誇，一溪春色定能佳。", "東風無意秀芳草，野鳥不言銜落花。", "拍拍濃愁渾似酒，悠悠短夢不禁茶。", "接䍦倒著歸來晚，千古風流繼習家。"]'),
('b8cc6fca-9d6a-4483-90d7-6af7f5a2d6a6','次韻李元量見贈','李若水','宋','宋诗','song-poetry','','[]','先生學業自無雙，當代聞人共歎降。',64,'全唐诗/poet.song.104000.json','["先生學業自無雙，當代聞人共歎降。", "文采羨君高楚夢，詩聲笑我類吳江。", "槐花過雨金堆砌，山色經秋碧滿窗。", "一幅珠璣照塵眼，龍文端信筆能扛。"]'),
('2102f58b-0632-4ed0-b5ee-303670a0d165','送何文植趨京','李若水','宋','宋诗','song-poetry','','[]','問君何日赴神京，明日揚鞭數去程。',64,'全唐诗/poet.song.104000.json','["問君何日赴神京，明日揚鞭數去程。", "風雪一天行客恨，關山千里故人情。", "銅臺曾見三都賦，金闕行傳二陸名。", "自許孤高謝凡客，從今有酒對誰傾。"]'),
('89cab130-27cb-44c5-a4ae-c0cea359d59a','次韻高子文途中見寄','李若水','宋','宋诗','song-poetry','','[]','人生半在客途中，休著狂蹤比斷蓬。',64,'全唐诗/poet.song.104000.json','["人生半在客途中，休著狂蹤比斷蓬。", "別後夢煩莊叟蝶，邇來書誤子卿鴻。", "月同千里水雲隔，天各一涯談笑空。", "趁取重陽復詩社，要看紅葉醉西風。"]'),
('049901c7-4bcc-4def-a990-7900ef541038','次韻李子建懷歸','李若水','宋','宋诗','song-poetry','','[]','寸心已老自宜休，誤別雲山歲幾周。',64,'全唐诗/poet.song.104000.json','["寸心已老自宜休，誤別雲山歲幾周。", "疏遠驟依雙鳳闕，清貧僅剩一貂裘。", "與人不偶緣方鑿，於世無求類直鈎。", "何日張帆旋故國，坐呼明月醉江頭。"]'),
('318c7074-7316-45af-bf23-f0ba37ba7d52','書懷','李若水','宋','宋诗','song-poetry','','[]','戎馬南來久不歸，山河殘破一身微。',64,'全唐诗/poet.song.104000.json','["戎馬南來久不歸，山河殘破一身微。", "功名誤我等雲過，歲月驚人還雪飛。", "每事恐貽千古笑，此生甘與衆人違。", "艱難重繫君親念，血淚斑斑滿客衣。"]'),
('32d38999-78d5-4052-b6d4-777979797043','偶成','李若水','宋','宋诗','song-poetry','','[]','自憐疇昔抱癡頑，不慣黄埃日跨鞍。',64,'全唐诗/poet.song.104000.json','["自憐疇昔抱癡頑，不慣黄埃日跨鞍。", "荒徑露霑旗尾潤，幽窗塵鎖筆頭乾。", "半林殘照人煙晚，一笛秋風雁影寒。", "還有田園得歸去，誰能俯首縛微官。"]'),
('93029e78-bfc1-49a6-ac5e-af9c404ae44a','次韻張濟川雪','李若水','宋','宋诗','song-poetry','','[]','雲將剪水戲微茫，草木非春也自芳。',64,'全唐诗/poet.song.104000.json','["雲將剪水戲微茫，草木非春也自芳。", "坐上落來千片急，鬢間添得數絲長。", "氣淩詩骨牋毫健，味借茶甌齒頰香。", "久客天涯衣縫斷，夢魂合眼到親旁。"]'),
('1b107ca7-91d0-44ac-87fa-db898253bcb0','聞卞氏舊有怪石藏宅中問其遺孫指一廢井云盡在是矣井在室中床下不可得見乃賦此詩','李若水','宋','宋诗','song-poetry','','[]','昔人遊宦久江湖，怪石嵌空駭里閭。',64,'全唐诗/poet.song.104000.json','["昔人遊宦久江湖，怪石嵌空駭里閭。", "一井深藏緣底事，百年不出待潛夫。", "棄捐泥土性仍在，睥睨林亭氣漸蘇。", "微物廢興猶有定，此生窮達漫長吁。"]'),
('57fe5faa-736a-492c-9434-002ea3bdfc5a','與沈信翁對飲憶雍節夫高子文','李若水','宋','宋诗','song-poetry','','[]','北門昔日吾三友，今日樽前得一人。',64,'全唐诗/poet.song.104000.json','["北門昔日吾三友，今日樽前得一人。", "雍老滑稽垂白首，高郎文雅最青春。", "一飛小篆追秦相，兩吐新詩近楚臣。", "落落星辰各千里，請君休說恐傷神。"]'),
('5af425b7-8eb9-4f45-84bf-20c81c9c3bba','與諸公遊葆真宮','李若水','宋','宋诗','song-poetry','','[]','晏坐芸堂情太幽，仙家有地供閑遊。',64,'全唐诗/poet.song.104000.json','["晏坐芸堂情太幽，仙家有地供閑遊。", "冷官經月未嘗醉，好景向人那得愁。", "宮殿風清鶴翅冷，池塘水白荷花秋。", "尊前不樂定癡煞，明日簿書堆案頭。"]'),
('834680dc-650f-46c1-b73d-0d5318e949b1','秋懷','李若水','宋','宋诗','song-poetry','','[]','滿眼羈愁不可裁，西風樓閣獨持杯。',64,'全唐诗/poet.song.104000.json','["滿眼羈愁不可裁，西風樓閣獨持杯。", "一檠短夢尋家去，萬瓦新霜逐雁來。", "富貴未涯身半老，雲山何處首空回。", "呼兒滌硯酬佳句，試我胸中隱隱雷。"]'),
('3e8d3ed3-0063-4362-858f-b783cbb816a8','鐵冠道士寄書','李若水','宋','宋诗','song-poetry','','[]','金甲將軍傳好夢，鐵冠道士寄新書。',32,'全唐诗/poet.song.104000.json','["金甲將軍傳好夢，鐵冠道士寄新書。", "我與雲長隔異代，翻疑此事太荒虛。"]'),
('b8800f4e-35ab-4d1f-a3f0-71f1ee7ca45b','奉使太原途中呈王坦翁副使  其一','李若水','宋','宋诗','song-poetry','','[]','中山忠義定何人，數月相從笑語真。',64,'全唐诗/poet.song.104000.json','["中山忠義定何人，數月相從笑語真。", "未信功名孤壯志，不妨詩酒寄閑身。", "此來飽看千巖秀，歸去遥知兩鬢新。", "就使牧羊吾不恨，漢旄零落落花春。"]'),
('fcb24bc5-a1ae-425e-8fd5-62423374cafb','奉使太原途中呈王坦翁副使  其二','李若水','宋','宋诗','song-poetry','','[]','舊持漢節愧前人，聞許傳來若不真。',64,'全唐诗/poet.song.104000.json','["舊持漢節愧前人，聞許傳來若不真。", "五鼓促回千里夢，一官妨盡百年身。", "關山吐月程程遠，詩景含秋句句新。", "孤館可能忘客恨，脫巾聊進一杯春。"]'),
('6943753e-c99b-48d3-a61c-8e69eafa9def','上巳','李若水','宋','宋诗','song-poetry','','[]','小桃脫萼柳梢柔，春色無邊破客愁。',32,'全唐诗/poet.song.104000.json','["小桃脫萼柳梢柔，春色無邊破客愁。", "好與永和修故事，一時人物盡風流。"]'),
('fe52580c-c1ab-4249-bf17-9482daf00f89','村落','李若水','宋','宋诗','song-poetry','','[]','一笛秋風急，千巖晚照多。',24,'全唐诗/poet.song.104000.json','["一笛秋風急，千巖晚照多。", "竹根鄰叟醉，牛背牧兒歌。"]'),
('5e8d7969-4d4f-4067-9f67-d94dbb69b782','御筆免房錢一旬','李若水','宋','宋诗','song-poetry','','[]','風摇庭樹雲拍天，雪花亂拋如翦綿。',160,'全唐诗/poet.song.104000.json','["風摇庭樹雲拍天，雪花亂拋如翦綿。", "舉頭三日不見日，屋檐已欹街已填。", "富兒圍爐笑浮頰，坐繞笙歌飛酒船。", "儒生屈膝凍欲死，猶呵禿筆書長牋。", "詩成吟哦不知了，兒饑索飯厨無煙。", "太平君子萬民父，身居天上心民邊。", "重懷長安桂玉費，急飛宸翰蠲屋錢。", "門前賣報走如水，家家頂祝神霄仙。", "小人猶有負暄見，輕繇薄稅今當先。", "楚人得弓未爲大，願將此施均八埏。"]'),
('0c52c083-12f7-46fe-82f6-e2480d5edfde','迎親途中','李若水','宋','宋诗','song-poetry','','[]','久佇白雲下，茲晨慰所思。',48,'全唐诗/poet.song.104000.json','["久佇白雲下，茲晨慰所思。", "一鞭遊宦處，三釜及親時。", "宿雨開蔬甲，薰風卧麥旗。", "馬頭浮喜色，已被鵲先知。"]'),
('14ab4ad8-927d-4c08-9c1e-e70783a69f8b','贈捉殺官馬謹','李若水','宋','宋诗','song-poetry','','[]','伏波將種材無敵，高談指日期凌烟。',128,'全唐诗/poet.song.104000.json','["伏波將種材無敵，高談指日期凌烟。", "團花戰袍隨萬乘，胡爲落此荒塞邊。", "憲臺郎中忠報國，徑奏姓名丹扆前。", "聞道偷兒敢恣睢，怒髯森森張兩肩。", "三石强弓如屈肘，丈五長戈如弄鞭。", "指揮健兒誓死戰，酒酣一呼聲動天。", "霸陵醉尉苦短弱，大似燕雀逐鷹鸇。", "何當遇賊拭塵眼，看爾躍馬殘賊咽。"]'),
('8bb34a12-b533-4fe5-9d89-6f510c5fa14c','贈張墨卿','李若水','宋','宋诗','song-poetry','','[]','張侯自是風騷將，畫月裁雲三百篇。',128,'全唐诗/poet.song.104000.json','["張侯自是風騷將，畫月裁雲三百篇。", "玉堂未許代王綍，聊作漫尉黄河邊。", "綠林豪客玩國憲，探丸境上如鷹鸇。", "遣奴識天得秘策，一旦就戮逃無緣。", "霞旌霜刃鼓雷發，凱旋夾路人駢肩。", "元老聞之喜折屐，徑入奏章丹扆前。", "佇□黄紙飛敕來，金印如斗官九遷。", "莫笑書生太疲軟，時來亦許參凌烟。"]'),
('f0f86676-10d3-41bd-a4c7-dc3ff42f209b','寄宋周臣','李若水','宋','宋诗','song-poetry','','[]','盍簪當日話殷勤，便著金蘭較此心。',64,'全唐诗/poet.song.104000.json','["盍簪當日話殷勤，便著金蘭較此心。", "相去不堪千里遠，別來何况一年深。", "江山有路通幽夢，魚雁無情斷好音。", "管鮑貧交君記否，少陵曾爲發悲吟。"]'),
('4149ec1a-55e2-4732-a61f-7696ef26293e','寄敦夫弟','李若水','宋','宋诗','song-poetry','','[]','秋風秀庭槐，舉子勤朝課。',144,'全唐诗/poet.song.104000.json','["秋風秀庭槐，舉子勤朝課。", "丹詔日邊下，收攬不貲貨。", "小陸富才藻，振筆追楚些。", "朱絲有知音，白雪定寡和。", "銳氣壓同流，龍泉不容剉。", "芥視青紫榮，未語手先唾。", "我昔游詞場，一飛脫轗軻。", "咫尺看青霄，三年困巡邏。", "虛名損富貴，此生分寒餓。", "輸他阿買輩，官高金印大。", "造物端戲人，益知吾道左。", "願爾早著勳，替我雲山卧。"]'),
('305f0353-6670-4181-a8de-d8692d0e7cf7','秦會之題絕塵亭','李若水','宋','宋诗','song-poetry','','[]','脫迹塵囂外，悠然寄此亭。',48,'全唐诗/poet.song.104000.json','["脫迹塵囂外，悠然寄此亭。", "池平一鑑浄，山遠數螺青。", "身世驚殘夢，行藏忌獨醒。", "惟閑即近道，不必玩丹經。"]'),
('726598bd-ba76-4d6c-a8ea-5cec89c5034a','次韻唐彥英留題學舍','李若水','宋','宋诗','song-poetry','','[]','篆壁蝸涎細，織檐蛛網圓。',24,'全唐诗/poet.song.104000.json','["篆壁蝸涎細，織檐蛛網圓。", "小軒幽夢破，竹露濕茶煙。"]'),
('90d405d7-366b-4be6-bb54-ed32de8af8e5','登斂翠亭','李若水','宋','宋诗','song-poetry','','[]','佇立危亭醉眼寬，無邊秋色夕陽間。',32,'全唐诗/poet.song.104000.json','["佇立危亭醉眼寬，無邊秋色夕陽間。", "牧兒腰笛挽牛去，却放半川雲水閑。"]'),
('c685a081-040a-45af-8807-aadc92cfc76f','偶書','李若水','宋','宋诗','song-poetry','','[]','太原城角小軍營，兀坐何人肯見臨。',64,'全唐诗/poet.song.104000.json','["太原城角小軍營，兀坐何人肯見臨。", "半陰半晴天氣雜，一去一住客思深。", "功名未信終相負，歲月無端早見侵。", "好在床頭滿壺酒，勸君休約十分斟。"]'),
('64580851-84ff-4e3f-bdd2-2568d3df81bd','送李志全還鄉','李若水','宋','宋诗','song-poetry','','[]','半竿曉日明柳梢，飛沙瞇眼東風豪。',64,'全唐诗/poet.song.104000.json','["半竿曉日明柳梢，飛沙瞇眼東風豪。", "之子北歸顔色好，黄紙寫敕藍染袍。", "隻輪軋軋鳴長路，回首高岡隔煙霧。", "自憐不及路旁草，却解送君君到處。"]'),
('c2a6d574-9424-4eba-9191-1fe9971aeb50','送李無陂還鄉','李若水','宋','宋诗','song-poetry','','[]','休辭十驛犯埃塵，花柳無邊政可人。',32,'全唐诗/poet.song.104000.json','["休辭十驛犯埃塵，花柳無邊政可人。", "我坐宦囚歸未得，仗君說與古溪春。"]'),
('d08cdfe4-3eac-42b5-b7c2-275fd9f2b8b3','句  其一','李若水','宋','宋诗','song-poetry','','[]','東風無迹秀芳草，野鳥不言銜落花。',16,'全唐诗/poet.song.104000.json','["東風無迹秀芳草，野鳥不言銜落花。"]'),
('3bbf4a3d-921a-415f-9e7f-b0570f34cbdb','句  其二','李若水','宋','宋诗','song-poetry','','[]','一庭鳥跡天書怪，八尺簟紋人字寒。',16,'全唐诗/poet.song.104000.json','["一庭鳥跡天書怪，八尺簟紋人字寒。"]'),
('f2a76797-1d90-4d6c-960f-f4002ef90c1b','句  其三','李若水','宋','宋诗','song-poetry','','[]','蛩聲千里暮，雁影一天秋。',12,'全唐诗/poet.song.104000.json','["蛩聲千里暮，雁影一天秋。"]'),
('95738606-79e1-45a5-b6b0-f5a34092035d','句  其四','李若水','宋','宋诗','song-poetry','','[]','半軒開萬象，一水斷雙峰。',12,'全唐诗/poet.song.104000.json','["半軒開萬象，一水斷雙峰。"]'),
('3596089e-296a-4afe-a155-69bc466c9bd8','句  其五','李若水','宋','宋诗','song-poetry','','[]','功名今晚矣。',6,'全唐诗/poet.song.104000.json','["功名今晚矣。"]'),
('99a26882-5855-4af0-b84b-6b8381fe348c','句  其六','李若水','宋','宋诗','song-poetry','','[]','夜靜竹藏風。',6,'全唐诗/poet.song.104000.json','["夜靜竹藏風。"]'),
('37c2ef19-0169-4b32-8542-7d322a160dcf','句  其七','李若水','宋','宋诗','song-poetry','','[]','遠雁入空碧，孤舟浮淺清。',12,'全唐诗/poet.song.104000.json','["遠雁入空碧，孤舟浮淺清。"]'),
('af5645b7-256b-408f-b07a-84d2de0d0bfb','和呂叔恭題和州香林湯','王之道','宋','宋诗','song-poetry','','[]','新詩等絺繡，文采照座右。',288,'全唐诗/poet.song.104000.json','["新詩等絺繡，文采照座右。", "尤憐繼絕唱，峥嶸競高秀。", "詞源眉山長，句法杜陵舊。", "相從今老矣，豈獨歌邂逅。", "香林在何許，溢沸發巖竇。", "其流漸清温，脈助草木茂。", "歲旱添苗槁，一溉十倍收。", "追游記疇昔，我僕苦痛疚。", "别來隔兵火，荆榛挂猿狖。", "温温自然湯，蠲痾古非謬。", "我聞泉所發，江海遠相透。", "其温本硫黄，氣味自同臭。", "大哉無礙浴，天地不輕授。", "嚴霜與烈日，冬夏特異候。", "人生困凌薄，往往少中壽。", "飄飄澡雪力，狴犴忽蒙宥。", "春寒不喜出，塊坐撥殘槱。", "晦陰又連朔，夜雨屢通晝。", "誰能慰窮愁，邵州有賢守。", "開箧出大軸，令我和其後。", "此意重虚辱，勉彊忘固陋。", "呂侯卿相家，博學靡不究。", "會當似前人，嘉猷日告后。", "君看華清宮，誨淫似招寇。"]'),
('adebb35d-3c63-4f74-8659-113e16f954ea','和富公權送行詩韵','王之道','宋','宋诗','song-poetry','','[]','叨塵四十年，静計所得禄。',288,'全唐诗/poet.song.104000.json','["叨塵四十年，静計所得禄。", "十分才二三，清餓似饑鵠。", "中昨守義陽，一時苦窮促。", "忽聞柏臺長，表薦徹聰目。", "不惟免罪戾，英游許追逐。", "接武憲漕間，寒庖見粱肉。", "從兄逮兩載，種種荷推轂。", "容我數百輩，大矣空洞腹。", "爲憐昔同升，相看日不足。", "芳時木芙蓉，唱酬動成軸。", "燒香每開奩，惠茗屢傾簏。", "青青閲冬夏，高視松柏獨。", "顧我如碔砆，詎敢比良玉。", "而兄不我鄙，步驟俾繼躅。", "是行集霰候，霜威日增肅。", "解維在朝夕，離緒可堪觸。", "戀戀重摻袪，移庖過吾屋。", "紫嚢出巨編，還我海陵錄。", "全家被燕衎，日盡繼以燭。", "何人鱠紅鮮，想見鯿項縮。", "腹腴愧偏勸，佐此一杯綠。", "實筐出越羅，幣帛更加束。", "酒闌兒女曹，起舞應歌曲。", "殷勤藥石誨，美疢肯滋毒。"]'),
('6a84997b-0ab6-428d-8d59-09d87fd40a32','有薦胡仁叔爲歷陽令者仁叔以詩送知己暇日楊德潤錄以示予因次其韵','王之道','宋','宋诗','song-poetry','','[]','四海皆兄弟，三界是道場。',288,'全唐诗/poet.song.104000.json','["四海皆兄弟，三界是道場。", "果且無彼我，安用分封疆。", "胡公歷陽來，氣焰何可當。", "威嚴走邸吏，不露太守章。", "錦衣榮會稽，暮雨成高唐。", "觀望改儕輩，鷄群鶴昂昂。", "斯民苦兵火，有意哀勞傷。", "豈無九轉丹，爲助千金方。", "古來記循吏，不稱苟道將。", "殺弟自取酷，防人人所防。", "子潛去少室，淵明戀柴桑。", "出處雖異事，一夢歸黄粱。", "昔日骨己朽，傷哉今也亡。", "邶國歌柏舟，曹風賦鵜梁。", "秋來河伯喜，未睹若與洋。", "大小自有見，一笑還兩忘。", "我生分每越，泉石成膏肓。", "棄遺等麟角，空虚漫龜腸。", "常欲埋車輪，除姦繼張綱。", "召此人氣和，致彼天時康。", "語之有暇矣，未窺夫子墻。", "理所不可及，馬腹徒鞭長。", "詎知王者師，異日韓張良。", "願言三顧廬，卧龍起南陽。"]'),
('a0aea6e9-3d15-4737-9f17-db955b06a415','和張詠老','王之道','宋','宋诗','song-poetry','','[]','三公與刺史，秩等二千石。',96,'全唐诗/poet.song.104000.json','["三公與刺史，秩等二千石。", "人生不知足，奔馳竟朝夕。", "誰能話名理，尊酒時促席。", "賢愚大相遠，叢玕映叢荻。", "多謝張南巢，詩筒肯予覓。", "琅琅若明珠，其來自靈壁。", "僧房聊解鞍，當暑得偃息。", "挽回清微風，筆有萬鈞力。"]'),
('a55639f9-6f77-4eee-b755-8827ca23422a','彦嘉通守當今之俊偉人也余心向慕之常以未獲識君爲恨茲因孔純老遂有邂逅之適其何幸如此將歸純老置酒餞别僕實預坐酒數行純老丐詩於彥嘉以記坐上笑談之樂頃刻掃數百言揮毫落紙雲烟飛動永叔所謂盈前盡珠璣一一難簡汰者殆謂是邪索鄙句不敢以固陋辭輒和北莊二詩奉呈  其一','王之道','宋','宋诗','song-poetry','','[]','春寒不肯去，穀雨猶裌衣。',48,'全唐诗/poet.song.104000.json','["春寒不肯去，穀雨猶裌衣。", "溪流灔池塘，遠看綠生漪。", "識君恨不早，語離我心悲。", "行行欲何往，丞郡金房西。"]'),
('9aa0c84f-20eb-4852-ac31-8f8538be59d4','彦嘉通守當今之俊偉人也余心向慕之常以未獲識君爲恨茲因孔純老遂有邂逅之適其何幸如此將歸純老置酒餞别僕實預坐酒數行純老丐詩於彥嘉以記坐上笑談之樂頃刻掃數百言揮毫落紙雲烟飛動永叔所謂盈前盡珠璣一一難簡汰者殆謂是邪索鄙句不敢以固陋辭輒和北莊二詩奉呈  其二','王之道','宋','宋诗','song-poetry','','[]','顛風送飛雨，日日吼東北。',96,'全唐诗/poet.song.104000.json','["顛風送飛雨，日日吼東北。", "簷聲決江河，傾瀉不成滴。", "朝來喜新霽，晨光透雲隙。", "垂楊翠幄開，遠岫青蓋立。", "孔君公事暇，侯子歸期逼。", "開樽且精設，論文萃清集。", "顧我老無能，分甘口挂壁。", "行矣不可挽，思君浩無極。"]'),
('a24abaf2-5988-4cbc-8c9d-d0a2f62e558c','送無爲倅張南仲歸吉州','王之道','宋','宋诗','song-poetry','','[]','吾友李粹老，少也游膠庠。',168,'全唐诗/poet.song.104000.json','["吾友李粹老，少也游膠庠。", "六年得一第，自謂貴且昌。", "衽席不知戒，飛黄中道僵。", "三閲大淵獻，歲月亦已長。", "嗟嗟死非所，至今未能忘。", "忠言類良藥，苦口不見嘗。", "那知兵火餘，獲見同舍郎。", "來丞濡須郡，兩歲依餘光。", "邂逅偶及此，爲之淚淋浪。", "高義藉激薄，美政稱扶傷。", "康沂富邦國，何獨歌王祥。", "江城四月盡，麥熟梅子黄。", "歸歟佐吾君，談笑躋羲皇。", "遥應不可留，船頭鼔其鏜。"]'),
('4c386b1e-3d17-4aea-92c0-108900716c1c','次韵因上人晚菊簡魏定父  其一','王之道','宋','宋诗','song-poetry','','[]','荆棘困松柏，風雨亂昏曉。',48,'全唐诗/poet.song.104000.json','["荆棘困松柏，風雨亂昏曉。", "干戈幾時息，年來費天討。", "孤芳如謝安，端恐非小草。", "此意誰人知，伊余相自保。"]'),
('fd8fa70f-03d7-4810-a9ec-e620301ed1d0','次韵因上人晚菊簡魏定父  其二','王之道','宋','宋诗','song-poetry','','[]','不學桃與李，芬芳競春時。',48,'全唐诗/poet.song.104000.json','["不學桃與李，芬芳競春時。", "天公豈多情，清露爲君遲。", "榮悴休問命，冷暖當自知。", "青熒夜窗燈，相對哦新詩。"]'),
('8447c7c8-a6fb-437b-a7d6-dc0a61719d07','次韵因上人晚菊簡魏定父  其三','王之道','宋','宋诗','song-poetry','','[]','離索自可笑，衰遲誰見憐。',48,'全唐诗/poet.song.104000.json','["離索自可笑，衰遲誰見憐。", "亭亭揺落中，一枝小窗前。", "正色有家法，細看清且妍。", "浮觴未云晚，松醪吾所便。"]'),
('c836d79b-55f8-44e5-9c0a-d8e66aad0cb9','次韵因上人晚菊簡魏定父  其四','王之道','宋','宋诗','song-poetry','','[]','經年混蒿艾，藴藏應待時。',48,'全唐诗/poet.song.104000.json','["經年混蒿艾，藴藏應待時。", "清香密漬沉，微風助紛披。", "宋玉昧秋意，乃作兒女悲。", "君子有所養，因君觀解頤。"]'),
('b7cc2cce-e182-4eb4-9ae5-da578c76df06','次韵因上人晚菊簡魏定父  其五','王之道','宋','宋诗','song-poetry','','[]','道人如青松，孤高不成叢。',48,'全唐诗/poet.song.104000.json','["道人如青松，孤高不成叢。", "愛此黄金花，蕭然有淳風。", "新詩皎秋月，警我野性慵。", "佳意不在酒，此身今醉翁。"]'),
('3e54da84-1d03-44df-beeb-e04e5c7edc4c','次韵因上人晚菊簡魏定父  其六','王之道','宋','宋诗','song-poetry','','[]','介壽誠有取，無問人所宜。',48,'全唐诗/poet.song.104000.json','["介壽誠有取，無問人所宜。", "君看菊花潭，事見桃源詩。", "東坡百世士，敢比流俗知。", "相逢勿相失，不醉欲何時。"]'),
('7e329105-b553-4305-b39c-e40d84b33509','次韵因上人晚菊簡魏定父  其七','王之道','宋','宋诗','song-poetry','','[]','黄花如故人，别久喜復面。',48,'全唐诗/poet.song.104000.json','["黄花如故人，别久喜復面。", "澆泥一杯酒，安用較深淺。", "清霜開浮雲，黄落信風捲。", "巖巖幽素姿，秋來不多見。"]'),
('6d15de99-91d1-4386-88b0-175ea6a1151e','鑑止亭','王之道','宋','宋诗','song-poetry','','[]','揚波欲澄濁，孰若波暫停。',48,'全唐诗/poet.song.104000.json','["揚波欲澄濁，孰若波暫停。", "止波濁自澄，萬象無逃形。", "世人競馳騖，方寸不得寧。", "投閒幸一來，先生常獨醒。"]'),
('d18cc4c4-94a2-45ff-9437-2669e69442b2','燈下讀魏彦成諸公詩因次其韵呈曾子修諸君','王之道','宋','宋诗','song-poetry','','[]','距春尚旬月，春信已回柳。',72,'全唐诗/poet.song.104000.json','["距春尚旬月，春信已回柳。", "時來芝與菌，往往出糞朽。", "流俗不自重，困窮變操守。", "貴賤等人耳，未易遽薄厚。", "桃李何敢輕，所報必瑶玖。", "一笑置勿論，旨有君子酒。"]'),
('07b62b92-8041-4060-b1ab-92c0a992cace','見山堂','王之道','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','浮雲開西風，落木下夕陽。',72,'全唐诗/poet.song.104000.json','["浮雲開西風，落木下夕陽。", "誰人步東籬，采菊哦秋光。", "悠然若有思，此意何可量。", "南山適當前，翠色摩穹蒼。", "我心不期見，我眼偶相望。", "咄哉逐獸夫，泰山空在旁。"]'),
('10032fda-ef49-45ea-a64d-bb2788bf6d7d','西靈鷲','王之道','宋','宋诗','song-poetry','','[]','我聞西靈鷲，幽奇冠龍舒。',120,'全唐诗/poet.song.104000.json','["我聞西靈鷲，幽奇冠龍舒。", "山神知我來，夜雨自滌除。", "籃舁犯霏微，敢惮石徑紆。", "清風偃林柯，征衣盡霑濡。", "樵人向我言，君行欲何如。", "松杉已在望，尚有七里餘。", "崎嶇雨過水，蹊雲上天衢。", "飛樓及湧殿，崢嶸映浮屠。", "幽鳥若相喜，好音弄笙竽。", "爲言一宿覺，何妨更踟蹰。"]'),
('400e7dcf-ac7a-4726-9173-9e9009c89c87','憩靈鷲道院','王之道','宋','宋诗','song-poetry','','[]','黎明發龍門，亭午憩西院。',48,'全唐诗/poet.song.104000.json','["黎明發龍門，亭午憩西院。", "冒雨且不辭，寧能避泥濺。", "是行良不惡，此處殊可戀。", "從今山中人，何獨識吾面。"]'),
('dfcd0793-fc0a-4721-8030-58995ac5a1fd','追和老杜種萵苣詩','王之道','宋','宋诗','song-poetry','','[]','我有數畝園，荒穢索鋤理。',252,'全唐诗/poet.song.104000.json','["我有數畝園，荒穢索鋤理。", "干戈何許久，生意困屠燬。", "道也其興與，時哉亦甚矣。", "去年失短吕，培植乏驅使。", "今年得老楊，衰病更臨起。", "晚菘已蕪没，早韭就茅靡。", "菁菁何所有，萵苣獨牛耳。", "縱苦可自珍，供盤况瀟洒。", "銀條直且甘，風味胡伯始。", "其視李太尉，小人與君子。", "明明如古鑑，不慮纖塵止。", "廓廓若太清，强欲浮雲滓。", "老氏有遺訓，重去彼取此。", "方今向太平，皋夔正端委。", "臺省登碩德，要荒竄誣毁。", "擊寇豈無人，蕃將來黑齒。", "破齊在不日，逆以誅正已。", "停觀勞還役，杖杜顒采芑。", "萬邦遇有道，貧賤古人耻。", "文王來呂夷，漢祖致園綺。", "異時免溝坑，願附織貝篚。"]'),
('abfd9079-0028-4536-afd0-56ad8fa773e5','種田庵','王之道','宋','宋诗','song-poetry','','[]','古人即耒耜，自有中田廬。',36,'全唐诗/poet.song.104000.json','["古人即耒耜，自有中田廬。", "看君種田庵，名異實則如。", "滌場歸去來，宮功不容紓。"]'),
('55bfa3c5-96ea-4f4d-8ae1-962f56309b4d','廉餘堂','王之道','宋','宋诗','song-poetry','','[]','高堂面山水，境與動靜兼。',36,'全唐诗/poet.song.104000.json','["高堂面山水，境與動靜兼。", "惟動故能樂，惟靜故能廉。", "樂也知有餘，廉也笑無饜。"]'),
('8f385c49-3fd4-4660-b505-cff9716ff4b7','次韵魏定文','王之道','宋','宋诗','song-poetry','','[]','半年去城府，寤寐溪東扉。',120,'全唐诗/poet.song.104000.json','["半年去城府，寤寐溪東扉。", "有時得君書，想像抉石猊。", "豈知紀渻子，養氣如養鷄。", "應響與疾視，一洗三旬非。", "我生坐窮困，哆侈傷南箕。", "鼷鼠亦何物，焉用千鈞機。", "封侯絣澼絖，藥等手不龜。", "所用有異耳，此言寓非巵。", "梅蕾良可人，如椒綴南枝。", "芬芳想不晚，太皥方執視。"]'),
('ae441cea-c715-43df-88ee-b244c3706afa','次韵沈次韓見贈','王之道','宋','宋诗','song-poetry','','[]','我狂衆所易，頼有君見容。',72,'全唐诗/poet.song.104000.json','["我狂衆所易，頼有君見容。", "十年卧巖壑，百念付一空。", "新詩似流泉，涓涓江漢供。", "人言鷄群鶴，我目霜中松。", "相距無兩舍，會見何溟濛。", "誰能寫離索，正藉詩思工。"]'),
('dc21227f-7c7b-44c6-9fb7-5b0a110873f9','次韵許志仁','王之道','宋','宋诗','song-poetry','','[]','我技類族庖，用刀常月更。',96,'全唐诗/poet.song.104000.json','["我技類族庖，用刀常月更。", "君才妙天下，遊刃得我驚。", "前年獲相值，因憶吳中行。", "一别忽兩載，依然舊交情。", "新詩璧夜光，厥價輕連城。", "相思不可見，把玩我願盈。", "筆札擅南州，文章動西京。", "行矣秋風高，更聽賓鴻聲。"]'),
('f76d89a2-4644-484d-a60f-95f7c99f8974','盆池','王之道','宋','宋诗','song-poetry','','[]','剜苔得古鑑，湛湛清不渾。',48,'全唐诗/poet.song.104000.json','["剜苔得古鑑，湛湛清不渾。", "大哉壺中天，勿與俗子言。", "誰能時汲井，注兹老瓦盆。", "欲觀從容鯈，無羡横海鯤。"]'),
('b8093ea6-841f-4ef1-ba76-93569f6f9523','秋晚采菊和徐伯遠','王之道','宋','宋诗','song-poetry','','[]','少皥司肅殺，於渠獨留情。',48,'全唐诗/poet.song.104000.json','["少皥司肅殺，於渠獨留情。", "一枝黄金花，照眼增雙明。", "香清露溥溥，秀色雲英英。", "會當飲潭水，使我病骨輕。"]'),
('710b7214-93ff-4717-a911-a33c697a734e','題德章山郭養源墨竹','王之道','宋','宋诗','song-poetry','','[]','胸次富盤錯，筆端妙蒼翠。',48,'全唐诗/poet.song.104000.json','["胸次富盤錯，筆端妙蒼翠。", "霜枝豈人爲，煙葉有生意。", "與可骨已朽，此法誰復嗣。", "偉哉尋丈姿，綽有萬尺勢。"]'),
('28d0014b-0353-41b8-a404-1cb0b6b0ef4f','追和東坡雨中睡熟至晚','王之道','宋','宋诗','song-poetry','','[]','春睡酣带酒，晚食美當肉。',72,'全唐诗/poet.song.104000.json','["春睡酣带酒，晚食美當肉。", "細觀東坡詩，萬事貴精熟。", "一陰七十日，雨意猶未足。", "山雲開復合，簷溜斷還續。", "東鄰嬌癡兒，索飯恣啼哭。", "驚廻夢中蝶，重把君詩讀。"]'),
('517d5be6-e493-406b-9a0f-bc377d8bf9f3','會河道中','王之道','宋','宋诗','song-poetry','','[]','會河村店西，沙水清練練。',48,'全唐诗/poet.song.104000.json','["會河村店西，沙水清練練。", "我行獨带月，滉漾掣金線。", "凝寒逼征衣，霜華重如霰。", "至此懷僧彌，老淚幾欲泫。"]'),
('0887260a-8c52-49f0-99ed-4021d4dfb3f0','和龔聖任即事','王之道','宋','宋诗','song-poetry','','[]','新詩似霜月，諦玩清且好。',48,'全唐诗/poet.song.104000.json','["新詩似霜月，諦玩清且好。", "欲見勢未能，思君令人老。", "啟蟄在朝夕，雷雨發枯槁。", "願言從杖屨，高吟備搜討。"]'),
('1d97660c-0b79-4853-9aaf-0611be4e94c1','月臺','王之道','宋','宋诗','song-poetry','','[]','低迷委徑柳，氛氲被池蓮。',48,'全唐诗/poet.song.104000.json','["低迷委徑柳，氛氲被池蓮。", "亭前秋雨餘，明月來婵娟。", "高臺甃蒼玉，清風夜周旋。", "舉杯屬姮娥，醉舞還蹁蹮。"]'),
('a47565e4-0b49-45d6-9cf1-d7cfa140e94e','小橋','王之道','宋','宋诗','song-poetry','','[]','芳榭遶流水，春餘半篙綠。',48,'全唐诗/poet.song.104000.json','["芳榭遶流水，春餘半篙綠。", "登臨賞幽花，兹亦我所欲。", "小橋果何往，長堤正相屬。", "朝看龜魚遊，晚聽鷗鷺浴。"]'),
('67a437a3-c701-4168-b18d-18d58eeb1118','次韵朱元順食萱草羮','王之道','宋','宋诗','song-poetry','','[]','衰年因羈旅，百念日縈繞。',96,'全唐诗/poet.song.104000.json','["衰年因羈旅，百念日縈繞。", "蓍龜亦何知，憂來又將老。", "出處稍不慎，遠志成小草。", "堂陰有孤芳，紛葩照人好。", "誰將忘憂姿，擷芼等蘋藻。", "充腸固甚慰，入鼎可堪擾。", "糠籺貧者事，甚矣兄逐嫂。", "異時饜粱肉，記此一羮飽。"]'),
('00178777-7193-482a-a2ca-cc2c39377cc6','贈術士羅世忠','王之道','宋','宋诗','song-poetry','','[]','春秋有羅國，之子豈其後。',120,'全唐诗/poet.song.104000.json','["春秋有羅國，之子豈其後。", "家傳錦嚢書，相地走淮右。", "爲問何所宗，此法古所授。", "卜瀍與卜宅，周孔語非謬。", "用能游公卿，所至術輒售。", "有時過吾廬，乘間得頻扣。", "談詩涉坡谷，說卦本爻繇。", "是名陰陽家，未可容易詬。", "歸歟春雨霽，飛花撲襟袖。", "遥憐玉笥峰，巋然插天秀。"]'),
('a61eb86c-a11f-4af3-a85c-89a6f7ba6051','送無爲宰趙渙冰仲','王之道','宋','宋诗','song-poetry','','[]','百里寄一令，於民爲最親。',144,'全唐诗/poet.song.104000.json','["百里寄一令，於民爲最親。", "休戚咳唾間，詎可非其人。", "趙侯古循吏，當世無等倫。", "朅來宰濡須，舊政俱更新。", "雖無赫赫名，吏戢民稱仁。", "善良仰若父，姦欺畏如神。", "幸哉百里地，兩載銷顰呻。", "果膺君相知，贊書下楓宸。", "不終三年淹，徑作帥幕賓。", "秋風散炎酷，夜雨清埃塵。", "寧容卧轍留，高檣艤江濵。", "君看眉間黄，華近兹其因。"]'),
('ad853841-cc35-4827-9a77-742d23cb5925','映雪亭','王之道','宋','宋诗','song-poetry','','[]','蕭然數株梅，皓與雪相映。',36,'全唐诗/poet.song.104000.json','["蕭然數株梅，皓與雪相映。", "臨池鍳疏影，影落大圓鏡。", "不煩粉塗株，寒光助嚴靚。"]'),
('65b62df8-3e52-4308-9652-5cc309a834a7','題宿雲軒','王之道','宋','宋诗','song-poetry','','[]','朝來怯秋霜，生撇甕裏清。',48,'全唐诗/poet.song.104000.json','["朝來怯秋霜，生撇甕裏清。", "我老顔已衰，一杯聊發赬。", "村尨恠我醉，忽吠三兩聲。", "蜀月不可見，宿雲有新行。"]'),
('8dd6a6d5-7bc1-4405-9d23-93cec214bbc2','酬朱元順參議','王之道','宋','宋诗','song-poetry','','[]','舟來自金沙，敢避江路繞。',96,'全唐诗/poet.song.104000.json','["舟來自金沙，敢避江路繞。", "計程踰五月，書勞比三考。", "湖陰見君處，取别殊草草。", "因思會面難，相從意彌好。", "新詩何所似，繪繡錯華藻。", "賡酬愧空疏，秪益我心攪。", "亨否有時命，恭倨任妻嫂。", "行矣無忘饑，俗諺戒一飽。"]'),
('54ce3b0a-44f5-4dc3-823a-8ab3d2e00d1c','送張仲甫赴江西參議','王之道','宋','宋诗','song-poetry','','[]','我生坐疏拙，逢人輒傾倒。',120,'全唐诗/poet.song.104000.json','["我生坐疏拙，逢人輒傾倒。", "語言無淺深，出口被伊惱。", "爲孽匪天作，受攻本誰造。", "懲非每嚼舌，事已復自蹈。", "可憐愚不靈，蹭蹬到今老。", "識君無幾時，底裏見襟抱。", "古人重傾蓋，相從恨不早。", "是行若登仙，江山爲君好。", "無繇挽畫鷁，此意增戀嫪。", "何當寄相思，臨風慰衰槁。"]'),
('c05648ee-b48a-40b8-b586-d3af0f078f18','曾欽道家山圖','王之道','宋','宋诗','song-poetry','','[]','永叔愛清潁，明仲樂陽羡。',240,'全唐诗/poet.song.104000.json','["永叔愛清潁，明仲樂陽羡。", "投老獲所歸，爲計亦良便。", "何如强健時，從官山水縣。", "升虚得吉卜，怳若地祗薦。", "曾侯卿相種，才業固邦彥。", "而况盛德後，世祀乃天眷。", "式古吾畏友，被命按郵傳。", "來歸自濠梁，訪我出詩卷。", "爲言有華宗，疇昔無半面。", "相逢遂相喜，笑語至舞忭。", "其家負家山，山水家可戀。", "松篁遞森列，岡巒互縈轉。", "臺池及花草，高下爛明絢。", "粲然圖一幅，規橅坐中見。", "予嘗賦此詩，好事敢獨擅。", "縱横一千字，把玩不知倦。", "桐廬在何許，東望眼欲眩。", "子陵亦往矣，釣瀨清練練。", "家山亘今昔，昔隠今始現。", "彼美曾侯賢，何當睹巖電。"]'),
('3ae81916-01d9-44e6-843f-08243ecb0703','題李夢發揺碧堂','王之道','宋','宋诗','song-poetry','','[]','群山俯平湖，冰壺浸蒲璧。',180,'全唐诗/poet.song.104000.json','["群山俯平湖，冰壺浸蒲璧。", "奫淪五千頃，岝峉一萬尺。", "蒼松偃旌蓋，翠竹森劍戟。", "纖塵不可到，湛湛見沙磧。", "詩人嗜好異，方寸富泉石。", "堂成欲臨賦，牋管羅几席。", "偶然對漣漪，微風緩揺碧。", "高吟寓動静，真賞廢晨夕。", "璇題壯簷楹，玉軸走賓客。", "清商入葱蒨，積雨洗炎赫。", "翺翔下幽鷺，從容出圓鯽。", "穿荷過獨舸，傍柳倚輕策。", "此興復不淺，何日當有獲。", "君方事閒放，佳處勿輕擲。", "明年谷鳴騶，金閨遂通籍。"]'),
('e8741edd-a4d8-428f-92ac-78bbb9b0bd48','和陳阜卿爲湯與立壽次韵','王之道','宋','宋诗','song-poetry','','[]','我聞無量壽，世作天人師。',156,'全唐诗/poet.song.104000.json','["我聞無量壽，世作天人師。", "有禱必應感，如形影隨之。", "吾見盛德士，吏隠江之湄。", "巖巖棟梁材，爲桷豈所宜。", "守道心自適，怡然見雙眉。", "何當日千里，整頓黄金羈。", "嗟予拙無用，正坐千林姿。", "荷兄獨青眼，少雪群兒欺。", "蘭菊雖異芳，春秋莫予遺。", "相逢一尊酒，駐馬聊共持。", "偶觀香霧鬰，彷彿初生時。", "願兄壽無量，登庸侍彤墀。", "年年遇今日，酌酒共瑶巵。"]'),
('bc731ca2-fc98-407f-bf55-57fc90477913','次韓子雲白蓮韵','王之道','宋','宋诗','song-poetry','','[]','金縷不相稱，紈素新裁衣。',120,'全唐诗/poet.song.104000.json','["金縷不相稱，紈素新裁衣。", "坐令時世粧，屏跡從招揮。", "施粉定太白，增分卻成肥。", "須知冰雪肌，秋月揚明輝。", "來從姑射山，一洗百念非。", "何煩障青綾，高談解郎圍。", "亭亭翠盖中，老眼省見稀。", "揺風自披拂，照水相因依。", "傍觀慎無前，恐犯丞相威。", "不如太華巔，食藕家翠微。"]'),
('d50d9b51-9ad1-4dee-881c-bc3f59611c6a','追和元微之春餘遣興示王覺民','王之道','宋','宋诗','song-poetry','','[]','物態有榮悴，時令互消長。',144,'全唐诗/poet.song.104000.json','["物態有榮悴，時令互消長。", "墮身名利場，魚鳥在羅網。", "豈無金屈巵，聽此石方響。", "殘花日晴陰，落絮風下上。", "春事雖已闌，餘芳尚堪賞。", "我有臨溪亭，疏櫺爲君敞。", "青青小荷錢，雅與水相養。", "狂吟醉題壁，縱步懶扶杖。", "仰止李謫仙，筆端走群象。", "九原不可作，夜夢見精爽。", "栖栖亦固矣，君子坦蕩蕩。", "相期醉酴醿，偕來衆無鞅。"]'),
('afd10825-0bb8-4fc6-b283-e8a5bd234f3d','九江解舟順風追和張文潛','王之道','宋','宋诗','song-poetry','','[]','朝來轉西風，天巧借吾便。',144,'全唐诗/poet.song.104000.json','["朝來轉西風，天巧借吾便。", "解維溢江口，去若弦上箭。", "水光漾朝曦，過浪掣驚電。", "周旋謝神貺，冠坐敢不變。", "斯須走四驛，俛仰驀二縣。", "誰知久留滯，一旦乃適願。", "吾聞信由中，溪毛可羞薦。", "咄哉和氏璞，底事待三獻。", "亨否自有時，時亨百無譴。", "雷聲在淵默，若訥故大辨。", "千巖與萬壑，左右供几硯。", "落帆風亦止，璧月熨江練。"]'),
('7ad72702-1286-4b2c-afac-23452ffb397b','花洞','王之道','宋','宋诗','song-poetry','','[]','浮渡竟何處，欲游未能游。',48,'全唐诗/poet.song.104000.json','["浮渡竟何處，欲游未能游。", "夢寐金谷巖，神往形獨留。", "異哉城市中，芳菲自春秋。", "長紅雜團綠，結成巖穴幽。"]'),
('d442aa91-71e8-4caf-a083-31b9c54347fd','怡顔堂','王之道','宋','宋诗','song-poetry','','[]','人生無百年，半被憂患苦。',48,'全唐诗/poet.song.104000.json','["人生無百年，半被憂患苦。", "其間開口笑，一月僅四五。", "誰能盻庭柯，怡然見眉宇。", "積財不得用，真是守錢虜。"]'),
('8491f589-ff90-4f97-aaf2-915163e78b15','蒸紅亭','王之道','宋','宋诗','song-poetry','','[]','桃源果何處，溪流出殘紅。',36,'全唐诗/poet.song.104000.json','["桃源果何處，溪流出殘紅。", "忽然見桃花，灼灼揺春風。", "蒸成日邉霞，高吟思無窮。"]'),
('a5719d81-9682-4fbc-a213-1f9ea0a53880','史佐才讀書堂','王之道','宋','宋诗','song-poetry','','[]','我聞輪人扁，妙解書中義。',264,'全唐诗/poet.song.104000.json','["我聞輪人扁，妙解書中義。", "當其聽讀書，默識聖人意。", "忽然釋椎鑿，有問發兹秘。", "雖云聖人語，糟粕豈精粹。", "齊侯詰其說，無說當致死。", "請以斵輪觀，固入要非易。", "不徐仍不疾，心手在相契。", "是中有數存，非言所能既。", "扁也亦何人，所得乃至此。", "固知斯道在，天下本無二。", "觀君榜斯堂，令我端拜議。", "想見堂中書，填箱溢巾笥。", "縱橫三萬卷，一覧悉能記。", "左右逢其原，下筆不能綴。", "我昔攝東城，君時尚童穉。", "如聞侍先公，往矣江之涘。", "崎嶇三十載，於此忽相值。", "出示諸公詩，圭璧爛庭瑞。", "君家依水竹，亭臺繚幽邃。", "作堂於其間，讀書乃其事。", "嗜好與人殊，可以見君志。", "明年冠群英，先正秘書字。"]'),
('f2f04f20-99dc-4d4e-9fec-07db9ac79e41','題王亦顔清心閣','王之道','宋','宋诗','song-poetry','','[]','湖光浩無際，遠與列岫并。',192,'全唐诗/poet.song.104000.json','["湖光浩無際，遠與列岫并。", "風澄烟霧開，炯若鏡面平。", "高人對萬變，寸田常默耕。", "擾擾亦何爲，豈容方寸攖。", "有時鑒湖光，愛其静而明。", "那知水是物，心清物還清。", "徘徊不忍去，傑閣指顧成。", "閣成何所喜，畫棟連朱甍。", "大江西南來，群山東北橫。", "江山不待招，宛轉趨簷楹。", "諏度多暇日，登臨有餘情。", "論文一樽酒，對客手自傾。", "酒闌復徜徉，觀書弄潁泓。", "使人之意消，鄙吝何由萌。", "嗟予頑鈍姿，栖栖亦勞生。", "從今事疏瀹，永守清心盟。"]'),
('87ad18f5-4c25-4448-9827-eb784b68486e','追和韋蘇州詩呈周守敦義','王之道','宋','宋诗','song-poetry','','[]','江城五月雨，千里荷花香。',120,'全唐诗/poet.song.104000.json','["江城五月雨，千里荷花香。", "清風吹葛衣，鈴齋有餘凉。", "日晏吏卒散，槐陰掃高堂。", "歸來欲偃仰，歎息不敢康。", "設醴致佳客，論交到相忘。", "高文如大烹，未慣染指嘗。", "何當侍函文，獲賦蔓草章。", "君方扶揺摶，我獨蓬蒿翔。", "生平一壑美，未見北海洋。", "願言承至教，雖老當自强。"]'),
('7daf8884-a4d6-482e-bb34-cf74dcd15d02','寄題魯如晦需堂','王之道','宋','宋诗','song-poetry','','[]','魯僖有賢裔，家在吳江東。',144,'全唐诗/poet.song.104000.json','["魯僖有賢裔，家在吳江東。", "宏詞與奥學，浩渺江無窮。", "魁然棟梁姿，久困荆棘中。", "抱能未施邦，殆與張籍同。", "人皆盲於心，我目昏不矇。", "而君乃勇退，奉祠環堵宫。", "築圃號通隠，花竹羅青紅。", "郡山湧其前，湖光湛冲瀜。", "日哦松菊間，志氣驕王公。", "客來醉需堂，飲食霑奴童。", "嗟予老且倦，齒豁仍頭童。", "田蕪未能歸，慚愧通隠翁。"]'),
('1b660d87-533d-4a45-88ff-5c5b8a353c97','題李夢發知足齋','王之道','宋','宋诗','song-poetry','','[]','荀卿重無禍，老氏貴不辱。',144,'全唐诗/poet.song.104000.json','["荀卿重無禍，老氏貴不辱。", "不辱非暫榮，無禍乃長福。", "咄哉名利場，甚矣身世梏。", "得侯方丏公，懷金未忘玉。", "經營蛾赴火，奔走蝇嗜肉。", "方當從後摶，寧復念前覆。", "李斯悲黄犬，揚雄誚丹轂。", "二者倘胥失，萬此亦何足。", "是理甚易知，允蹈君所獨。", "使人之意銷，豈止我心服。", "不貪子罕寶，屬厭女寛腹。", "庶幾聞高風，將遂變流俗。"]'),
('fcbfe129-820b-401a-a731-9c01847fee1b','夏日雨霽郊行次韵劉春卿','王之道','宋','宋诗','song-poetry','','[]','皇天久不雨，既雨晴亦好。',168,'全唐诗/poet.song.104000.json','["皇天久不雨，既雨晴亦好。", "食已得從容，偕行石城道。", "桑麻光似潑，山林淨如澡。", "蒼苔長綠髮，嫩竹揺翠葆。", "離離實攅椅，蔌蔌花褪棗。", "風梢水中蒲，烟葉湖外草。", "新秧良可喜，勃然見興槁。", "老農競耘耔，出作恨不早。", "誰家列午餉，蔬筍雜鮮薧。", "田頭立婦子，柳下坐翁媪。", "寧能擇豐甘，放筯等一掃。", "旁觀猶快意，想見慰傾倒。", "嗟予少力穯，自取宦遊惱。", "何當賦歸來，鬚髪已華皓。"]'),
('3579654e-91ec-4535-be85-b6a221eb7250','次韵陳勉仲登群山觀','王之道','宋','宋诗','song-poetry','','[]','十年放江湖，親朋益疏散。',192,'全唐诗/poet.song.104000.json','["十年放江湖，親朋益疏散。", "不知跬步間，游覽有奇觀。", "因君寄新詩，心目益悽斷。", "東城俯荻洲，下有魚鳥亂。", "想見江南山，終日對書案。", "小立笻杖倚，兀坐葛巾岸。", "高情渺雲外，竑議涉唐漢。", "嗟予衰且老，兒輩逼婚冠。", "豈復敢言詩，觀詩重增歎。", "舂容來大軸，玩味起頑懦。", "窮愁欲誰知，富貴當自斷。", "探虎愧吕蒙，思鱸抗張翰。", "别來能幾時，鬢髪暗凋換。", "養成杜甫懶，甘作元結漫。", "何當遂拂衣，疲馬解韁絆。", "卜鄰大期東，攜酒日相看。"]'),
('24de7742-eac7-46fc-b6b4-06fd33fe9f1b','題龍舒天祚宫玉虹亭','王之道','宋','宋诗','song-poetry','','[]','山祇不愛寶，傾寫白玉霙。',48,'全唐诗/poet.song.104000.json','["山祇不愛寶，傾寫白玉霙。", "秋陽正炎赫，噴薄爭清明。", "我疑石韜玉，白虹貫巖泓。", "源源自何來，萬古風雷聲。"]'),
('d8b099f0-3ea4-42cd-a293-7e59bde1667c','聞蟬和彦時兄','王之道','宋','宋诗','song-poetry','','[]','浮光我家尉，近處惟高安。',132,'全唐诗/poet.song.104000.json','["浮光我家尉，近處惟高安。", "嘗欲爲親擇，敢作非意干。", "憶昔從東來，飛雪凌羈單。", "青春不可挽，明月裁齊紈。", "三釡竟何地，一囊今屢殚。", "我有醉翁吟，試從徽外彈。", "古人骨已朽，知音果哉難。", "攣拳抱枝蟬，未露先號寒。", "緬想江南山，瓊梳碧成攅。", "僧窗開南薫，俯仰天地寛。", "詩成有佳句，往往勝得官。"]'),
('5ccd06b5-e2dc-4d01-ad49-1b39dbdf93a3','贈筆工柳之庠','王之道','宋','宋诗','song-poetry','','[]','我昔丞歷陽，好筆得柳生。',120,'全唐诗/poet.song.104000.json','["我昔丞歷陽，好筆得柳生。", "維時習治久，群盜方縱橫。", "生售數毛頴，一一簡擇精。", "作字可人意，爲我供筆耕。", "不知二十年，天下乃復平。", "爾貧技不售，我困功無成。", "布衫負篛笠，羸然過柴荆。", "我老廢讀書，無意游管城。", "千錢與斗米，聊爾餉此行。", "歸家飽妻子，一笑嘲彭亨。"]'),
('1c172b4b-92de-4975-b86f-68571d33654a','送彦立兄遊太學以恩袍草色動爲韵  其一','王之道','宋','宋诗','song-poetry','','[]','鼠腊要非玉，箎聲偶先塤。',48,'全唐诗/poet.song.104000.json','["鼠腊要非玉，箎聲偶先塤。", "窮通一生事，早晚焉足論。", "行行欲何之，闊步登金門。", "有意韓淮陰，報讎如報恩。"]'),
('b2f53e8a-ff00-4861-9950-757ec95ce2de','送彦立兄遊太學以恩袍草色動爲韵  其二','王之道','宋','宋诗','song-poetry','','[]','西風曉飛霜，獵獵吹征袍。',48,'全唐诗/poet.song.104000.json','["西風曉飛霜，獵獵吹征袍。", "丁寧顧婢語，肯效兒女曹。", "舉鞭問長安，詩海今誰豪。", "我欲從之遊，痛飲歌離騷。"]'),
('88dbe521-82c9-41f9-bc28-d7854f7329eb','送彦立兄遊太學以恩袍草色動爲韵  其三','王之道','宋','宋诗','song-poetry','','[]','文章我家勃，人喚腹爲藁。',48,'全唐诗/poet.song.104000.json','["文章我家勃，人喚腹爲藁。", "隨行載中書，所至得揮掃。", "新詩如秋月，皎皎清更好。", "惠連有佳夢，池塘遍春草。"]'),
('d50a43b7-73e7-41ad-afa7-28b00776378e','送彦立兄遊太學以恩袍草色動爲韵  其四','王之道','宋','宋诗','song-poetry','','[]','梅花破朝寒，似欲壯行色。',48,'全唐诗/poet.song.104000.json','["梅花破朝寒，似欲壯行色。", "駸駸小驪駒，回首便數驛。", "一鶚在雲路，鷙鳥空累百。", "從令馬賓王，不是新豐客。"]'),
('6c99b053-63a0-4378-b7d3-04698a4d7e18','送彦立兄遊太學以恩袍草色動爲韵  其五','王之道','宋','宋诗','song-poetry','','[]','君子贈以言，古人重相送。',48,'全唐诗/poet.song.104000.json','["君子贈以言，古人重相送。", "大梁在何許，我心欲飛動。", "兄才如青錢，萬選仍萬中。", "行矣喜冬晴，北方地多凍。"]'),
('35fd1f9d-3899-40ed-b91f-ca454cb456d4','題璋老清閟軒','王之道','宋','宋诗','song-poetry','','[]','典午接曹氏，其風扇浮虚。',168,'全唐诗/poet.song.104000.json','["典午接曹氏，其風扇浮虚。", "當時波浪從，高談乃其餘。", "竹誠松柏流，一日不可無。", "子猷爲此語，千古誰能渝。", "堂堂韓退之，議論荀揚徒。", "詠竹美清閟，長篇載諸書。", "吉祥在無爲，隠若西南隅。", "我来過梅雨，新竹環精廬。", "風梢弄蒼筤，日影穿扶疏。", "高標挺直節，勁特凌萬夫。", "道人謂予言，吾方葺吾居。", "公其爲吾名，要令與實符。", "清閟退之詠，是軒良不孤。", "何當對此君，搜吟更躊躇。"]'),
('fb006c83-1f6f-4b54-8abf-59e3615c2cca','和魯如晦喜雨','王之道','宋','宋诗','song-poetry','','[]','我本山中人，當暑玩泉石。',108,'全唐诗/poet.song.104000.json','["我本山中人，當暑玩泉石。", "高吟清風朝，長嘯明月夕。", "前年徙江城，舴艋劣容席。", "是時暑雨過，黄流没青荻。", "城中無置錐，僦舍至三易。", "邇来成小築，風月得相覓。", "執熱想飛瀑，白練掛蒼壁。", "頓從釡甑中，令我獲蘓息。", "尤憐昨夜雨，洒濯有餘力。"]'),
('634cca5e-f785-40d8-aa39-10e72e315bf9','假山','王之道','宋','宋诗','song-poetry','','[]','幽人愛九華，胸臆富岩竇。',48,'全唐诗/poet.song.104000.json','["幽人愛九華，胸臆富岩竇。", "疊石談笑頃，窗間列遠岫。", "一拳儻興雲，其功等高秀。", "君看負山者，盍亦備兹寇。"]'),
('fdf5f151-11bd-4be8-9b5c-767e68682729','柳徑','王之道','宋','宋诗','song-poetry','','[]','我笑陶彭澤，門栽五株柳。',48,'全唐诗/poet.song.104000.json','["我笑陶彭澤，門栽五株柳。", "柳成復自號，清陰亦何有。", "豈如兩分行，一徑入花藪。", "白氊春盡時，青障雨晴後。"]'),
('d231f69e-f7c2-4400-9782-4d7294c5d47f','古松','王之道','宋','宋诗','song-poetry','','[]','老松如蛟龍，氣奪百萬軍。',48,'全唐诗/poet.song.104000.json','["老松如蛟龍，氣奪百萬軍。", "根蟠蒼崖石，梢拂青天雲。", "山神護野火，地主訶樵斤。", "魁然棟梁材，爲之獻吾君。"]'),
('df6b5b2a-6b39-424e-82df-5cdf8b9591a3','白蓮池','王之道','宋','宋诗','song-poetry','','[]','白蓮如玉人，高潔謝脂澤。',36,'全唐诗/poet.song.104000.json','["白蓮如玉人，高潔謝脂澤。", "圓荷作翠盖，掩映秋水碧。", "小亭日相對，無言倚輕策。"]'),
('40a2b9df-e29f-44df-90ed-369ed87606d5','種橘','王之道','宋','宋诗','song-poetry','','[]','或言千樹橘，貴可比封君。',36,'全唐诗/poet.song.104000.json','["或言千樹橘，貴可比封君。", "先生種橘意，此計何足云。", "珍絕色香味，解酲有餘勲。"]'),
('0440daad-60ca-403d-9ec4-9b0464e7bede','次韵王山甫春日出郊探梅','王之道','宋','宋诗','song-poetry','','[]','倚竹有佳人，天寒玉肌温。',288,'全唐诗/poet.song.104000.json','["倚竹有佳人，天寒玉肌温。", "永懷經年别，及此春日暄。", "幽閒誰與娱，依依映丘樊。", "計臺二三友，才高工撥繁。", "幕府公事退，聯鑣出郊原。", "城南富卉木，勝處陳家園。", "東風發萌芽，柳眼暗若昏。", "昨宵一陣雨，清爽到乾坤。", "植杖芳草徑，繫馬枯桑根。", "觀梅不忍去，錯爼羅金樽。", "主人笑揖客，徘徊倚朱門。", "指麾群兒輩，薪水相撫存。", "鄰婦抹紅粧，来覘攀籬援。", "酒酣詩思逸，筆力華旗搴。", "薑鹽芼蕪菁，絕勝瓠葉幡。", "蕭然出塵姿，飄飄欲騰掀。", "桃李分當避，蜂蝶那敢喧。", "誰能移將歸，栽培擁高垣。", "要令百種花，俯伏争趨奔。", "不煩頻出游，正恐嘲短轅。", "太簇初應律，飛霙尚翩翩。", "何妨醉瑶舟，大嚼供炮燔。", "手撚一枝春，吟笑窮曛暾。", "可憐廊廟具，沉滯三家村。"]'),
('2fe1b1bc-b885-43f6-8f3e-5be65083f862','對雪和子厚弟四首  其一','王之道','宋','宋诗','song-poetry','','[]','凍雲不成雨，巧作白玉霙。',48,'全唐诗/poet.song.104000.json','["凍雲不成雨，巧作白玉霙。", "寒光僣曉色，報我東窗明。", "起来撥殘灰，煖酒手自傾。", "多謝麴居士，於人殊有情。"]'),
('d815003f-84f0-4b9b-a67c-47e8821ef6b1','對雪和子厚弟四首  其二','王之道','宋','宋诗','song-poetry','','[]','前村不多地，坐覺阻且長。',48,'全唐诗/poet.song.104000.json','["前村不多地，坐覺阻且長。", "梅花應已開，鼻觀来清香。", "天公愛衰朽，古木敲鳴璫。", "僵僕巧耐寒，冰柱生承漿。"]'),
('d95957de-a472-4a77-ae5f-a05c1eb15d60','對雪和子厚弟四首  其三','王之道','宋','宋诗','song-poetry','','[]','青腰夜種玉，不見稠與稀。',48,'全唐诗/poet.song.104000.json','["青腰夜種玉，不見稠與稀。", "將軍欲何往，滹沱正流澌。", "軟火燒黄精，我爾寧苦饑。", "行行復行行，舌在請勿疑。"]'),
('8603d1fb-d90a-4041-aadd-0b35bb26f04c','對雪和子厚弟四首  其四','王之道','宋','宋诗','song-poetry','','[]','瑶林我家風，銀色佛世界。',48,'全唐诗/poet.song.104000.json','["瑶林我家風，銀色佛世界。", "泠泠一川水，淙玉漱寒瀬。", "敲冰往得魚，撥凍自挑菜。", "山居果如此，冷暖任交態。"]'),
('a18ed84f-9ab3-4f22-8d20-c35e500e7df8','和沈元吉與唐用崔乞菊','王之道','宋','宋诗','song-poetry','','[]','黄花如幽人，别來心念之。',84,'全唐诗/poet.song.104000.json','["黄花如幽人，别來心念之。", "邂逅適我願，詎可無一辭。", "緬懷東籬游，舊與西風期。", "乞我三百株，爛醉風前杯。", "休文有佳裔，咳唾成新詩。", "把玩乞菊章，頗愧前篇非。", "寄言崔藍田，捨之復誰貽。"]'),
('5822f007-ff48-4222-b785-80dcf2f7cedb','和魏桐城題三瀑泉贈湯洞卿  其一','王之道','宋','宋诗','song-poetry','','[]','奔霆響空山，飛連掛絕壁。',48,'全唐诗/poet.song.104000.json','["奔霆響空山，飛連掛絕壁。", "毛髮忽森竪，精神共英特。", "平生丘壑姿，至此意頗適。", "何必遊九華，龍眠自尤物。"]'),
('f6afd328-1ea6-4392-b308-3ba8d42ca7ef','和魏桐城題三瀑泉贈湯洞卿  其二','王之道','宋','宋诗','song-poetry','','[]','雨雹碎晴峰，珠璣瀉石壁。',48,'全唐诗/poet.song.104000.json','["雨雹碎晴峰，珠璣瀉石壁。", "勢增九軍勇，氣壓百夫特。", "先生我輩人，一見願自適。", "壯哉三瀑泉，表表塵外物。"]'),
('1c0112da-4f21-46d6-aaa0-23bb2637de65','題雙峰磨院瀑布','王之道','宋','宋诗','song-poetry','','[]','烈日冰雪皎，淡烟玉虹明。',48,'全唐诗/poet.song.104000.json','["烈日冰雪皎，淡烟玉虹明。", "誰云真珠簾，要之亦强名。", "我來少躊躇，一洗塵埃清。", "便欲覓千斛，爲壓歸裝輕。"]'),
('fbdfc48e-f6bb-49ae-8af0-df5b9b8a2bf4','予紹興三十二年夏四月三日行部至山中時月上人方入山十有八日旋披荆棘立數椽以居其徒明年改元隆興夏六月二日再過山而堂室粗備且於雲母泉側創爲茅亭使往来觀者得以駐足而酌甘誠可嘉也時巴陵尉臨川李克仁高密劉孝傑華容尉權三衢徐二譽在焉子輩侍行','王之道','宋','宋诗','song-poetry','','[]','去年入山時，孟夏暑猶薄。',168,'全唐诗/poet.song.104000.json','["去年入山時，孟夏暑猶薄。", "来觀雲母泉，陰崖坐盤礴。", "老禪披荆榛，經營始興作。", "山空斤斧響，丁丁振林壑。", "俛仰恰周星，炎赫若凌薄。", "昨朝發岳陽，東風怒還惡。", "驚濤送輕舟，十里沙頭落。", "投凉不待曉，肩輿上磽确。", "僧徒笑相迎，此意安可卻。", "高亭蔭白茅，群峰峙青廓。", "偕行二三子，臨泉一杯酌。", "呼僮瀹石鼎，煮湯旋和藥。", "誰令俗士駕，急去能不怍。", "因成數句語，聊發後来噱。"]'),
('0d33e6e0-32d1-4fc2-9c27-39cedd9fa027','癸酉閠十二月朔旦入夜雪復作静言歲歉斯人艱食展轉不能寐强沃一杯徑醉因成此詩','王之道','宋','宋诗','song-poetry','','[]','宿雁驚江渚，餓彪嘯林丘。',120,'全唐诗/poet.song.104000.json','["宿雁驚江渚，餓彪嘯林丘。", "不知雪如許，但怪風颼飀。", "起看堂前柳，枯梢戞鳴球。", "安得萬家春，解我饑寒憂。", "旋支折脚鐺，移燈視床頭。", "發蒙餘半缾，聊温三四甌。", "鳴腸時一沃，曲身漸和柔。", "遥應原野間，錦衾覆釐麰。", "農夫庤錢鎛，指日望有秋。", "願言開同雲，東郊從春游。"]'),
('7d4e2e50-95ed-4ae8-9484-dcda77c90b99','再用前韵謝潘壽卿見和二首  其一','王之道','宋','宋诗','song-poetry','','[]','小人南郭綦，君子東家丘。',120,'全唐诗/poet.song.104000.json','["小人南郭綦，君子東家丘。", "相從濡須塢，雪案風颼飀。", "眼界眩兜綿，耳根鬨鳴球。", "何妨具杯酌，一笑寛百憂。", "不見劉带花，逢愁但揺頭。", "時來看崔盧，姓名覆金甌。", "我願霽晨霜，栗烈還温柔。", "黄金著高柳，綠浪翻來麰。", "要令扶犁兒，力田遂逢秋。", "飽食奚所須，鼓腹同天游。"]'),
('37b4ef14-0b7a-4850-a99b-4696f6789995','再用前韵謝潘壽卿見和二首  其二','王之道','宋','宋诗','song-poetry','','[]','新詩清絕俗，想見胸中丘。',120,'全唐诗/poet.song.104000.json','["新詩清絕俗，想見胸中丘。", "飛泉落高峰，風聲助颼飀。", "又如清廟中，河圖見天球。", "不惟竦觀瞻，玩之可忘憂。", "是行何處來，楚尾連吳頭。", "一杯聊效芹，大似勝茶甌。", "賡我喜雪章，詞情和且柔。", "久旱民苦饑，重憐來與麰。", "勃焉來争春，富哉麰向秋。", "吾君德無邊，今與和氣游。"]'),
('c6036d24-0dba-40fc-87cf-1a9dba375db8','再用前韵謝張濟之見和','王之道','宋','宋诗','song-poetry','','[]','我欲訪蓬萊，長笑挹浮丘。',120,'全唐诗/poet.song.104000.json','["我欲訪蓬萊，長笑挹浮丘。", "此身插兩翼，泠然御颼飀。", "樓臺聳瓊瑶，草木叢珠球。", "周旋於其間，不知塵世憂。", "願言久未遂，俛仰今白頭。", "茅齋夜飛雪，碎玉敲風甌。", "平生鐡石腸，化作繞指柔。", "年饑百無贏，接新待來麰。", "君才似鵰鶚，脩翎正横秋。", "沖天在不日，入侍巖廊游。"]'),
('61f7aa9e-67dd-4f3f-a857-c26404d7d022','四面山午飯澡雪塵土往太湖二首  其一','王之道','宋','宋诗','song-poetry','','["\u592a\u6e56"]','白沙浥夜雨，蒼松弄朝日。',48,'全唐诗/poet.song.104000.json','["白沙浥夜雨，蒼松弄朝日。", "清風滿行路，駸駸馬蹄疾。", "溪聲静如漱，嵐翠濃欲滴。", "我豈山中僧，前身飽游歷。"]'),
('914d052a-3a71-45b7-a347-0f246a19fef0','四面山午飯澡雪塵土往太湖二首  其二','王之道','宋','宋诗','song-poetry','','["\u592a\u6e56"]','重門掩松篁，傑閣戞霄漢。',48,'全唐诗/poet.song.104000.json','["重門掩松篁，傑閣戞霄漢。", "溪流水晶軟，石棧雲母粲。", "清游不可失，微勞敢言憚。", "斜陽無相催，我欲濯塵汗。"]'),
('f8e58a7b-a8e1-49ef-8e88-2de454c85c87','次韵徐伯源九日閒居追和淵明','王之道','宋','宋诗','song-poetry','','[]','閒居遇重九，對酒懷陶生。',108,'全唐诗/poet.song.104000.json','["閒居遇重九，對酒懷陶生。", "陶生不可見，愛此重九名。", "清霜肅時令，天宇增高明。", "依依遠山色，隠隠賓鴻聲。", "泛酒黄金花，人言可延齡。", "嗟予不解飲，酒到從之傾。", "嫣然木芙蓉，揺風倚東榮。", "雖無窈窕歌，自足娛吾情。", "鼓琴復何爲，年來泯虧成。"]'),
('8d5925de-d3ce-4a53-8563-991b94cfaf33','追和東坡喜雪用王覿韵','王之道','宋','宋诗','song-poetry','','[]','長安一夜雪，酒價湧朝市。',120,'全唐诗/poet.song.104000.json','["長安一夜雪，酒價湧朝市。", "何人獨耐寒，翛然立庭砌。", "盈盈竹間梅，靚粧欲誰媚。", "冰肌與玉骨，似不勝風袂。", "豐年貴三白，麟鳳敢稱瑞。", "要令輿論協，庶遂我心慰。", "春回在朝夕，枯荄動和氣。", "尤憐麥蓋錦，秀發功必倍。", "憂葵亦何爲，度日同度歲。", "不如擁百城，陶然六經醉。"]'),
('7e49673f-c666-469c-bd38-e6ffa9155786','對雪二首再用前韵  其一','王之道','宋','宋诗','song-poetry','','[]','同雲晝暗空，孤城早休市。',120,'全唐诗/poet.song.104000.json','["同雲晝暗空，孤城早休市。", "行人失道路，賀客擁堦砌。", "翻縞語亦工，飛絮思争媚。", "飄飄何所似，想見六銖袂。", "盈尺信爲大，三白乃成瑞。", "梅花不畏寒，點綴若相慰。", "高吟撚凍鬚，詩社頗增氣。", "薫然一杯酒，神速功力倍。", "來麰被餘潤，預可占有歲。", "便當呼老農，潑醅取沉醉。"]'),
('eb9e6389-f177-4232-9025-5dc4a0f059d0','對雪二首再用前韵  其二','王之道','宋','宋诗','song-poetry','','[]','我笑袁司徒，閉戶雪中市。',120,'全唐诗/poet.song.104000.json','["我笑袁司徒，閉戶雪中市。", "高眠罷炊爨，冰榻對瑶砌。", "豈如王孝伯，鶴氅鬬清媚。", "隨風楊柳花，縱横撲襟袂。", "冬温犯春令，破白已爲瑞。", "何妨盈地尺，萬井共歡慰。", "草木含餘滋，山川鬰佳氣。", "清寒入詩骨，敢問酒價倍。", "日月同過鳥，燔烈又興歲。", "老大不足悲，吾今但心醉。"]'),
('9a835989-968c-45cf-ba2b-b5e889350675','書懷示周少隠右司','王之道','宋','宋诗','song-poetry','','[]','我生動多艱，一笑不易得。',96,'全唐诗/poet.song.104000.json','["我生動多艱，一笑不易得。", "朅來坐逆旅，俯仰空太息。", "吾人當代秀，文章擅華國。", "分攜十四載，復此見顔色。", "怱怱未及款，歸程忽云逼。", "願君因索塗，爲我指南北。", "金門與玉堂，努力事登陟。", "閒將咫尺書，因風寄相憶。"]'),
('5fbddc41-4f3b-41ff-97ef-2bd69f027022','因納上人寄題望江張氏春暉亭詩','王之道','宋','宋诗','song-poetry','','[]','青青原上草，初生殆毫芒。',180,'全唐诗/poet.song.104000.json','["青青原上草，初生殆毫芒。", "邇來没蓬蒿，似有三尺强。", "春暉主發生，萬物資餘光。", "遲遲雖不暴，萋萋自能長。", "條風與糓雨，其功固難量。", "予嘗優劣之，豈得相輩行。", "大哉發生恩，欲報不可償。", "東野古純孝，作詩本肝腸。", "懷親感春暉，義見遊子章。", "凱風亦遠矣，此道何茫茫。", "惟餘東野詩，千古遥相望。", "張公雷江人，鷄群鶴昂昂。", "冰魚與冬笋，志慕孟與王。", "結廬守松楸，至行稱淮鄉。", "我不識君面，因詩得其詳。"]'),
('4061d663-01e9-416a-b1b9-3b7a7aa1c915','一經堂爲王亦顔題','王之道','宋','宋诗','song-poetry','','[]','我生非我有，天地暫委形。',192,'全唐诗/poet.song.104000.json','["我生非我有，天地暫委形。", "諦觀子若孫，相值如浮萍。", "崔昭與李兼，甚矣愚不靈。", "積錢遺芸窟，轉手還星星。", "何如散籯金，人遺以一經。", "韋賢不可作，高風看典型。", "公家世植德，蘭玉滋芳馨。", "三鱣偶墮砌，伯魚初過庭。", "明明有聖訓，言之爾其聽。", "退而學詩禮，齋扉晝長扄。", "矻矻對月牖，孜孜守風櫺。", "冬映孫子雪，夜聚車公螢。", "有時聞誦詩，流泉韵泠泠。", "懸知睟見面，巖電仍雙熒。", "行當擢賢科，發策驚天廷。", "致君此其術，何獨取紫青。"]'),
('21b334ba-863e-4827-b6ee-bf6112a7990e','苦雨呈蘄守徐次公','王之道','宋','宋诗','song-poetry','','[]','涉春苦淫雨，連綿過梅夏。',240,'全唐诗/poet.song.104000.json','["涉春苦淫雨，連綿過梅夏。", "西來二十日，終朝走泥溠。", "林霏欲開戶，簷溜又淙夜。", "勢如黄河翻，聲若滄海瀉。", "頽垣就崩摧，敗屋遂傾卸。", "垂成麥傷潦，將老蠶病柘。", "那知困羈旅，正恐害耕稼。", "痛哉兵火餘，人物久凋謝。", "瘡痍索撫養，嵬瑣煩教化。", "方推中牟恭，復獲潁川覇。", "是行良不惡，漸美同噉蔗。", "况承雙魚書，敢緩千里駕。", "平生慕山水，尋勝每偷暇。", "何妨見君子，大厭顧榮炙。", "一舉欣兩得，重趼輕百舍。", "登臨興何窮，吟詠樂無價。", "猿鶴互酬對，雲煙競邀迓。", "巖松升龍矯，溪橋斷虹跨。", "尚恨阻豐隆，未果訪姑射。", "須煩段文昌，一出補天罅。"]'),
('34dc4c7f-a99a-45ee-8114-d8e31cd924ad','告春亭詩爲江寧令荀晉仲作','王之道','宋','宋诗','song-poetry','','[]','淵明晉高士，從官非所好。',264,'全唐诗/poet.song.104000.json','["淵明晉高士，從官非所好。", "當時令彭澤，爲米聊寄傲。", "公田三百畆，一稔足炊䤖。", "明年春二月，農以仲春告。", "爲言當舉趾，西疇雨如膏。", "雨後春日遲，不寒亦不暴。", "欣欣木争榮，民析肯居隩。", "感此萬物時，吾年廹衰眊。", "餘生復幾許，遑遑近顛倒。", "翩然賦歸去，豈爲折腰躁。", "兄也今淵明，强盛當遠到。", "學問窮古始，文章配盤誥。", "十年宰兩邑，五月政三報。", "去冬得兄書，憐我加慰勞。", "仁言暖於帛，失喜至舞蹈。", "其間何所云，作亭縣之奥。", "爲農榜告春，此意在勸導。", "我欲求子詩，併以示倪耄。", "春作苟盡力，秋成可無禱。", "先當起疲瘵，次用振凋耗。", "别來忽九載，觸緒增戀嫪。", "塞命敢不勉，一笑一杯犒。"]'),
('97a5ac2f-5126-4e75-9c89-2c4ee2d26eef','次韵同年蔡仲平察院遊西湖','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','朝日不受霧，晴光似暉暉。',192,'全唐诗/poet.song.104000.json','["朝日不受霧，晴光似暉暉。", "忽然快我心，清風爲解圍。", "坐見九里松，旌幢碧相依。", "天竺了在望，上有祥雲微。", "西湖一千頃，圓荷覆青衣。", "輕舟競遊覽，往往俗客稀。", "幸及新雨霽，欣逢露初晞。", "水光與山色，高低映郊畿。", "佳哉氣葱鬰，觀闕何巍巍。", "誰云門庭遠，咫尺永天威。", "諸公萃俊傑，高論玉麈揮。", "載酒旨且多，不醉無庸歸。", "餘歡到獻酢，灔灔雙鴛飛。", "新詩爛錦段，想見勞心機。", "顧我雖百拙，續貂重相違。", "明年若重來，種種當如幾。"]'),
('06347b51-0133-4ebf-96d1-9a7fd7a812dc','和秦壽之喜雨','王之道','宋','宋诗','song-poetry','','[]','雲峰擁稜層，不動若頑石。',108,'全唐诗/poet.song.104000.json','["雲峰擁稜層，不動若頑石。", "追凉困無所，何當日云夕。", "揮箑汗如流，欲卧莫安席。", "雲頭從北來，微風動疏荻。", "滂沱一尺雨，旱魃驚辟易。", "巾屨獲暫御，尊酒容復覔。", "誰憐貧長卿，空洞家四壁。", "熬熬爐炭中，萬物同一息。", "明朝槁苗興，農畆歌帝力。"]'),
('ac2c9d6b-4abb-486b-ac34-5dab33d477ec','秋日訪程元明喜雨而作','王之道','宋','宋诗','song-poetry','','[]','去年夏六月，我來自臨安。',168,'全唐诗/poet.song.104000.json','["去年夏六月，我來自臨安。", "滂沲一夜雨，原隰俱瀰漫。", "俛仰忽再秋，秋旱畎澮亁。", "嘉穀槁垂盡，萬口空長歎。", "我從相山來，朝雲起巑岏。", "油然遍寰宇，半道濡征鞍。", "亭午至君家，簷聲落驚湍。", "詰旦視大田，青青已堪看。", "會見百室盈，陋巷飽一簞。", "何獨解君憂，我心其少寛。", "襲芳富卉木，秋炎苦摧殘。", "柯葉頓欣榮，秀色良可餐。", "速宜置尊酒，一洗儒生酸。", "我雖不解飲，醒狂佐君歡。"]'),
('9f6a8bde-8d2f-45e4-b21a-3bf09650fdd0','和天寧因上人韵送僧用懿住桐城金繩山','王之道','宋','宋诗','song-poetry','','[]','老松如蛟龍，秋來露鱗甲。',120,'全唐诗/poet.song.104000.json','["老松如蛟龍，秋來露鱗甲。", "雷霆昨夜雨，奮迅以時發。", "道人粲可流，出世雨相法。", "至今獅子吼，狐兔尚驚怛。", "金繩小金山，突兀一峰拔。", "桐城舊知音，相招遺書札。", "世情强輕重，祖道無廣狹。", "天寧有佳句，鐘磬鬬鏗戞。", "嗟予丘壑姿，晚歲麋鹿狎。", "屬和良不工，前詩萬鈞壓。"]'),
('71460ae7-244c-41d3-9d92-6d3b920a817b','送延上人歸雲峰','王之道','宋','宋诗','song-poetry','','[]','去年出山時，飛雪正撩亂。',96,'全唐诗/poet.song.104000.json','["去年出山時，飛雪正撩亂。", "慇懃大洪老，呵筆寫真贊。", "爲言化菩薩，持鉢江北岸。", "欲將說禪相，醒彼瞌睡漢。", "别來能幾日，漚滅冰且泮。", "似聞妙湛師，接踵還舊觀。", "公歸勿惆悵，生死同夜旦。", "幸有囊中金，了此一重案。"]'),
('84d0bc75-783e-4b4e-a383-db5c11cd8734','送遵禪者','王之道','宋','宋诗','song-poetry','','[]','阿遵我輩人，相從十年舊。',168,'全唐诗/poet.song.104000.json','["阿遵我輩人，相從十年舊。", "行肥形愈瘠，身貧道常富。", "厥初爲天衣，持鉢化淮右。", "袖攜維衛錄，訪我過蓬陋。", "若言法華山，有象金所就。", "其來自西土，隠現不可究。", "我時嘗記之，爾耳亦聊復。", "誰令慈悲師，鏤板播疏謬。", "向來天衣遊，追隨遍巖竇。", "高談屢絕倒，寢食廢宵晝。", "歸歟又同舟，半道過濠壽。", "是行寄先塋，一再獲邂逅。", "清霜殞群木，凄勁搗衣候。", "翩然不我留，雲山挺高秀。"]'),
('e9f86cc6-8bd7-4bb5-9231-09af664e6337','次韵慧上人見寄','王之道','宋','宋诗','song-poetry','','[]','别來六改歲，想遍江南山。',132,'全唐诗/poet.song.104000.json','["别來六改歲，想遍江南山。", "江南二百州，雲水相往還。", "秦望冠吳越，嵯峨俯塵寰。", "法華在其側，參差擁高鬟。", "幽花自芬芳，好鳥時緍蠻。", "傳聞發夢寐，登覽忘劬艱。", "去年謁老聰，默坐焚金顔。", "忽然獅子吼，頓覺醒冥頑。", "子今從之游，舊習須夷刪。", "人人自有分，既悟不我慳。", "請看釣魚翁，滿船載魴鰥。"]'),
('c7bac739-f7a6-40b5-92bf-f6fe9efac0a2','用東坡三峽橋韵贈源上人','王之道','宋','宋诗','song-poetry','','[]','解衣振林霏，欹枕聽簷溜。',120,'全唐诗/poet.song.104000.json','["解衣振林霏，欹枕聽簷溜。", "饑腸欲雷鳴，病耳忽牛鬬。", "自嗟兵火餘，十載困淮右。", "崎嶇窮水石，邂逅遍巖竇。", "山遊雜麋鹿，野處狎猿狖。", "那知膏粱肥，但覺蔬筍瘦。", "寶林吾北鄰，晨夕鐘鼓奏。", "疏篁玉森列，樛木弓半彀。", "來爲聖人祝，歌唄發清晝。", "歸餘雨脚稀，溪流静如漱。"]'),
('3a2f4773-0650-4b5e-a21e-cef5c4cbc896','和韋蘇州遊靈岩山寺韵呈言上人','王之道','宋','宋诗','song-poetry','','[]','我老懶成癖，貪此林泉幽。',84,'全唐诗/poet.song.104000.json','["我老懶成癖，貪此林泉幽。", "誰令吳中來，兩月乘江流。", "闔門十日雨，不得歷虎丘。", "讀子靈岩詩，還復令我愁。", "想見韋左司，擁騎當年遊。", "山中雨新霽，綠樹鳴鶯稠。", "乘興自不惡，金風颯清秋。"]'),
('9418d7e3-a92d-495b-b859-f475e6be7073','游白雲山海會寺','王之道','宋','宋诗','song-poetry','','[]','龍舒富山水，白雲又其角。',240,'全唐诗/poet.song.104000.json','["龍舒富山水，白雲又其角。", "七峰互回環，仰見天一握。", "古木森建幢，蒼藤大張幄。", "初疑翠黛掃，頗類青玉琢。", "飛泉何處來，其勢自天落。", "舂撞吼雷霆，激射紛雪雹。", "田家承下流，伐石競耕鑿。", "揺風麥初齊，泛水秧尚弱。", "怳若桃花源，誤入不容卻。", "況有古道場，碧瓦照丹雘。", "樓臺鎖煙霞，松杉聚猿鶴。", "我來孟夏初，征衫汗如濯。", "行行不知勞，梯雲上青廓。", "入門寂無人，幽鳥自相樂。", "登堂趙州出，此意亦不惡。", "徐徐叩其端，善巧萬金藥。", "銷除愛欲惱，澡浣塵土濁。", "山神似相留，入夜雨還作。", "明朝出山去，欲去更盤礴。", "何當賦歸來，寄傲酬素約。"]'),
('aad71c1d-b80d-43fc-ac7b-31350926c0c2','題三祖山','王之道','宋','宋诗','song-poetry','','[]','觀山不憚遠，有癖老增劇。',192,'全唐诗/poet.song.104000.json','["觀山不憚遠，有癖老增劇。", "是行廹王事，所過飛鳥疾。", "路傍四五祖，不得着脚歷。", "朝來所幹集，我願容自適。", "衝寒走海會，嘯吟遂終日。", "眷言三祖山，經從阻良覿。", "僧果知我意，飯僕濟行色。", "崎嶇五十里，入山及未昃。", "山頭殘雪在，青瑶點微白。", "殷勤承老禪，傾蓋同莫逆。", "爲言住此山，予寶始今日。", "欲以扶我衰，不鄙昔輕策。", "捫蘿助探討，躡石共登陟。", "群峰聳遥翠，一水漲深碧。", "行行何所喜，兩脚有餘力。", "歸來飽香積，清淡更過昔。"]'),
('5d8fc794-362d-4713-8344-76f1ec6c685d','五祖山','王之道','宋','宋诗','song-poetry','','[]','我生事幽討，塵埃良獨難。',192,'全唐诗/poet.song.104000.json','["我生事幽討，塵埃良獨難。", "朅來舒蘄游，登臨每長歎。", "如何勝絕境，佛屋多所安。", "大哉慈悲力，神功助劖刓。", "住處未易言，小道亦可觀。", "五祖古名刹，樓臺倚巑岏。", "崎嶇六七里，縈紆三百盤。", "懸崖擢青士，夾道羅蒼官。", "飛泉響環玦，幽芳馥沉檀。", "我來及新霽，千峰碧玉攅。", "忽聞杞犬吠，旋覺壺天寛。", "水聲擢午暑，嵐氣生晚寒。", "心目快開豁，腰脚嗟蹣跚。", "看雲更搘笻，披風少凭欄。", "欲營五畆宮，它年寄衰殘。", "試煩問祖師，莫作非意干。"]'),
('503d1a38-2ecd-4d1e-92d3-39c1918be084','贈浮屠有則','王之道','宋','宋诗','song-poetry','','[]','我老不能詩，其窮類詩人。',72,'全唐诗/poet.song.104000.json','["我老不能詩，其窮類詩人。", "多謝二三子，强以窮相親。", "師從何方來，過聽誤失真。", "袖攜諸公詩，丐我踵後塵。", "顧我雖不能，欲辭恐師嗔。", "勉作數句偈，拙惡慚無倫。"]'),
('aad14fe7-389e-4a70-9941-5dcaa90f3da7','題澄上人頤庵','王之道','宋','宋诗','song-poetry','','[]','我生困語言，老大猶棲遲。',144,'全唐诗/poet.song.104000.json','["我生困語言，老大猶棲遲。", "咄哉一言失，雖悔何能追。", "常欲說向人，到口還忸怩。", "不如静中坐，此理吾所知。", "春風入城郭，古寺花開時。", "廣庭積雨過，紅紫初紛披。", "偶逢頤庵人，强丐頤庵詩。", "是庵清而虚，底事名爲頤。", "南陵有徐子，頃嘗吏於斯。", "作字妙羲獻，學易深坎離。", "慎言與節飲，卦象不可欺。", "君看命名意，往往只在兹。"]'),
('e304c7bb-dc8a-444b-9ede-af4d3413797c','追和游謝氏山亭贈賢上人','王之道','宋','宋诗','song-poetry','','[]','春旱久不雨，既雨風日清。',96,'全唐诗/poet.song.104000.json','["春旱久不雨，既雨風日清。", "桑麻被膏潤，往往争欣榮。", "花鳥發詩思，湖山歡野情。", "駕言南畆遊，遂有西塔行。", "雲光鬰在望，地僻路亦生。", "賢公方外交，别來鶯再鳴。", "相逢話疇昔，茗椀喜屢傾。", "多謝二三子，壺漿競邀迎。"]'),
('59a96fbe-799c-47fd-9032-5c816ff134c1','黄梅東禪寺','王之道','宋','宋诗','song-poetry','','[]','南晉今黄梅，東禪舊青蓮。',168,'全唐诗/poet.song.104000.json','["南晉今黄梅，東禪舊青蓮。", "曹溪竟何許，龍朔知幾年。", "我聞二祖師，屬袂兹褊褼。", "片言道有契，千古衣相傳。", "栽松與舂磑，爲此一大緣。", "朝追固若廹，夜度亦大遄。", "邇来五百載，兵火數變遷。", "惟餘墜腰石，繩竅徒空穿。", "堂堂吳生畫，筆法世所賢。", "絹素雖朽蠧，丹青尚依然。", "嗟予二三子，平生慕真詮。", "來游獲瞻仰，投老當周旋。", "獨恨走俗狀，明朝又加鞭。", "臨池更徘徊，圓荷汎漪漣。"]'),
('8d7bf8ed-384b-4d17-928e-9603bde50f15','題智果寺','王之道','宋','宋诗','song-poetry','','[]','呂侯妙章句，珠玉走鄰境。',144,'全唐诗/poet.song.104000.json','["呂侯妙章句，珠玉走鄰境。", "想當落筆時，豪邁不淹頃。", "智果古精舍，松篁轉岡嶺。", "幽人所盤礴，俗客作遠屏。", "春雲忽解剥，林日光炯炯。", "門迎有高僧，烏用賦渴井。", "開緘讀數過，令我發深省。", "老來習懶放，萬事廢不整。", "猶憐閒中趣，日月頗增永。", "何當遂浮家，百口具舴艋。", "不見六一翁，夢寐在清潁。", "人生會如意，歲晚果得請。"]'),
('ca3ffe4e-d157-4dbe-a24f-ed3502482b9c','菩提院','王之道','宋','宋诗','song-poetry','','[]','菩提古精舍，兵餘但茅茨。',96,'全唐诗/poet.song.104000.json','["菩提古精舍，兵餘但茅茨。", "我行勌午暑，少憩容奴炊。", "山僧老無子，養蠶如養兒。", "奈何煮白蠒，廼欲繅青絲。", "燕泥固可惡，覆巢似非宜。", "不聞兩足尊，頂鵲安無隳。", "我亦學佛者，言之爲興悲。", "作詩書壁間，以爲浮屠規。"]'),
('4eb22097-9cf9-4aea-9bf8-1a759460bf5c','黄頓琅玕山永福院','王之道','宋','宋诗','song-poetry','','[]','我從明光來，十里得永福。',48,'全唐诗/poet.song.104000.json','["我從明光來，十里得永福。", "山中何所有，離離見疏竹。", "前人目琅玕，用意良不俗。", "誰能對此君，蔬飯賤粱肉。"]'),
('8e72ada2-2aa3-410b-83bf-097406bceabd','成相院','王之道','宋','宋诗','song-poetry','','[]','山前羅萬松，邀我行數里。',48,'全唐诗/poet.song.104000.json','["山前羅萬松，邀我行數里。", "不知幽人居，但愛亂峰峙。", "新晴翠似潑，乍熱汗如洗。", "幸獲聽潺湲，何妨濯清泚。"]'),
('0de6c0ad-e18a-43f9-a511-66a81a063b0c','弔魏敏功贈住庵通老','王之道','宋','宋诗','song-poetry','','[]','一别異生死，三年能幾時。',48,'全唐诗/poet.song.104000.json','["一别異生死，三年能幾時。", "埋玉不可見，拱木徒興悲。", "通老奉香火，坐閲歲月移。", "圓顱點飛霜，夷曠真吾師。"]'),
('22ae40f4-ff63-460d-9121-f9e9b7ce662c','和因老游水寨府治東軒二首  其一','王之道','宋','宋诗','song-poetry','','[]','市井從東州，水竹自西府。',48,'全唐诗/poet.song.104000.json','["市井從東州，水竹自西府。", "我來與公偕，槃礴日欹午。", "從容河底魚，樂哉得其所。", "此意與誰論，相看默無語。"]'),
('09733693-cb8a-4d09-8631-14ce9849e819','和因老游水寨府治東軒二首  其二','王之道','宋','宋诗','song-poetry','','[]','買山荷疊錢，照天水開府。',48,'全唐诗/poet.song.104000.json','["買山荷疊錢，照天水開府。", "幽花有餘香，誰復爲賈午。", "勝句須斯人，清遊更何所。", "臨深未能還，我欲作危語。"]'),
('4f398ec0-1fd5-406c-bf8c-6556a9f3c897','題崇因院信上人宿雲軒','王之道','宋','宋诗','song-poetry','','[]','秋聲入高梧，暝色上疏竹。',96,'全唐诗/poet.song.104000.json','["秋聲入高梧，暝色上疏竹。", "南山攏青螺，過已淨如沐。", "悠然孤飛雲，窈窕轉林麓。", "自疑歸去晚，意欲窗下宿。", "道人等虚空，去來斷追逐。", "雲來不吾拒，雲去不吾速。", "相從一息頃，便覺静緣熟。", "何以照我心，老蟾掛枯木。"]'),
('19bc63b7-96c5-46df-9986-6feb7a12434b','宿彰教寺','王之道','宋','宋诗','song-poetry','','[]','過市欲投宿，穢隘非所安。',120,'全唐诗/poet.song.104000.json','["過市欲投宿，穢隘非所安。", "人言五里餘，有寺潔且寛。", "驅駑犯泥淖，敢憚風雨寒。", "稻塍與兔逕，縈紆度千盤。", "衣裘被沾濕，脚膝加蹣跚。", "因思聖人語，後獲當先難。", "壯哉古道場，翬飛映層巒。", "秀色藹松檜，清香馥芝蘭。", "我心大有得，豈惟厭遊觀。", "行行勿躊躇，霽日升雲端。"]'),
('ddc2415c-426f-4130-859a-958a46eec471','贈六安文殊亮老','王之道','宋','宋诗','song-poetry','','[]','我從東蓼來，水竹遂幽討。',96,'全唐诗/poet.song.104000.json','["我從東蓼來，水竹遂幽討。", "崎嶇至於六，獲見文殊老。", "文殊方外友，僧門素稱寶。", "平生首肯處，可嗣布禪皓。", "寤寐思棒喝，邂逅得傾倒。", "何妨萃高人，坐上識吾葆。", "會勝索枝撐，得師恨不早。", "勉爲雲山留，未可止中道。"]'),
('55836901-11ee-4b95-87fd-5d1e9de717d4','贈僧辨端','王之道','宋','宋诗','song-poetry','','[]','南僧如竹葦，在處即成林。',96,'全唐诗/poet.song.104000.json','["南僧如竹葦，在處即成林。", "雖去常人髮，不異常人心。", "邈哉端上人，所得趣向深。", "雲泉香火裏，日夕長苦吟。", "爲我有時名，踏雪來相尋。", "相尋緣底事，論詩復鳴琴。", "我是折腰吏，衣带塵土侵。", "何以謝吾師，恨無虞師金。"]'),
('85468f66-74eb-4dba-bae3-ebc665169a4f','送尚老之江西','王之道','宋','宋诗','song-poetry','','[]','道人野鶴姿，昂昂在鷄群。',96,'全唐诗/poet.song.104000.json','["道人野鶴姿，昂昂在鷄群。", "誰能戀場粟，俯仰勞骸筋。", "飄然欲何之，駐目西山雲。", "西山甲南昌，雄勝天下聞。", "翠巖爲之冠，有客許見分。", "旋酌秀溪月，煮茗特勸君。", "寄言翠巖老，吾將謝紛紜。", "尚有鼻端堊，須煩爲揮斤。"]'),
('60179d31-8d8c-46ef-8e20-ffd1fc87567f','贈浮屠勤上人','王之道','宋','宋诗','song-poetry','','[]','隔宿不問道，此語幼所聞。',144,'全唐诗/poet.song.104000.json','["隔宿不問道，此語幼所聞。", "汨没塵土中，歲晚方得君。", "學道戒怠惰，成功在精勤。", "勤哉勤道者，取名不徒云。", "别來十二秋，東遊遍温鄞。", "持呪動至暮，坐禪常達昕。", "寸陰古所惜，君今惜餘分。", "兢兢窮晝夜，直欲忘齋薫。", "軒昂冲天鶴，那容混鷄群。", "我老懶成癖，見君但歡欣。", "茅齋無一物，坐對柏子焚。", "忽然捨我去，翩若風中雲。"]'),
('57cd8c30-8357-4dbd-9472-eee1b376fd18','龍門呈心老','王之道','宋','宋诗','song-poetry','','[]','千山倚天高，一徑穿雲斜。',96,'全唐诗/poet.song.104000.json','["千山倚天高，一徑穿雲斜。", "忽然見樓閣，知是佛子家。", "蒼松老不死，夭矯如龍蛇。", "霜皮自鱗皴，風梢互槎牙。", "幽花似薝蔔，清絕不可加。", "過庭送好音，異哉碧鴒伽。", "我來不忍去，一步三咨嗟。", "終當解冠裳，從師卧煙霞。"]'),
('73fae004-cc96-4d4f-b894-a17f1ad21366','國清化人示寒山','王之道','宋','宋诗','song-poetry','','[]','師從天台來，示我一集詩。',120,'全唐诗/poet.song.104000.json','["師從天台來，示我一集詩。", "開編未及讀，涕淚已交頤。", "紛紛世間人，迷妄覺者誰。", "浮沉苦海中，欲出無端涯。", "寒山與拾得，旁觀爲興悲。", "作詩三百篇，勸戒仍嘲嗤。", "覺此未覺者，當下成牟尼。", "此意亦良厚，柰何人罕知。", "師持國清鉢，欲救雲堂饑。", "贈言亦安用，聊以報所貽。"]'),
('5fbe8246-95ab-4ecf-a7be-cf280e968ec0','奉送果上人住開先寺','王之道','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我昔遊成均，年少心猶童。',168,'全唐诗/poet.song.104000.json','["我昔遊成均，年少心猶童。", "倒床即甘寢，寧問達與窮。", "精爽忽飛越，夢到廬山中。", "廬山最佳處，二林占西東。", "開先在其間，泉石清而雄。", "分明我所記，古刹磨碑豐。", "長銜似持節，覺來夢還空。", "俛仰殆三絕，蹭蹬老更癃。", "貴賤等夢爾，覺夢一理同。", "持節何足道，得時可三公。", "說夢乃夢語，笑殺懶散翁。", "翁今往開先，憑何警盲聾。", "將此一轉語，截斷雙石谼。", "源源自何來，其去何所終。"]'),
('8c205680-fd59-4887-afe8-8d38a48fcef3','次韵因老見贈','王之道','宋','宋诗','song-poetry','','[]','扁舟歷陽來，訪君得少息。',180,'全唐诗/poet.song.104000.json','["扁舟歷陽來，訪君得少息。", "登堂默無語，見者稱目擊。", "去年糝江上，群盜羅劍戟。", "君時濡須游，入山笑相揖。", "肩擔祖師禪，問答揮即栗。", "豈惟警聾瞶，亦足慰岑寂。", "春容褪丹青，雨意鋪水墨。", "定將儻赴感，澄霽自端的。", "麥秋數日間，饑腸頗貪得。", "兵餘敝廬盡，何獨空四壁。", "維摩幸無恙，胡避有新室。", "白雲夲無心，能歸定能出。", "巋然三傑峰，況是舊相識。", "我有半仙丹，和劑等菖术。", "爲言山中人，蟠桃已成實。"]'),
('2e9e6e81-cb04-4271-be47-121ff63cd258','信陽和同官喜雨韵','王之道','宋','宋诗','song-poetry','','[]','欲識農夫田作苦，久雨禱晴晴禱雨。',320,'全唐诗/poet.song.104000.json','["欲識農夫田作苦，久雨禱晴晴禱雨。", "禱晴得雨雨得晴，此患到今傳自古。", "苾芬非是蕭蘭馨，誠心一發通三靈。", "文昌俗吏亦何者，乃能致雨興雷霆。", "爾來旱氣爞爞熱，夜望天涯電光掣。", "原田嘉穀半焦黄，何獨枯魚濡涸轍。", "忽然一雨洗瘴昬，珠玉無邊難價論。", "坐令愁嘆變歡抃，千巖萬壑江流奔。", "從今不厭商羊舞，十日一犂均下土。", "漏邦寒儉酒味醨，且磑新茶其分乳。", "庭前花草還青葱，想見黍稌紛芄芄。", "吾君早晚復疆宇，屢豐將見追元豐。", "天人大扺常相即，人若必天天可必。", "願修人事格天心，天若不從非所恤。", "泰亨自復先朋來，時通端不憂塵埃。", "新詩要非所宜辱，敢以木李酬瓊瑰。", "六年無蓄號不足，菜色定應緣半菽。", "要令汸暴似海岳，豈但河沙論秉斛。", "炎天赫日當流金，去國多年思轉深。", "只今淮北望霓切，須煩伊傅資商霖。"]'),
('0888dec3-f29a-452f-9c5b-5cfea28ac986','次韵子厚弟喜雨行贈趙守端質','王之道','宋','宋诗','song-poetry','','[]','我生畏暑如畏焚，奈此歲旱風塵昏。',320,'全唐诗/poet.song.104000.json','["我生畏暑如畏焚，奈此歲旱風塵昏。", "十年廢放卧巖壑，名雖八品身黎元。", "恒暘乞雨雨乞霽，雨轉爲淫暘轉熾。", "不知此理果何如，每訝天心異人意。", "去年避地還家園，蒿萊滿目高侵天。", "秋陽肆虐冬益甚，涉春陂澤皆平川。", "邇來焦稿遍區宇，黄金融液膠流弩。", "趙侯日爲疲瘵憂，應怪魯書三不雨。", "天人大抵常相資，顧我錄錄傷無奇。", "鬻漿苦涼屠苦熱，敢望屏翳從招麾。", "聖主東巡群后覲，萬里江淮方水運。", "折衝禦侮賴親賢，何獨爲霖福斯郡。", "精誠昭格吾誰欺，頃間禱雨人所知。", "忽然簷溜瀉河漢，數聲霹靂轟相隨。", "公堂六月清無暑，旋磑龍團試分乳。", "官曹相賀復何言，且戒農夫築場圃。", "小人托庇安村墟，獲同野老歌而呼。", "願公玉带懸金魚，奉報得雨禾生稃。", "霏霏不厭沾衣裾，稍晴欲自躬犂鋤。", "斯民食足吾其俱，何妨把酒仍觀書。"]'),
('8537a069-f373-4a78-8360-c33f165d04b8','酬潘縣尉','王之道','宋','宋诗','song-poetry','','[]','堯明文采燦星宿，子全道義高金玉。',272,'全唐诗/poet.song.104000.json','["堯明文采燦星宿，子全道義高金玉。", "傷哉二子不可見，墓上悲風號拱木。", "逢君論友話偶及，令我呑聲爲渠哭。", "因渠感君不我鄙，遠寄錦囊詩一軸。", "有如貝闕羅珠璣，東攫西拏厭吾欲。", "又如康衢走騏驥，朝越暮燕惟爾逐。", "匹夫獲罪坐懷璧，誰使夜光衝蔀屋。", "仲尼知本故稱水，請看懸崖瀉飛瀑。", "我從二子方弱冠，俛仰三終同轉轂。", "壯年登第今已老，碌碌無奇堪齒錄。", "羨君節操似松筠，雪裏高標仍絕俗。", "已將義命等窮途，肯爲身名强榮辱。", "高情慷慨憐衰晚，妙句縱横丐膏馥。", "開緘反復讀數過，骨竦毛森頭觳觫。", "施隆報蔑君勿誚，明月輕投得魚目。", "人生遇合會有日，行矣鳴騶入空谷。", "燮調元化坐廟堂，長使斯民歌鼓腹。"]'),
('d8e8bc02-387b-4f32-88c4-45431330de3b','贈淮西運幹徐伯遠','王之道','宋','宋诗','song-poetry','','[]','嗟予偃伏淮南村，十年不踐公侯門。',160,'全唐诗/poet.song.104000.json','["嗟予偃伏淮南村，十年不踐公侯門。", "誰令金印入魂夢，平章六字承君恩。", "左手人頭右手印，此理未可輕易論。", "丈夫盖棺事始定，擒戎會使來稱藩。", "争如徐子擅騷雅，筆力豪縱今文園。", "楊君收印六十載，細觀制作同新翻。", "爲言常侍故家物，其先得自南昌潘。", "珠還合浦有時節，餘慶未艾鍾仍昆。", "子今得之類摘鵲，此貺重可輕璵璠。", "便當凖擬佩三印，併與文安遺子孫。"]'),
('bee06c9b-e71b-4b0c-b024-cd278a940f36','和王覺民梅花詩','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅花似是東君客，漏洩春風犯寒坼。',224,'全唐诗/poet.song.104000.json','["梅花似是東君客，漏洩春風犯寒坼。", "冰肌玉骨照雙泉，應爲孤根借泉脈。", "先生狂得次公醒，詩思藹藹飄晴雲。", "爲憐老拙有舊分，俾預勝賞沾清芬。", "我時被酒酒初透，香撲鼻端曾一嗅。", "别來飛雪往未能，想見精神愈高痩。", "西湖處士真詩仙，東坡老人所推先。", "豈知此花自奇絕，神助妙語相争妍。", "浪言投李報瓊玖，牛後何如作鷄口。", "我今無物報投瓊，木李雖輕聊藉手。", "先生標致良可人，此詩不減花娉婷。", "相當欹枕初得句，夜興冠坐如驚霆。", "願君追作淮夷雅，換取公卿重文價。", "嗟予衰矣不復論，但欲高門容駟馬。"]'),
('c24f3fb0-291a-4f22-bdfe-b34b25ce3c77','沈湯輔隠軒詩','王之道','宋','宋诗','song-poetry','','[]','小隠山林大朝市，夫子命軒良有意。',256,'全唐诗/poet.song.104000.json','["小隠山林大朝市，夫子命軒良有意。", "仕途捷徑固無取，泉石膏肓亦猶次。", "不知朝隠誰得之，我恐曼倩爲近似。", "公卿百執各有職，豈容妄隠但充位。", "古人禄仕所不免，意在全身近於智。", "莊周梅福此其流，吏隠之名可無愧。", "沈君有弟今休文，咳唾成章數千字。", "恥從舉子事進取，逸韵高情寓吟醉。", "乃兄宦達方强仕，翠竹停鸞想風致。", "君侯才業伯仲間，退以求名名亦遂。", "方今堯舜理四海，巖穴彈冠求自試。", "朝廷既治群吏肅，何處堪爲隠者地。", "不如市隠最得策，大勝山林自憔悴。", "花源繚繞轉紅綠，竹洞深沉入幽邃。", "我聞此風頗健羨，圖成未可日月冀。", "他時儻作江西游，兄曰能來訪予季。"]'),
('cd18d1f1-b01e-4c74-8dcd-ef8ed9f86ddd','大梁食李有感呈彦時兄','王之道','宋','宋诗','song-poetry','','[]','葵花已過荷花繁，南風入户清而温。',128,'全唐诗/poet.song.104000.json','["葵花已過荷花繁，南風入户清而温。", "擔頭有李初入眼，令人引脰懷家園。", "三年爲客在兩處，李熟未果登清樽。", "翻思整冠誠可樂，何苦鑚核輒不存。", "急宜買冰致凝凜，全勝汲井供潺湲。", "小床方簟嚼春雪，一實自可輕璵璠。", "扁舟行逐東南奔，回首稻粱江上村。", "相歡孰若弟與昆，古來唱和須箎塤。"]'),
('a36ef1af-3018-4e75-82f3-0f92bb36106a','用子藺韵賦九日小酌','王之道','宋','宋诗','song-poetry','','[]','春日歸來忽重九，潦旱相仍歲無有。',160,'全唐诗/poet.song.104000.json','["春日歸來忽重九，潦旱相仍歲無有。", "庭前巖桂獨青青，此意於人亦良厚。", "欲酬佳節拚一醉，會有白衣來送酒。", "須臾殽核第羅列，無蟹猶空把螯手。", "坐來靈雨灑珠璣，洗出湖山競高秀。", "三公在望無百里，咫尺銀屏擁其後。", "長篇落紙箭離筈，大白浮醪簷注溜。", "細看黄菊與紅茱，想像年時還話舊。", "登高何必須人扶，我有笻杖頗堅痩。", "明朝寫出醉中語，牽帥不知誰唱首。"]'),
('91d8b41c-8117-4117-84f8-08abc15c6a13','春晚書懷','王之道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十年萍梗三到吳，走俗未暇觀西湖。',160,'全唐诗/poet.song.104000.json','["十年萍梗三到吳，走俗未暇觀西湖。", "是行信步至湖上，水光山色開天壺。", "游人雜遝半羅綺，一徑不憚穿雲紆。", "歸來神思頓清發，詩中寫出錢塘圖。", "張侯妙語何所似，青玉爲案黄金鋪。", "要當聨轡事幽討，邂逅得句相招呼。", "東坡已死不可作，因君對景還嗟吁。", "水仙配食竟莫舉，但見舊隠環菰蒲。", "山間有寺過三百，終期徧走參能儒。", "還家兒輩若問我，庶免不知空囁嚅。"]'),
('d07728b5-f08c-4d39-8365-5853fb29f73a','和劉春卿夏日閔旱次韵','王之道','宋','宋诗','song-poetry','','[]','何人夜作秋蟲號，吟詩坐對山月高。',240,'全唐诗/poet.song.104000.json','["何人夜作秋蟲號，吟詩坐對山月高。", "想當龍門奪錦袍，從臣拱手看揮毫。", "衡茅咫尺臨江皋，浮光灔灔翻金濤。", "滿帆何處乘風艘，千山過眼同奔逃。", "不防鱠鯉兼炰羔，酒酣起舞如飛猱。", "醉中往往笑成咷，一時輩流籍湜翺。", "嗟予蹇剥意欎陶，七年坐困山林牢。", "邇來天旱地不毛，釡魚薪蟻何嗷嗷。", "誰能讀詩夜焚膏，只益心蓬增目蒿。", "丈人純白羞桔橰，終日抱甕忘其勞。", "今春屬國紛旗旄，兩淮供億争鳴鼛。", "干戈載戢弓其弢，此行輔弼環蕭曹。", "藁街佇見懸酋豪，買牛賣劍犢賣刀。", "我雖不飲當漱醪，堆盤況有瑶池桃。", "鹿鳴會賦嘉賓敖，予衰尚可追風騷。"]'),
('8de845b2-1fab-467c-ab9c-18c6a1fd988d','過集湖德濟廟用趙尉廉留題韵示周欽夫程彦游','王之道','宋','宋诗','song-poetry','','[]','秋陽汎汎流清暉，帆腹不張旂脚垂。',128,'全唐诗/poet.song.104000.json','["秋陽汎汎流清暉，帆腹不張旂脚垂。", "靈祠輪奐湖之麋，水天一色成玻瓈。", "西軒爽塏高不危，憑欄下瞰群山卑。", "鬼神亮我心無欺，風濤縱險夫何疑。", "區區奔走勞驅馳，和光未免世俗隨。", "相逢一笑聊伸眉，明朝摻袂還東之。", "蕭曹有節未見奇，往往樵牧相鄙夷。", "吾生傾否會有時，窮愁過眼無足悲。"]'),
('75a23cd6-896d-4661-852c-402d94d54a30','次韵張文伯喜雨','王之道','宋','宋诗','song-poetry','','[]','新詩句句堪流傳，令人讀之神凜然。',160,'全唐诗/poet.song.104000.json','["新詩句句堪流傳，令人讀之神凜然。", "孟君已死不可見，如公筆力今無前。", "天生百穀養萬姓，暄潤稍闕功難全。", "江城秋旱望一溉，斯民窮極伊誰憐。", "滂沱忽澍三尺雨，稿苗厭厭藨緜緜。", "不知何以遽得此，有賢太守方承宣。", "焚香默禱辭未絕，精誠已格高高天。", "油雲垂布若可攬，沾濡車盖初言旋。", "西成指日多黍稌，頌歌未負賡豐年。", "豚蹄盂酒謝神貺，鼓腹一笑非予偏。"]');
